const migrationsDir = path.join(ledgerDir, "migrations");

function ensureColumn(db, tableName, columnName, definitionSql) {
  const cols = db.prepare(`PRAGMA table_info(${tableName})`).all();
  if (!cols.some((x) => x.name === columnName)) {
    db.exec(`ALTER TABLE ${tableName} ADD COLUMN ${columnName} ${definitionSql}`);
  }
}

function ensureSchemaMigrationsTable(db) {
  db.exec(
    "CREATE TABLE IF NOT EXISTS schema_migrations (id TEXT PRIMARY KEY, filename TEXT NOT NULL UNIQUE, applied_at TEXT NOT NULL)"
  );
}

function applyLedgerMigrations(db) {
  ensureSchemaMigrationsTable(db);
  if (!fs.existsSync(migrationsDir)) {
    return [];
  }
  const files = fs
    .readdirSync(migrationsDir, { withFileTypes: true })
    .filter((x) => x.isFile() && x.name.toLowerCase().endsWith(".sql"))
    .map((x) => x.name)
    .sort((a, b) => a.localeCompare(b));
  const applied = [];
  for (const file of files) {
    const done = db.prepare("SELECT 1 AS ok FROM schema_migrations WHERE filename = ? LIMIT 1").get(file);
    if (done) {
      continue;
    }
    const sql = fs.readFileSync(path.join(migrationsDir, file), "utf8");
    db.exec(sql);
    db.prepare("INSERT INTO schema_migrations (id, filename, applied_at) VALUES (?, ?, ?)").run(
      shortId("migr"),
      file,
      nowIso()
    );
    applied.push(file);
  }
  return applied;
}

