function nowIso() {
  return new Date().toISOString();
}

function shortId(prefix) {
  return `${prefix}_${Date.now()}_${crypto.randomUUID().slice(0, 8)}`;
}

function resolveFrontendFrozenType(type) {
  const clean = String(type || "").trim();
  if (!clean) {
    return null;
  }
  if (frontendFrozenSubset.has(clean)) {
    return clean;
  }
  return frontendAliasToFrozen.get(clean) || null;
}

function validateFrontendContractPayload(type, payload) {
  const frozenType = resolveFrontendFrozenType(type);
  if (!frozenType) {
    return {
      covered: false,
      frozen_type: null,
      valid: true,
      errors: []
    };
  }
  const schema = frontendEventContract?.event_schema?.[frozenType] || frontendEventContract?.event_schema?.[type] || null;
  const required = Array.isArray(schema?.required_payload_keys) ? schema.required_payload_keys : [];
  const p = payload && typeof payload === "object" ? payload : {};
  const missing = required.filter((key) => !(key in p));
  return {
    covered: true,
    frozen_type: frozenType,
    valid: missing.length === 0,
    errors: missing.map((key) => `missing:${key}`)
  };
}

const DISPLAY_EVENT_TYPES = Object.freeze({
  USER_MESSAGE: "user_message",
  ASSISTANT_REPLY: "assistant_reply",
  TASK_PROGRESS: "task_progress",
  AUTH_REQUIRED: "auth_required",
  ATTACHMENT_ADDED: "attachment_added",
  VERIFY_SUMMARY: "verify_summary",
  DEPLOY_SUMMARY: "deploy_summary",
  RECOVERY_SUMMARY: "recovery_summary"
});

const DISPLAY_EVENT_CONTRACT = Object.freeze({
  version: "v1.display-event-projection-closeout",
  main_thread_allowed: [
    DISPLAY_EVENT_TYPES.USER_MESSAGE,
    DISPLAY_EVENT_TYPES.ASSISTANT_REPLY,
    DISPLAY_EVENT_TYPES.TASK_PROGRESS,
    DISPLAY_EVENT_TYPES.AUTH_REQUIRED,
    DISPLAY_EVENT_TYPES.ATTACHMENT_ADDED,
    DISPLAY_EVENT_TYPES.VERIFY_SUMMARY,
    DISPLAY_EVENT_TYPES.DEPLOY_SUMMARY,
    DISPLAY_EVENT_TYPES.RECOVERY_SUMMARY
  ],
  internal_route: Object.freeze({
    logs_tab: "review.logs",
    trace_tab: "review.logs"
  })
});

const DISPLAY_EVENT_INTERNAL_TEXT_PATTERNS = [
  /\bmode=analysis\b/i,
  /\bexecution_mode=answer_only\b/i,
  /\brequires_tools=no\b/i,
  /\bcompact_run=/i,
  /context projection verified/i,
  /context assembled from compact\+delta/i,
  /\bworkspace_id:/i,
  /\blane_detail:/i,
  /\bcontext_mode:/i
];

const DISPLAY_EVENT_PRIORITY_KEYS = [
  "message",
  "summary",
  "reason",
  "status",
  "result",
  "result_summary",
  "failure_summary",
  "stdout_summary",
  "stderr_summary",
  "error",
  "error_code",
  "lifecycle_state",
  "task_type",
  "step_id",
  "case_id",
  "mode",
  "hydrate_mode"
];

function payloadValueToText(value) {
  if (typeof value === "string" && value.trim()) {
    return value.trim();
  }
  if (typeof value === "number" && Number.isFinite(value)) {
    return String(value);
  }
  if (typeof value === "boolean") {
    return value ? "yes" : "no";
  }
  return "";
}

function readPayloadText(payload, keys = DISPLAY_EVENT_PRIORITY_KEYS) {
  if (!payload || typeof payload !== "object") {
    return "";
  }
  for (const key of keys) {
    const value = payload[key];
    const direct = payloadValueToText(value);
    if (direct) {
      return direct;
    }
    if (value && typeof value === "object") {
      const nested =
        payloadValueToText(value.message) ||
        payloadValueToText(value.summary) ||
        payloadValueToText(value.reason) ||
        payloadValueToText(value.status) ||
        payloadValueToText(value.code);
      if (nested) {
        return nested;
      }
    }
  }
  if (payload.error && typeof payload.error === "object") {
    const nested =
      payloadValueToText(payload.error.message) ||
      payloadValueToText(payload.error.reason) ||
      payloadValueToText(payload.error.code);
    if (nested) {
      return nested;
    }
  }
  return "";
}

function sanitizeDisplayEventBody(value) {
  const text = String(value ?? "").replace(/\r/g, "").trim();
  if (!text) {
    return "";
  }
  for (const pattern of DISPLAY_EVENT_INTERNAL_TEXT_PATTERNS) {
    if (pattern.test(text)) {
      return "";
    }
  }
  if (text.length > 1600) {
    return `${text.slice(0, 1597)}...`;
  }
  return text;
}

function classifyDisplayEventType(eventType) {
  const type = String(eventType || "").trim().toLowerCase();
  if (!type) {
    return null;
  }
  if (type === "user.message" || type.startsWith("user.message")) {
    return DISPLAY_EVENT_TYPES.USER_MESSAGE;
  }
  if (type === "attachment.ingested") {
    return DISPLAY_EVENT_TYPES.ATTACHMENT_ADDED;
  }
  if (type === "auth.required" || type.startsWith("approval.pending")) {
    return DISPLAY_EVENT_TYPES.AUTH_REQUIRED;
  }
  if (type.startsWith("verify.") || type.includes(".verify.")) {
    return DISPLAY_EVENT_TYPES.VERIFY_SUMMARY;
  }
  if (type.startsWith("deploy.") || type.startsWith("release.") || type.includes(".deploy.") || type.includes(".release.")) {
    return DISPLAY_EVENT_TYPES.DEPLOY_SUMMARY;
  }
  if (
    type === "step.failed" ||
    type === "step.failed_controlled" ||
    type.startsWith("recovery.") ||
    type.startsWith("resume.") ||
    type.startsWith("replay.") ||
    type.startsWith("retry.") ||
    type.startsWith("stale.running.recover")
  ) {
    return DISPLAY_EVENT_TYPES.RECOVERY_SUMMARY;
  }
  if (type === "step.completed") {
    return DISPLAY_EVENT_TYPES.ASSISTANT_REPLY;
  }
  return DISPLAY_EVENT_TYPES.TASK_PROGRESS;
}

function buildDisplayBodyFromRuntimeEvent(eventType, payload) {
  const type = String(eventType || "").trim();
  const p = payload && typeof payload === "object" ? payload : {};
  if (!type) {
    return "";
  }
  if (type === "auth.required" || type.startsWith("approval.pending")) {
    return "Authorization required before execution can continue.";
  }
  if (type === "auth.submit.duplicate_ignored") {
    return "Authorization already submitted. Waiting for verification.";
  }
  if (type === "auth.verified" || type === "approval.continue.started") {
    return "Authorization verified. Execution resumed.";
  }
  if (type === "attachment.ingested") {
    const name = readPayloadText(p, ["original_name", "source_type", "mime_type", "attachment_id"]);
    const mime = String(p.mime_type || "").toLowerCase();
    if (mime.startsWith("image/")) {
      return name ? `Image and text included in current context (${name})` : "Image and text included in current context";
    }
    return name ? `Attachment added to current context (${name})` : "Attachment added to current context";
  }
  if (type === "context.hydration.started") {
    return "Context restored from previous session";
  }
  if (type === "context.hydration.completed") {
    const mode = String(p.hydrate_mode || "").toLowerCase();
    if (mode.includes("compact")) {
      return "Current turn uses summarized context";
    }
    return "Context restored from previous session";
  }
  if (type === "context.projection.built" || type === "context.projection.verified") {
    return "Context restored from previous session";
  }
  if (type === "compact.requested" || type === "compact.started") {
    return "Compacting long conversation context";
  }
  if (type === "compact.completed" || type === "fork.compact.completed") {
    return "Long conversation compacted automatically";
  }
  if (type === "step.requested") {
    const stepId = readPayloadText(p, ["step_id", "task_type", "case_id"]);
    return stepId ? `Task started: ${stepId}` : "Task started";
  }
  if (type === "step.completed") {
    const summary = readPayloadText(p, ["message", "summary", "result_summary", "status"]);
    return summary || "Task completed";
  }
  if (type === "step.failed_controlled") {
    const reason = readPayloadText(p, ["reason", "failure_summary", "error_code", "status"]);
    return reason ? `Task stopped safely: ${reason.replaceAll("_", " ")}` : "Task stopped safely";
  }
  if (type === "step.failed") {
    const reason = readPayloadText(p, ["reason", "failure_summary", "error_code", "status"]);
    return reason ? `Task failed: ${reason.replaceAll("_", " ")}` : "Task failed";
  }
  if (type.startsWith("verify.") || type.includes(".verify.")) {
    const summary = readPayloadText(p, ["summary", "message", "status", "failure_summary"]);
    return summary ? `Verification summary: ${summary}` : "Verification summary updated";
  }
  if (type.startsWith("deploy.") || type.startsWith("release.") || type.includes(".deploy.") || type.includes(".release.")) {
    const summary = readPayloadText(p, ["summary", "message", "status", "lane_id", "blocker"]);
    return summary ? `Deploy summary: ${summary}` : "Deploy summary updated";
  }
  if (
    type.startsWith("recovery.") ||
    type.startsWith("resume.") ||
    type.startsWith("replay.") ||
    type.startsWith("retry.") ||
    type.startsWith("stale.running.recover")
  ) {
    const summary = readPayloadText(p, ["summary", "message", "reason", "status"]);
    return summary ? `Recovery update: ${summary}` : "Recovery update available";
  }
  if (type.startsWith("context.") || type.startsWith("compact.") || type.startsWith("autocontext.")) {
    const summary = readPayloadText(p, ["summary", "message", "status", "hydrate_mode"]);
    return summary || "Current turn uses summarized context";
  }
  return readPayloadText(p);
}

function projectRuntimeEventToDisplayEvent(event) {
  if (!event || typeof event !== "object") {
    return null;
  }
  const eventType = String(event.type || "").trim();
  if (!eventType) {
    return null;
  }
  const displayType = classifyDisplayEventType(eventType);
  if (!displayType) {
    return null;
  }
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  const body = sanitizeDisplayEventBody(buildDisplayBodyFromRuntimeEvent(eventType, payload));
  if (!body) {
    return null;
  }
  const seq = Number(event.seq);
  const createdAt = String(event.created_at || event.ts || event.createdAt || "").trim() || null;
  return {
    display_type: displayType,
    body,
    seq: Number.isFinite(seq) ? seq : null,
    created_at: createdAt,
    source_event_type: eventType
  };
}

function projectDisplayEventsFromRuntimeEvents(events) {
  if (!Array.isArray(events)) {
    return [];
  }
  const out = [];
  const seen = new Set();
  for (const event of events) {
    const projected = projectRuntimeEventToDisplayEvent(event);
    if (!projected) {
      continue;
    }
    const key = `${projected.seq || "na"}:${projected.display_type}:${projected.body}`;
    if (seen.has(key)) {
      continue;
    }
    seen.add(key);
    out.push(projected);
  }
  return out;
}

const terminalTraceExemptRunIds = new Set(
  Array.isArray(ledgerIntegrityExemptionsContract?.terminal_trace_missing?.exempt_run_ids)
    ? ledgerIntegrityExemptionsContract.terminal_trace_missing.exempt_run_ids.map((x) => String(x || "").trim()).filter(Boolean)
    : []
);

function toBoundaryErrorPayload(error) {
  const reason = String(error?.reason || "outside_working_root");
  const spec = pathBoundaryErrorContract?.reasons?.[reason] || null;
  return {
    status: Number(spec?.status || pathBoundaryErrorContract?.default_status || 403),
    body: {
      error: String(pathBoundaryErrorContract?.error || "path_boundary_rejected"),
      error_code: String(spec?.error_code || `path_boundary_${reason}`),
      reason,
      check_type: String(error?.check_type || "path_access"),
      path: typeof error?.path === "string" ? error.path : null,
      workspace_root: typeof error?.workspace_root === "string" ? error.workspace_root : null
    }
  };
}

function makePathBoundaryError({ reason = "outside_working_root", checkType = "path_access", pathValue = null, workspaceRoot = null }) {
  const spec = pathBoundaryErrorContract?.reasons?.[reason] || null;
  const error = new Error(`path_boundary_rejected:${reason}:${pathValue || ""}`);
  error.name = "PathBoundaryError";
  error.code = "path_boundary_rejected";
  error.status = Number(spec?.status || pathBoundaryErrorContract?.default_status || 403);
  error.reason = reason;
  error.check_type = checkType;
  error.path = typeof pathValue === "string" ? pathValue : null;
  error.workspace_root = typeof workspaceRoot === "string" ? workspaceRoot : null;
  return error;
}

function parsePositiveInt(value, fallback) {
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) {
    return fallback;
  }
  return Math.floor(n);
}

function hashIdentifier(input) {
  return crypto.createHash("sha256").update(String(input || ""), "utf8").digest("hex");
}

function normalizeByoScope(rawScope) {
  const value = typeof rawScope === "string" && rawScope.trim() ? rawScope.trim() : BYO_DEFAULT_SCOPE;
  return BYO_SCOPES.has(value) ? value : BYO_DEFAULT_SCOPE;
}

function resolveByoProfileId(req, body = {}) {
  const headerValue = req?.headers?.["x-browser-profile-id"];
  const fromHeader = Array.isArray(headerValue) ? headerValue[0] : headerValue;
  if (typeof fromHeader === "string" && fromHeader.trim()) {
    return fromHeader.trim();
  }
  if (typeof body.browser_profile_id === "string" && body.browser_profile_id.trim()) {
    return body.browser_profile_id.trim();
  }
  return BYO_DEFAULT_PROFILE_ID;
}

function browserProfileHash(profileId) {
  return hashIdentifier(`profile:${String(profileId || BYO_DEFAULT_PROFILE_ID)}`);
}

function computeKeyFingerprint(provider, apiKey) {
  return hashIdentifier(`${provider}:${String(apiKey || "")}`);
}

function allowedByoValidationStatus(value) {
  const clean = String(value || "").trim();
  return BYO_VALIDATION_STATUSES.has(clean) ? clean : "unknown_auth_error";
}

function normalizeByoFailureReason(input) {
  if (input === null || input === undefined) {
    return null;
  }
  const clean = summarizeText(String(input), 160);
  return clean || null;
}

function emitRunEventIfExists(runId, type, payload) {
  if (typeof runId !== "string" || !runId.trim()) {
    return null;
  }
  const run = dbGet("SELECT id FROM runs WHERE id = ?", runId.trim());
  if (!run) {
    return null;
  }
  return emitEvent(runId.trim(), type, payload);
}

