function findBindingForProfile({ bindingId, provider, scope, profileHash }) {
  if (bindingId) {
    const row = dbGet("SELECT * FROM byo_key_bindings WHERE id = ?", bindingId);
    if (!row) {
      return null;
    }
    if (String(row.status || "").toLowerCase() === "deleted") {
      return null;
    }
    if (row.provider !== provider) {
      return null;
    }
    if (row.binding_scope === "browser_profile_scope" && row.browser_profile_id_hash !== profileHash) {
      return null;
    }
    return row;
  }

  if (scope === "browser_profile_scope") {
    return dbGet(
      "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = ? AND browser_profile_id_hash = ? AND status <> 'deleted' ORDER BY created_at DESC LIMIT 1",
      provider,
      scope,
      profileHash
    );
  }

  return dbGet(
    "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = ? AND status <> 'deleted' ORDER BY created_at DESC LIMIT 1",
    provider,
    scope
  );
}

function stableStringify(value) {
  if (Array.isArray(value)) {
    return `[${value.map((x) => stableStringify(x)).join(",")}]`;
  }
  if (value && typeof value === "object") {
    const keys = Object.keys(value).sort();
    return `{${keys.map((k) => `${JSON.stringify(k)}:${stableStringify(value[k])}`).join(",")}}`;
  }
  return JSON.stringify(value);
}

function toBase64Url(bufferLike) {
  const buf = Buffer.isBuffer(bufferLike) ? bufferLike : Buffer.from(bufferLike);
  return buf.toString("base64").replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

function fromBase64Url(input) {
  const value = String(input || "").trim().replace(/-/g, "+").replace(/_/g, "/");
  if (!value) return Buffer.alloc(0);
  const padLen = (4 - (value.length % 4)) % 4;
  return Buffer.from(value + "=".repeat(padLen), "base64");
}

function computePublicKeyFingerprint(publicKeyJwk) {
  return hashIdentifier(`byo-public-key:${stableStringify(publicKeyJwk || {})}`);
}

function buildByoChallengeSigningMessage({ action, challengeId, nonce, profileHash, scope }) {
  return `litecodex.byo.v1|${action}|${challengeId}|${nonce}|${profileHash}|${scope}`;
}

function pruneExpiredByoChallenges() {
  const now = Date.now();
  for (const [id, row] of byoChallengeMemory.entries()) {
    const expiresTs = Number(row?.expires_ts || 0);
    if (expiresTs > 0 && now > expiresTs) {
      byoChallengeMemory.delete(id);
    }
  }
}

function createByoChallenge({ action, profileHash, scope, bindingId = null }) {
  pruneExpiredByoChallenges();
  const challengeId = shortId("byochal");
  const nonce = toBase64Url(crypto.randomBytes(24));
  const expiresTs = Date.now() + BYO_CHALLENGE_TTL_MS;
  const record = {
    challenge_id: challengeId,
    action,
    nonce,
    profile_hash: profileHash,
    scope: normalizeByoScope(scope),
    binding_id: bindingId || null,
    created_at: nowIso(),
    expires_at: new Date(expiresTs).toISOString(),
    expires_ts: expiresTs
  };
  byoChallengeMemory.set(challengeId, record);
  return record;
}

async function verifyByoChallengeResponse({
  action,
  challengeId,
  signature,
  publicKeyJwk,
  profileHash,
  scope,
  expectedBindingRow = null
}) {
  pruneExpiredByoChallenges();
  const challenge = byoChallengeMemory.get(String(challengeId || ""));
  if (!challenge) {
    return { ok: false, error: "challenge_not_found" };
  }
  if (Date.now() > Number(challenge.expires_ts || 0)) {
    byoChallengeMemory.delete(challenge.challenge_id);
    return { ok: false, error: "challenge_expired" };
  }
  if (challenge.action !== action) {
    return { ok: false, error: "challenge_action_mismatch" };
  }
  if (challenge.profile_hash !== profileHash) {
    return { ok: false, error: "challenge_profile_mismatch" };
  }
  if (normalizeByoScope(challenge.scope) !== normalizeByoScope(scope)) {
    return { ok: false, error: "challenge_scope_mismatch" };
  }
  if (expectedBindingRow && challenge.binding_id && challenge.binding_id !== expectedBindingRow.id) {
    return { ok: false, error: "challenge_binding_mismatch" };
  }
  if (!publicKeyJwk || typeof publicKeyJwk !== "object") {
    return { ok: false, error: "public_key_missing" };
  }
  const publicKeyFingerprint = computePublicKeyFingerprint(publicKeyJwk);
  if (expectedBindingRow && expectedBindingRow.public_key_fingerprint) {
    if (String(expectedBindingRow.public_key_fingerprint) !== publicKeyFingerprint) {
      return { ok: false, error: "public_key_fingerprint_mismatch" };
    }
  }
  const signatureBytes = fromBase64Url(signature);
  if (!signatureBytes.length) {
    return { ok: false, error: "signature_missing" };
  }
  try {
    const verifyKey = await crypto.webcrypto.subtle.importKey(
      "jwk",
      publicKeyJwk,
      { name: "ECDSA", namedCurve: "P-256" },
      true,
      ["verify"]
    );
    const message = buildByoChallengeSigningMessage({
      action,
      challengeId: challenge.challenge_id,
      nonce: challenge.nonce,
      profileHash: challenge.profile_hash,
      scope: challenge.scope
    });
    const ok = await crypto.webcrypto.subtle.verify(
      { name: "ECDSA", hash: "SHA-256" },
      verifyKey,
      signatureBytes,
      Buffer.from(message, "utf8")
    );
    if (!ok) {
      return { ok: false, error: "signature_verify_failed" };
    }
  } catch (error) {
    return { ok: false, error: normalizeByoFailureReason(error instanceof Error ? error.message : "signature_verify_error") };
  } finally {
    // one-shot challenge
    byoChallengeMemory.delete(challenge.challenge_id);
  }
  return {
    ok: true,
    challenge_id: challenge.challenge_id,
    action,
    scope: challenge.scope,
    profile_hash: challenge.profile_hash,
    public_key_fingerprint: publicKeyFingerprint,
    verified_at: nowIso()
  };
}

async function verifyByoProofFromBody({ body, action, profileHash, scope, expectedBindingRow = null }) {
  const challengeId = typeof body.challenge_id === "string" ? body.challenge_id.trim() : "";
  const signature = typeof body.challenge_signature === "string" ? body.challenge_signature.trim() : "";
  const publicKeyJwk =
    body.public_key_jwk && typeof body.public_key_jwk === "object" ? body.public_key_jwk : null;
  if (!challengeId || !signature || !publicKeyJwk) {
    return { ok: false, error: "challenge_proof_missing" };
  }
  return verifyByoChallengeResponse({
    action,
    challengeId,
    signature,
    publicKeyJwk,
    profileHash,
    scope,
    expectedBindingRow
  });
}

async function getOrCreateByoProfileSigner(profileId) {
  const key = String(profileId || BYO_DEFAULT_PROFILE_ID);
  const cached = byoProfileSignerMemory.get(key);
  if (cached?.privateKey && cached?.publicKeyJwk && cached?.publicKeyFingerprint) {
    return cached;
  }
  const keyPair = await crypto.webcrypto.subtle.generateKey(
    { name: "ECDSA", namedCurve: "P-256" },
    false,
    ["sign", "verify"]
  );
  const publicKeyJwk = await crypto.webcrypto.subtle.exportKey("jwk", keyPair.publicKey);
  const signer = {
    profileId: key,
    privateKey: keyPair.privateKey,
    publicKeyJwk,
    publicKeyFingerprint: computePublicKeyFingerprint(publicKeyJwk),
    created_at: nowIso()
  };
  byoProfileSignerMemory.set(key, signer);
  return signer;
}

async function buildSyntheticByoProof({ action, profileId, scope, bindingId = null }) {
  const signer = await getOrCreateByoProfileSigner(profileId);
  const challenge = createByoChallenge({
    action,
    profileHash: browserProfileHash(profileId),
    scope,
    bindingId
  });
  const message = buildByoChallengeSigningMessage({
    action,
    challengeId: challenge.challenge_id,
    nonce: challenge.nonce,
    profileHash: challenge.profile_hash,
    scope: challenge.scope
  });
  const signature = await crypto.webcrypto.subtle.sign(
    { name: "ECDSA", hash: "SHA-256" },
    signer.privateKey,
    Buffer.from(message, "utf8")
  );
  const proofBody = {
    challenge_id: challenge.challenge_id,
    challenge_signature: toBase64Url(Buffer.from(signature)),
    public_key_jwk: signer.publicKeyJwk
  };
  const receipt = await verifyByoProofFromBody({
    body: proofBody,
    action,
    profileHash: challenge.profile_hash,
    scope: challenge.scope,
    expectedBindingRow: null
  });
  if (!receipt.ok) {
    throw new Error(`synthetic_byo_proof_failed:${receipt.error}`);
  }
  return { proofBody, receipt, signer, challenge };
}

function normalizeRetrievalReason(reasonCode) {
  const allowed = new Set([
    "user_requested_web_search",
    "freshness_required",
    "url_provided",
    "low_confidence_external_fact",
    "local_repo_sufficient",
    "deterministic_local_task"
  ]);
  return allowed.has(String(reasonCode || "")) ? String(reasonCode) : "deterministic_local_task";
}

function sanitizeUrlForRetrieval(input) {
  const raw = String(input || "").trim();
  if (!raw) return "";
  try {
    const u = new URL(raw);
    const sensitive = new Set(["token", "api_key", "apikey", "key", "otp", "code", "session", "cookie", "sig"]);
    for (const k of [...u.searchParams.keys()]) {
      if (sensitive.has(String(k).toLowerCase())) {
        u.searchParams.set(k, "[REDACTED]");
      }
    }
    return u.toString();
  } catch {
    return redactSensitiveText(raw);
  }
}

function classifyRetrievalDecision(input = {}) {
  const query = String(input.query || "").trim();
  const taskType = String(input.task_type || "").trim().toLowerCase();
  const userRequested = Boolean(input.user_requested_web_search);
  const explicitFreshness = Boolean(input.freshness_required);
  const hasUrl = /https?:\/\/[^\s]+/i.test(query) || Boolean(input.url_provided);
  const lowConfidence = Boolean(input.low_confidence_external_fact);
  if (taskType === "local_repo" || taskType === "file" || taskType === "shell") {
    return { search_needed: false, reason_code: "local_repo_sufficient" };
  }
  if (taskType === "deterministic_local") {
    return { search_needed: false, reason_code: "deterministic_local_task" };
  }
  if (userRequested) {
    return { search_needed: true, reason_code: "user_requested_web_search" };
  }
  if (explicitFreshness || /\b(latest|today|current|recent|newest|up-to-date)\b/i.test(query)) {
    return { search_needed: true, reason_code: "freshness_required" };
  }
  if (hasUrl) {
    return { search_needed: true, reason_code: "url_provided" };
  }
  if (lowConfidence) {
    return { search_needed: true, reason_code: "low_confidence_external_fact" };
  }
  return { search_needed: false, reason_code: "deterministic_local_task" };
}

