function retrievalPath(runId, relativeName) {
  const safe = String(relativeName || "").replace(/\\/g, "/").replace(/^\/+/, "");
  return path.join(runDir(runId), "retrieval", safe);
}

function writeRetrievalArtifact(runId, relativeName, content, maxBytes = 256 * 1024) {
  const target = retrievalPath(runId, relativeName);
  fs.mkdirSync(path.dirname(target), { recursive: true });
  const text = redactSensitiveText(String(content || ""));
  const bytes = Buffer.byteLength(text, "utf8");
  const out = bytes > maxBytes ? `${text.slice(0, maxBytes)}\n[TRUNCATED ${bytes - maxBytes} BYTES]\n` : text;
  fs.writeFileSync(target, out, "utf8");
  return target;
}

function extractRetrievalDomain(url) {
  try {
    return new URL(String(url || "")).hostname;
  } catch {
    return "";
  }
}

function toSourceHit({
  provider,
  url,
  title,
  snippet,
  markdown = null,
  extractedJson = null,
  publishedAt = null,
  score = null,
  fetchReason = "search",
  citationLabel
}) {
  const safeUrl = sanitizeUrlForRetrieval(url || "");
  return {
    provider,
    url: safeUrl,
    canonical_url: safeUrl,
    domain: extractRetrievalDomain(safeUrl),
    title: summarizeText(title || "", 180),
    snippet: summarizeText(snippet || "", 320),
    markdown: typeof markdown === "string" ? summarizeText(markdown, 1200) : null,
    extracted_json: extractedJson && typeof extractedJson === "object" ? extractedJson : null,
    published_at: publishedAt || null,
    fetched_at: nowIso(),
    score: Number.isFinite(Number(score)) ? Number(score) : null,
    fetch_reason: fetchReason,
    citation_label: citationLabel
  };
}

function retrievalProviderEnvKey(provider) {
  if (provider === "tavily") return "TAVILY_API_KEY";
  if (provider === "exa") return "EXA_API_KEY";
  if (provider === "firecrawl") return "FIRECRAWL_API_KEY";
  return "";
}

function evaluateProviderMemoryHealth(provider, forcedFail = false, forcedReason = null) {
  const now = nowIso();
  if (forcedFail) {
    const row = recordCredentialHealthRow({
      provider,
      source: ".env",
      sourceScope: "local_process_memory",
      grantState: "degraded",
      healthStatus: "unhealthy",
      failureReason: forcedReason || "forced_provider_failure",
      lastVerifiedAt: now
    });
    return { ready: false, key: "", healthRow: row };
  }
  const envKey = retrievalProviderEnvKey(provider);
  const key = String(process.env[envKey] || "").trim();
  if (!key) {
    const row = recordCredentialHealthRow({
      provider,
      source: ".env",
      sourceScope: "local_process_memory",
      grantState: "degraded",
      healthStatus: "unhealthy",
      failureReason: `${provider}_api_key_missing`,
      lastVerifiedAt: now
    });
    return { ready: false, key: "", healthRow: row };
  }
  const row = recordCredentialHealthRow({
    provider,
    source: ".env",
    sourceScope: "local_process_memory",
    grantState: "granted",
    healthStatus: "healthy",
    failureReason: null,
    lastVerifiedAt: now
  });
  return { ready: true, key, healthRow: row };
}

function classifySecondHopNeed({ query, tavilyHits, forceSecondHop }) {
  if (forceSecondHop) return true;
  if (!Array.isArray(tavilyHits) || tavilyHits.length < 3) return true;
  const q = String(query || "").toLowerCase();
  if (/\b(domain|site:|from:\d{4}|to:\d{4}|research|paper|policy)\b/.test(q)) return true;
  return false;
}

function uniqueHitsByUrl(hits) {
  const out = [];
  const seen = new Set();
  for (const hit of hits || []) {
    const key = String(hit?.canonical_url || hit?.url || "").toLowerCase();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(hit);
  }
  return out;
}

const retrievalProviderRuntimeState = new Map();

function wildcardMatch(value, rule) {
  const v = String(value || "").toLowerCase();
  const r = String(rule || "").toLowerCase();
  if (!v || !r) return false;
  if (r.endsWith("*")) {
    return v.startsWith(r.slice(0, -1));
  }
  if (r.startsWith("*.")) {
    const suffix = r.slice(1);
    return v.endsWith(suffix);
  }
  return v === r || v.endsWith(`.${r}`);
}

function canonicalizeRetrievalUrl(input) {
  const raw = String(input || "").trim();
  if (!raw) return "";
  try {
    const u = new URL(raw);
    const dropRules = Array.isArray(citationQualityGateContract?.canonicalization_rules?.drop_tracking_query_params)
      ? citationQualityGateContract.canonicalization_rules.drop_tracking_query_params
      : [];
    for (const k of [...u.searchParams.keys()]) {
      const lower = String(k).toLowerCase();
      if (dropRules.some((rule) => wildcardMatch(lower, rule))) {
        u.searchParams.delete(k);
      }
    }
    u.hash = "";
    u.protocol = u.protocol.toLowerCase();
    u.hostname = u.hostname.toLowerCase();
    if (u.pathname.length > 1) {
      u.pathname = u.pathname.replace(/\/+$/, "");
    }
    return sanitizeUrlForRetrieval(u.toString());
  } catch {
    return sanitizeUrlForRetrieval(raw);
  }
}

function retrievalDomainTrustTier(domain) {
  const d = String(domain || "").toLowerCase();
  const tiers = citationQualityGateContract?.domain_trust_tiers || {};
  if (!d) return "low";
  for (const item of tiers.blocked || []) {
    if (wildcardMatch(d, item)) return "blocked";
  }
  for (const item of tiers.high || []) {
    if (wildcardMatch(d, item)) return "high";
  }
  for (const item of tiers.medium || []) {
    if (wildcardMatch(d, item)) return "medium";
  }
  for (const item of tiers.low || []) {
    if (wildcardMatch(d, item)) return "low";
  }
  return "low";
}

function retrievalStaleScore(publishedAt) {
  const policy = citationQualityGateContract?.stale_source_policy || {};
  const bands = Array.isArray(policy.stale_score_days_bands) ? policy.stale_score_days_bands : [];
  const ts = Date.parse(String(publishedAt || ""));
  if (!Number.isFinite(ts)) {
    return Number(policy.unknown_published_at_score || 0.55);
  }
  const ageDays = Math.max(0, Math.floor((Date.now() - ts) / 86400000));
  for (const b of bands) {
    if (ageDays <= Number(b.max_days || 0)) {
      return Number(b.score || 0);
    }
  }
  return 0.4;
}

function rankDomainTier(tier) {
  if (tier === "high") return 4;
  if (tier === "medium") return 3;
  if (tier === "low") return 2;
  return 1;
}

function retrievalHitRankScore(hit) {
  const sourceScore = Number.isFinite(Number(hit?.score)) ? Number(hit.score) : 0;
  const staleScore = Number.isFinite(Number(hit?.stale_score)) ? Number(hit.stale_score) : 0;
  const tierScore = rankDomainTier(String(hit?.domain_trust_tier || "low"));
  const fetchedTs = Date.parse(String(hit?.published_at || hit?.fetched_at || ""));
  const timeScore = Number.isFinite(fetchedTs) ? fetchedTs / 1e14 : 0;
  return sourceScore * 4 + staleScore * 2 + tierScore + timeScore;
}

function updateRetrievalHitGovernance(hit) {
  const sourceHitId = String(hit?.source_hit_id || "").trim();
  if (!sourceHitId) return;
  dbRun(
    `UPDATE retrieval_hits
     SET canonical_url = ?, domain_trust_tier = ?, stale_score = ?, citation_eligible = ?, citation_reject_reason = ?, dedup_cluster_id = ?
     WHERE id = ?`,
    sanitizeUrlForRetrieval(hit.canonical_url || hit.url || ""),
    summarizeText(hit.domain_trust_tier || "low", 24),
    Number.isFinite(Number(hit.stale_score)) ? Number(hit.stale_score) : null,
    hit.citation_eligible ? 1 : 0,
    hit.citation_reject_reason ? summarizeText(hit.citation_reject_reason, 96) : null,
    hit.dedup_cluster_id ? summarizeText(hit.dedup_cluster_id, 64) : null,
    sourceHitId
  );
}

function applyCitationQualityGate({ runId, reasonCode, sources }) {
  const list = Array.isArray(sources) ? sources.map((x) => ({ ...x })) : [];
  const groups = new Map();
  const freshnessMin = Number(citationQualityGateContract?.stale_source_policy?.freshness_required_min_stale_score || 0.45);
  for (const hit of list) {
    const canonicalUrl = canonicalizeRetrievalUrl(hit.canonical_url || hit.url || "");
    hit.canonical_url = canonicalUrl;
    hit.domain = extractRetrievalDomain(canonicalUrl || hit.url || "");
    hit.domain_trust_tier = retrievalDomainTrustTier(hit.domain);
    hit.stale_score = retrievalStaleScore(hit.published_at);
    hit.citation_eligible = true;
    hit.citation_reject_reason = null;
    if (!canonicalUrl) {
      hit.citation_eligible = false;
      hit.citation_reject_reason = "missing_url";
    } else if (!String(hit.title || "").trim() && !String(hit.snippet || "").trim()) {
      hit.citation_eligible = false;
      hit.citation_reject_reason = "missing_content";
    } else if (hit.domain_trust_tier === "blocked") {
      hit.citation_eligible = false;
      hit.citation_reject_reason = "blocked_domain_tier";
    } else if (reasonCode === "freshness_required" && Number(hit.stale_score) < freshnessMin) {
      hit.citation_eligible = false;
      hit.citation_reject_reason = "stale_source";
    }
    const clusterId = `dup_${hashIdentifier(canonicalUrl || hit.url || shortId("dup")).slice(0, 12)}`;
    hit.dedup_cluster_id = clusterId;
    if (!groups.has(clusterId)) {
      groups.set(clusterId, []);
    }
    groups.get(clusterId).push(hit);
  }

  for (const cluster of groups.values()) {
    if (cluster.length <= 1) continue;
    const sorted = [...cluster].sort((a, b) => retrievalHitRankScore(b) - retrievalHitRankScore(a));
    const winner = sorted[0];
    for (const loser of sorted.slice(1)) {
      if (loser === winner) continue;
      loser.citation_eligible = false;
      loser.citation_reject_reason = "duplicate_collapsed";
    }
  }

  let eligibleCount = 0;
  let rejectedCount = 0;
  for (const hit of list) {
    if (hit.citation_eligible) eligibleCount += 1;
    else rejectedCount += 1;
    const row = recordCitationGateCheckRow({
      runId,
      sourceHitId: hit.source_hit_id || shortId("src"),
      canonicalUrl: hit.canonical_url || hit.url,
      citationEligible: Boolean(hit.citation_eligible),
      rejectReason: hit.citation_reject_reason,
      dedupClusterId: hit.dedup_cluster_id
    });
    hit.citation_gate_check_id = row.id;
    updateRetrievalHitGovernance(hit);
  }

  emitEvent(runId, "retrieval.citation.gate.checked", {
    total_sources: list.length,
    citation_eligible_count: eligibleCount,
    citation_rejected_count: rejectedCount
  });
  return { sources: list, eligibleCount, rejectedCount };
}

function factSignalFromHit(hit) {
  const text = `${hit?.title || ""} ${hit?.snippet || ""}`;
  const semver = text.match(/\b(v?\d+\.\d+(?:\.\d+)?)\b/i);
  if (semver) return semver[1].toLowerCase();
  const numeric = text.match(/\b(\d{4}|\d{1,3}(?:\.\d+)?)\b/);
  if (numeric) return numeric[1];
  return summarizeText(String(hit?.snippet || hit?.title || "").toLowerCase(), 64);
}

function factConfidenceFromHit(hit) {
  const tierWeight = { high: 0.35, medium: 0.25, low: 0.15, blocked: 0.05 }[String(hit?.domain_trust_tier || "low")] || 0.15;
  const stale = Number.isFinite(Number(hit?.stale_score)) ? Number(hit.stale_score) : 0.5;
  const sourceScore = Number.isFinite(Number(hit?.score)) ? Math.min(1, Math.max(0, Number(hit.score))) : 0.5;
  const conf = 0.15 + tierWeight + stale * 0.3 + sourceScore * 0.2;
  return Math.max(0, Math.min(1, Number(conf.toFixed(3))));
}

function buildConflictAwareBundleParts({ runId, query, sources }) {
  const eligible = (Array.isArray(sources) ? sources : []).filter((x) => x.citation_eligible === true);
  if (!eligible.length) {
    const gaps = [
      {
        reason: String(conflictResolutionContract?.insufficient_evidence_rules?.gap_reason || "insufficient_evidence"),
        detail: "No citation-eligible sources after citation quality gate."
      }
    ];
    const row = recordConflictResolutionRunRow({
      runId,
      conflictCount: 0,
      resolvedCount: 0,
      unresolvedCount: 0,
      evidencePath: null
    });
    return {
      facts: [],
      conflicts: [],
      gaps,
      finalBundleStatus: "insufficient_evidence",
      conflictRowId: row.id
    };
  }

  const factCandidates = eligible.map((hit, idx) => {
    const confidence = factConfidenceFromHit(hit);
    return {
      fact_id: `F${idx + 1}`,
      fact: summarizeText(String(hit.snippet || hit.title || ""), 220),
      confidence,
      provenance_refs: [hit.source_hit_id || hit.citation_gate_check_id || `src-${idx + 1}`],
      citation_labels: [hit.citation_label || `S${idx + 1}`],
      signal: factSignalFromHit(hit),
      source: hit
    };
  });
  const facts = factCandidates.map((x) => ({
    fact_id: x.fact_id,
    fact: x.fact,
    confidence: x.confidence,
    provenance_refs: x.provenance_refs,
    citation_labels: x.citation_labels
  }));

  const signalGroups = new Map();
  for (const item of factCandidates) {
    const key = String(item.signal || "unknown");
    if (!signalGroups.has(key)) signalGroups.set(key, []);
    signalGroups.get(key).push(item);
  }
  const distinctSignals = [...signalGroups.keys()].filter(Boolean);
  const conflicts = [];
  const gaps = [];
  let resolvedCount = 0;
  let unresolvedCount = 0;
  if (distinctSignals.length >= Number(conflictResolutionContract?.conflict_detection_rules?.conflict_when_distinct_values_count_gte || 2)) {
    emitEvent(runId, "retrieval.conflict.detected", {
      conflict_topic: summarizeText(query || "primary_claim", 120),
      candidate_values: distinctSignals.slice(0, 6)
    });
    const sorted = [...factCandidates].sort((a, b) => Number(b.confidence) - Number(a.confidence));
    const winner = sorted[0] || null;
    const runnerUp = sorted[1] || null;
    const margin = winner && runnerUp ? Number(winner.confidence) - Number(runnerUp.confidence) : 1;
    const minMargin = Number(conflictResolutionContract?.conflict_resolution_rules?.min_confidence_margin_for_resolved || 0.15);
    const resolved = margin >= minMargin;
    const conflictEntry = {
      conflict_id: shortId("conf"),
      topic: summarizeText(query || "primary_claim", 120),
      status: resolved
        ? String(conflictResolutionContract?.conflict_resolution_rules?.resolved_status || "resolved_conflict")
        : String(conflictResolutionContract?.conflict_resolution_rules?.unresolved_status || "unresolved_conflict"),
      winner: resolved && winner ? winner.fact_id : null,
      candidate_values: distinctSignals.slice(0, 6),
      provenance_refs: factCandidates.flatMap((x) => x.provenance_refs).slice(0, 12)
    };
    conflicts.push(conflictEntry);
    if (resolved) {
      resolvedCount += 1;
      emitEvent(runId, "retrieval.conflict.resolved", {
        conflict_id: conflictEntry.conflict_id,
        winner: conflictEntry.winner
      });
    } else {
      unresolvedCount += 1;
      gaps.push({
        reason: "insufficient_evidence",
        detail: "Conflict unresolved because confidence margin is below threshold."
      });
      emitEvent(runId, "retrieval.conflict.unresolved", {
        conflict_id: conflictEntry.conflict_id,
        reason: "confidence_margin_too_low"
      });
    }
  }
  const finalBundleStatus = unresolvedCount > 0 ? "unresolved_conflict" : "ready";
  const row = recordConflictResolutionRunRow({
    runId,
    conflictCount: conflicts.length,
    resolvedCount,
    unresolvedCount,
    evidencePath: null
  });
  return { facts, conflicts, gaps, finalBundleStatus, conflictRowId: row.id };
}

function retrievalProviderState(provider) {
  const key = String(provider || "").toLowerCase();
  if (!retrievalProviderRuntimeState.has(key)) {
    retrievalProviderRuntimeState.set(key, { health: "unknown", cooldownUntil: null, failures: 0 });
  }
  return retrievalProviderRuntimeState.get(key);
}

function providerInCooldown(provider) {
  const ttlMs = parsePositiveInt(providerHealthGovernanceContract?.health_ttl_ms, 300000);
  const key = String(provider || "").toLowerCase();
  const state = retrievalProviderState(key);
  const localCooldownTs = Date.parse(String(state.cooldownUntil || ""));
  if (Number.isFinite(localCooldownTs) && localCooldownTs > Date.now()) {
    return true;
  }
  const row = dbGet(
    "SELECT * FROM provider_health_governance WHERE provider = ? ORDER BY created_at DESC LIMIT 1",
    key
  );
  if (!row) return false;
  const rowTs = Date.parse(String(row.created_at || ""));
  if (!Number.isFinite(rowTs) || Date.now() - rowTs > ttlMs) {
    return false;
  }
  const cooldownUntilTs = Date.parse(String(row.cooldown_until || ""));
  if (Number.isFinite(cooldownUntilTs) && cooldownUntilTs > Date.now()) {
    state.cooldownUntil = row.cooldown_until;
    state.health = row.new_health || state.health;
    return true;
  }
  return false;
}

function updateProviderHealthGovernance({ runId, provider, healthy, fallbackDecision = null, failureReason = null }) {
  const key = String(provider || "").toLowerCase();
  const state = retrievalProviderState(key);
  const previous = state.health || "unknown";
  const failureWindow = providerHealthGovernanceContract?.failure_window || {};
  const threshold = parsePositiveInt(failureWindow.degrade_threshold, 2);
  const cooldownMs = parsePositiveInt(
    providerHealthGovernanceContract?.temporary_disable_policy?.cooldown_ms ||
      retrievalBudgetPolicyContract?.cooldown_policy?.cooldown_ms,
    120000
  );
  if (healthy) {
    state.health = "healthy";
    state.failures = 0;
    state.cooldownUntil = null;
  } else {
    state.failures = Number(state.failures || 0) + 1;
    state.health = state.failures >= threshold ? "degraded" : "unhealthy";
    if (state.failures >= threshold) {
      state.cooldownUntil = new Date(Date.now() + cooldownMs).toISOString();
    }
  }
  const row = recordProviderHealthGovernanceRow({
    runId,
    provider: key,
    previousHealth: previous,
    newHealth: state.health,
    fallbackDecision: fallbackDecision || failureReason || null,
    cooldownUntil: state.cooldownUntil
  });
  emitEvent(runId, "retrieval.health.updated", {
    provider: key,
    previous_health: previous,
    new_health: state.health,
    failure_reason: failureReason || null,
    fallback_decision: fallbackDecision || null,
    cooldown_until: state.cooldownUntil
  });
  return row;
}

async function runTavilyMinimalSearch({ runId, query, reasonCode, suppressBundle = false }) {
  const tavilyKey = String(process.env.TAVILY_API_KEY || "").trim();
  if (!tavilyKey) {
    throw new Error("tavily_api_key_missing");
  }
  const provider = "tavily";
  emitEvent(runId, "retrieval.query_planned", {
    provider,
    query_summary: summarizeText(query, 240),
    search_depth: "basic",
    max_results: 5,
    auto_parameters: false
  });
  emitEvent(runId, "retrieval.provider_selected", {
    provider,
    enabled_providers: ["tavily", "exa", "firecrawl_fetch"],
    disabled_providers: ["firecrawl_search", "firecrawl_crawl"]
  });
  emitEvent(runId, "retrieval.search_started", {
    provider,
    reason_code: reasonCode
  });
  const startedAt = Date.now();
  const response = await fetch("https://api.tavily.com/search", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${tavilyKey}`
    },
    body: JSON.stringify({
      query,
      search_depth: "basic",
      max_results: 5,
      include_answer: false,
      include_raw_content: false,
      include_images: false,
      auto_parameters: false
    })
  });
  const bodyText = await response.text();
  const latencyMs = Date.now() - startedAt;
  const rawDisk = writeRetrievalArtifact(runId, `tavily_search_${Date.now()}.json`, bodyText, 256 * 1024);
  if (!response.ok) {
    throw new Error(`tavily_http_${response.status}:${summarizeText(bodyText, 120)}`);
  }
  const parsed = safeParseJson(bodyText) || {};
  const results = Array.isArray(parsed.results) ? parsed.results : [];
  const hits = [];
  for (let i = 0; i < results.length; i += 1) {
    const row = results[i] || {};
    const url = String(row.url || "").trim();
    const citationLabel = `S${i + 1}`;
    const sourceHit = toSourceHit({
      provider,
      url,
      title: String(row.title || ""),
      snippet: String(row.content || row.snippet || ""),
      markdown: null,
      extractedJson: null,
      publishedAt: row.published_date || null,
      score: row.score,
      fetchReason: "search",
      citationLabel
    });
    const hitRow = recordRetrievalHitRow({
      runId,
      provider,
      url: sourceHit.url,
      canonicalUrl: sourceHit.canonical_url,
      title: sourceHit.title,
      domain: sourceHit.domain,
      score: sourceHit.score,
      citationLabel
    });
    sourceHit.source_hit_id = hitRow.id;
    hits.push(sourceHit);
  }
  emitEvent(runId, "retrieval.search_completed", {
    provider,
    hits_count: hits.length,
    latency_ms: latencyMs
  });
  if (suppressBundle) {
    return {
      provider,
      hits,
      latency_ms: latencyMs,
      credits_estimate: 1,
      raw_context_ref: rawDisk,
      bundle: null,
      bundle_path: null
    };
  }
  const bundle = {
    decision: { search_needed: true, reason_code: reasonCode },
    query_plan: {
      provider_chain: [provider],
      query: summarizeText(query, 280),
      search_depth: "basic",
      max_results: 5,
      auto_parameters: false,
      fetch_targets: []
    },
    sources: hits,
    facts: hits.map((x) => ({ citation_label: x.citation_label, fact: x.snippet })),
    conflicts: [],
    gaps: hits.length ? [] : ["no_hits_returned"],
    summary: hits.length
      ? `Retrieved ${hits.length} source hit(s) via tavily basic search.`
      : "No source hits returned by tavily.",
    raw_context_refs: [rawDisk],
    provider_status: [
      { provider: "tavily", status: "healthy", latency_ms: latencyMs, credits_estimate: 1, failure_reason: null }
    ]
  };
  const bundlePath = writeRetrievalArtifact(
    runId,
    `evidence_bundle_${Date.now()}.json`,
    `${JSON.stringify(bundle, null, 2)}\n`,
    256 * 1024
  );
  const bundleRow = recordRetrievalBundleRow({
    runId,
    provider,
    providerChain: [provider],
    evidenceBundlePath: bundlePath,
    sourcesCount: bundle.sources.length,
    factsCount: bundle.facts.length,
    conflictsCount: bundle.conflicts.length,
    gapsCount: bundle.gaps.length
  });
  emitEvent(runId, "retrieval.bundle_ready", {
    provider,
    provider_chain: [provider],
    provider_status: bundle.provider_status,
    evidence_bundle_path: bundlePath,
    sources_count: bundleRow.sources_count,
    facts_count: bundleRow.facts_count,
    conflicts_count: bundleRow.conflicts_count,
    gaps_count: bundleRow.gaps_count
  });
  return { provider, hits, latency_ms: latencyMs, credits_estimate: 1, raw_context_ref: rawDisk, bundle, bundle_path: bundlePath };
}

async function runExaSecondHopSearch({ runId, query, reasonCode }) {
  const exaKey = String(process.env.EXA_API_KEY || "").trim();
  if (!exaKey) {
    throw new Error("exa_api_key_missing");
  }
  const provider = "exa";
  emitEvent(runId, "retrieval.query_planned", {
    provider,
    query_summary: summarizeText(query, 240),
    mode: "second_hop_highlights",
    max_results: 5
  });
  emitEvent(runId, "retrieval.provider_selected", {
    provider,
    selected_mode: "second_hop",
    reason_code: reasonCode
  });
  emitEvent(runId, "retrieval.search_started", {
    provider,
    reason_code: reasonCode
  });
  const startedAt = Date.now();
  const response = await fetch("https://api.exa.ai/search", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": exaKey
    },
    body: JSON.stringify({
      query,
      numResults: 5,
      type: "keyword",
      useAutoprompt: false,
      contents: {
        highlights: {
          numSentences: 2,
          highlightsPerUrl: 1
        }
      }
    })
  });
  const bodyText = await response.text();
  const latencyMs = Date.now() - startedAt;
  const rawDisk = writeRetrievalArtifact(runId, `exa_search_${Date.now()}.json`, bodyText, 256 * 1024);
  if (!response.ok) {
    recordCredentialHealthRow({
      provider,
      source: ".env",
      sourceScope: "local_process_memory",
      grantState: "degraded",
      healthStatus: "unhealthy",
      failureReason: `exa_http_${response.status}`,
      lastVerifiedAt: nowIso()
    });
    throw new Error(`exa_http_${response.status}:${summarizeText(bodyText, 120)}`);
  }
  const parsed = safeParseJson(bodyText) || {};
  const results = Array.isArray(parsed.results) ? parsed.results : [];
  const hits = [];
  for (let i = 0; i < results.length; i += 1) {
    const row = results[i] || {};
    const highlights = Array.isArray(row.highlights) ? row.highlights : [];
    const snippet = highlights.length ? String(highlights[0] || "") : String(row.text || row.snippet || "");
    const citationLabel = `S${i + 1}`;
    const sourceHit = toSourceHit({
      provider,
      url: String(row.url || ""),
      title: String(row.title || ""),
      snippet,
      markdown: null,
      extractedJson: null,
      publishedAt: row.publishedDate || null,
      score: row.score,
      fetchReason: "search",
      citationLabel
    });
    const hitRow = recordRetrievalHitRow({
      runId,
      provider,
      url: sourceHit.url,
      canonicalUrl: sourceHit.canonical_url,
      title: sourceHit.title,
      domain: sourceHit.domain,
      score: sourceHit.score,
      citationLabel
    });
    sourceHit.source_hit_id = hitRow.id;
    hits.push(sourceHit);
  }
  recordCredentialHealthRow({
    provider,
    source: ".env",
    sourceScope: "local_process_memory",
    grantState: "granted",
    healthStatus: "healthy",
    failureReason: null,
    lastVerifiedAt: nowIso()
  });
  emitEvent(runId, "retrieval.search_completed", {
    provider,
    hits_count: hits.length,
    latency_ms: latencyMs
  });
  return { provider, hits, latency_ms: latencyMs, credits_estimate: 1, raw_context_ref: rawDisk };
}

async function runFirecrawlScrape({ runId, targetUrl, reasonCode }) {
  const firecrawlKey = String(process.env.FIRECRAWL_API_KEY || "").trim();
  if (!firecrawlKey) {
    throw new Error("firecrawl_api_key_missing");
  }
  const provider = "firecrawl_fetch";
  emitEvent(runId, "retrieval.provider_selected", {
    provider,
    selected_mode: "scrape",
    reason_code: reasonCode
  });
  emitEvent(runId, "retrieval.fetch_started", {
    provider,
    fetch_type: "scrape",
    target_url: sanitizeUrlForRetrieval(targetUrl || "")
  });
  const startedAt = Date.now();
  const response = await fetch("https://api.firecrawl.dev/v1/scrape", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${firecrawlKey}`
    },
    body: JSON.stringify({
      url: targetUrl,
      formats: ["markdown"]
    })
  });
  const bodyText = await response.text();
  const latencyMs = Date.now() - startedAt;
  const rawDisk = writeRetrievalArtifact(runId, `firecrawl_scrape_${Date.now()}.json`, bodyText, 512 * 1024);
  if (!response.ok) {
    const fetchRow = recordRetrievalFetchRow({
      runId,
      provider: "firecrawl",
      fetchType: "scrape",
      targetUrl,
      status: `failed_http_${response.status}`,
      artifactPath: rawDisk
    });
    recordCredentialHealthRow({
      provider: "firecrawl",
      source: ".env",
      sourceScope: "local_process_memory",
      grantState: "degraded",
      healthStatus: "unhealthy",
      failureReason: `firecrawl_http_${response.status}`,
      lastVerifiedAt: nowIso()
    });
    emitEvent(runId, "retrieval.fetch_completed", {
      provider,
      fetch_type: "scrape",
      retrieval_fetch_id: fetchRow.id,
      status: "failed"
    });
    throw new Error(`firecrawl_scrape_http_${response.status}:${summarizeText(bodyText, 120)}`);
  }
  const parsed = safeParseJson(bodyText) || {};
  const markdown = String(parsed?.data?.markdown || "");
  const title = String(parsed?.data?.metadata?.title || targetUrl || "firecrawl scrape");
  const sourceHit = toSourceHit({
    provider: "firecrawl_scrape",
    url: targetUrl,
    title,
    snippet: markdown || title,
    markdown: markdown || null,
    extractedJson: null,
    publishedAt: parsed?.data?.metadata?.publishedTime || null,
    score: 1,
    fetchReason: "scrape",
    citationLabel: "S1"
  });
  const scrapeHitRow = recordRetrievalHitRow({
    runId,
    provider: "firecrawl_scrape",
    url: sourceHit.url,
    canonicalUrl: sourceHit.canonical_url,
    title: sourceHit.title,
    domain: sourceHit.domain,
    score: sourceHit.score,
    citationLabel: sourceHit.citation_label
  });
  sourceHit.source_hit_id = scrapeHitRow.id;
  const fetchRow = recordRetrievalFetchRow({
    runId,
    provider: "firecrawl",
    fetchType: "scrape",
    targetUrl,
    status: "completed",
    artifactPath: rawDisk
  });
  recordCredentialHealthRow({
    provider: "firecrawl",
    source: ".env",
    sourceScope: "local_process_memory",
    grantState: "granted",
    healthStatus: "healthy",
    failureReason: null,
    lastVerifiedAt: nowIso()
  });
  emitEvent(runId, "retrieval.fetch_completed", {
    provider,
    fetch_type: "scrape",
    retrieval_fetch_id: fetchRow.id,
    status: "completed",
    latency_ms: latencyMs
  });
  return { provider, fetch_type: "scrape", hits: [sourceHit], latency_ms: latencyMs, credits_estimate: 1, raw_context_ref: rawDisk };
}

async function runFirecrawlExtract({ runId, targetUrls, reasonCode, extractionGoal }) {
  const firecrawlKey = String(process.env.FIRECRAWL_API_KEY || "").trim();
  if (!firecrawlKey) {
    throw new Error("firecrawl_api_key_missing");
  }
  const boundedUrls = (Array.isArray(targetUrls) ? targetUrls : [])
    .map((x) => String(x || "").trim())
    .filter(Boolean)
    .slice(0, Math.max(1, parsePositiveInt(retrievalBudgetPolicyContract?.max_urls_per_task, 3)));
  const provider = "firecrawl_fetch";
  emitEvent(runId, "retrieval.provider_selected", {
    provider,
    selected_mode: "extract",
    reason_code: reasonCode
  });
  emitEvent(runId, "retrieval.fetch_started", {
    provider,
    fetch_type: "extract",
    target_urls: boundedUrls.map((x) => sanitizeUrlForRetrieval(x))
  });
  const startedAt = Date.now();
  const response = await fetch("https://api.firecrawl.dev/v1/extract", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${firecrawlKey}`
    },
    body: JSON.stringify({
      urls: boundedUrls,
      prompt:
        extractionGoal ||
        "Extract key facts and output compact JSON with keys topic,value,source."
    })
  });
  const bodyText = await response.text();
  const latencyMs = Date.now() - startedAt;
  const rawDisk = writeRetrievalArtifact(runId, `firecrawl_extract_${Date.now()}.json`, bodyText, 512 * 1024);
  if (!response.ok) {
    const fetchRow = recordRetrievalFetchRow({
      runId,
      provider: "firecrawl",
      fetchType: "extract",
      targetUrl: boundedUrls.join(","),
      status: `failed_http_${response.status}`,
      artifactPath: rawDisk
    });
    recordCredentialHealthRow({
      provider: "firecrawl",
      source: ".env",
      sourceScope: "local_process_memory",
      grantState: "degraded",
      healthStatus: "unhealthy",
      failureReason: `firecrawl_http_${response.status}`,
      lastVerifiedAt: nowIso()
    });
    emitEvent(runId, "retrieval.fetch_completed", {
      provider,
      fetch_type: "extract",
      retrieval_fetch_id: fetchRow.id,
      status: "failed"
    });
    throw new Error(`firecrawl_extract_http_${response.status}:${summarizeText(bodyText, 120)}`);
  }
  const parsed = safeParseJson(bodyText) || {};
  const extracted = parsed?.data || parsed || {};
  const hits = boundedUrls.map((url, idx) =>
    toSourceHit({
      provider: "firecrawl_extract",
      url,
      title: `Firecrawl extract target ${idx + 1}`,
      snippet: JSON.stringify(extracted),
      markdown: null,
      extractedJson: extracted,
      publishedAt: null,
      score: 1,
      fetchReason: "extract",
      citationLabel: `S${idx + 1}`
    })
  );
  for (const hit of hits) {
    const hitRow = recordRetrievalHitRow({
      runId,
      provider: "firecrawl_extract",
      url: hit.url,
      canonicalUrl: hit.canonical_url,
      title: hit.title,
      domain: hit.domain,
      score: hit.score,
      citationLabel: hit.citation_label
    });
    hit.source_hit_id = hitRow.id;
  }
  const fetchRow = recordRetrievalFetchRow({
    runId,
    provider: "firecrawl",
    fetchType: "extract",
    targetUrl: boundedUrls.join(","),
    status: "completed",
    artifactPath: rawDisk
  });
  recordCredentialHealthRow({
    provider: "firecrawl",
    source: ".env",
    sourceScope: "local_process_memory",
    grantState: "granted",
    healthStatus: "healthy",
    failureReason: null,
    lastVerifiedAt: nowIso()
  });
  emitEvent(runId, "retrieval.fetch_completed", {
    provider,
    fetch_type: "extract",
    retrieval_fetch_id: fetchRow.id,
    status: "completed",
    latency_ms: latencyMs
  });
  return { provider, fetch_type: "extract", hits, latency_ms: latencyMs, credits_estimate: 1, raw_context_ref: rawDisk };
}

function buildRetrievalBundle({
  decision,
  query,
  providerChain,
  sources,
  rawContextRefs,
  providerStatus,
  fetchTargets
}) {
  const uniqueSources = uniqueHitsByUrl(sources || []);
  const facts = uniqueSources.slice(0, 8).map((x) => ({
    citation_label: x.citation_label,
    fact: summarizeText(x.snippet || x.title || "", 220)
  }));
  return {
    decision: {
      search_needed: Boolean(decision?.search_needed),
      reason_code: normalizeRetrievalReason(decision?.reason_code)
    },
    query_plan: {
      provider_chain: providerChain,
      query: summarizeText(query || "", 280),
      search_depth: "basic",
      max_results: 5,
      auto_parameters: false,
      fetch_targets: Array.isArray(fetchTargets) ? fetchTargets.map((x) => sanitizeUrlForRetrieval(x)) : []
    },
    sources: uniqueSources,
    facts,
    conflicts: [],
    gaps: uniqueSources.length ? [] : ["no_sources_collected"],
    summary: uniqueSources.length
      ? `Collected ${uniqueSources.length} source hit(s) from provider chain: ${providerChain.join(" -> ")}.`
      : "No sources collected from selected providers.",
    raw_context_refs: Array.isArray(rawContextRefs) ? rawContextRefs.filter(Boolean) : [],
    provider_status: Array.isArray(providerStatus) ? providerStatus : []
  };
}

async function executeRetrievalPipeline(runId, options = {}) {
  const query = String(options.query || "").trim();
  const decision = options.decision || classifyRetrievalDecision(options);
  const forceSecondHopExa = Boolean(options.force_second_hop_exa);
  const disableSecondHop = Boolean(options.disable_second_hop);
  const forceProviderFail = String(options.force_provider_fail || "").trim().toLowerCase();
  const preferredProvider = String(options.preferred_provider || "tavily").trim().toLowerCase();
  const firecrawlMode = String(options.firecrawl_mode || "").trim().toLowerCase();
  const maxRounds = Math.max(1, Math.min(2, parsePositiveInt(retrievalBudgetPolicyContract?.max_search_rounds, 2)));
  const maxUrlsPerTask = Math.max(1, parsePositiveInt(retrievalBudgetPolicyContract?.max_urls_per_task, 3));
  const providerBudgetCeiling = retrievalBudgetPolicyContract?.provider_budget_ceiling || {};
  const explicitUrls = Array.isArray(options.urls) ? options.urls : [];
  const queryUrls = [...query.matchAll(/https?:\/\/[^\s)]+/gi)].map((m) => String(m[0]));
  const fetchTargets = [...new Set([...explicitUrls, ...queryUrls].map((x) => String(x || "").trim()).filter(Boolean))].slice(
    0,
    maxUrlsPerTask
  );
  const providerChain = [];
  const allSources = [];
  const rawContextRefs = [];
  const providerStatus = [];
  const providerUsage = new Map();
  let degradedMode = false;
  let roundsUsed = 0;
  const urlsUsed = fetchTargets.length;

  const pushProviderStatus = (provider, status, latencyMs = null, creditsEstimate = null, failureReason = null) => {
    providerStatus.push({
      provider,
      status,
      latency_ms: latencyMs,
      credits_estimate: creditsEstimate,
      failure_reason: failureReason
    });
  };
  const markDegraded = (provider, reason) => {
    degradedMode = true;
    emitEvent(runId, "retrieval.degraded.mode.entered", {
      provider: provider || null,
      reason: summarizeText(reason || "degraded_mode", 160)
    });
  };
  const canUseProviderByBudget = (provider) => {
    const key = String(provider || "");
    const used = Number(providerUsage.get(key) || 0);
    const ceiling = Math.max(1, parsePositiveInt(providerBudgetCeiling?.[key], 1));
    return used < ceiling;
  };
  const markProviderUsed = (provider) => {
    const key = String(provider || "");
    providerUsage.set(key, Number(providerUsage.get(key) || 0) + 1);
  };

  if (decision.search_needed !== true) {
    const bundle = {
      decision: {
        search_needed: false,
        reason_code: normalizeRetrievalReason(decision.reason_code)
      },
      query_plan: {
        provider_chain: [],
        query: summarizeText(query || "", 280),
        search_depth: null,
        max_results: null,
        auto_parameters: null,
        fetch_targets: []
      },
      sources: [],
      facts: [],
      conflicts: [],
      gaps: [],
      summary: "No web search required for this deterministic/local task.",
      raw_context_refs: [],
      provider_status: [],
      final_bundle_status: "ready"
    };
    const bundlePath = writeRetrievalArtifact(runId, `evidence_bundle_${Date.now()}.json`, `${JSON.stringify(bundle, null, 2)}\n`);
    const bundleRow = recordRetrievalBundleRow({
      runId,
      provider: "none",
      providerChain: [],
      evidenceBundlePath: bundlePath,
      sourcesCount: 0,
      factsCount: 0,
      conflictsCount: 0,
      gapsCount: bundle.gaps.length,
      finalBundleStatus: bundle.final_bundle_status
    });
    const budgetRow = recordRetrievalBudgetCheckRow({
      runId,
      providerChain: [],
      roundsUsed: 0,
      urlsUsed: 0,
      budgetStatus: "not_required",
      degradedMode: false
    });
    emitEvent(runId, "retrieval.budget.checked", {
      budget_check_id: budgetRow.id,
      rounds_used: 0,
      urls_used: 0,
      budget_status: "not_required",
      degraded_mode: false
    });
    emitEvent(runId, "retrieval.bundle_ready", {
      provider_chain: [],
      evidence_bundle_path: bundlePath,
      sources_count: bundleRow.sources_count,
      facts_count: bundleRow.facts_count,
      conflicts_count: bundleRow.conflicts_count,
      gaps_count: bundleRow.gaps_count,
      final_bundle_status: bundle.final_bundle_status
    });
    return { provider_chain: [], hits: [], bundle, bundle_path: bundlePath, provider_status: [] };
  }

  if (decision.reason_code === "url_provided" || firecrawlMode === "scrape" || firecrawlMode === "extract") {
    if (!canUseProviderByBudget("firecrawl_fetch")) {
      markDegraded("firecrawl_fetch", "provider_budget_ceiling_reached");
      pushProviderStatus("firecrawl_fetch", "degraded", null, null, "provider_budget_ceiling_reached");
      throw new Error("firecrawl_budget_ceiling_reached");
    }
    if (providerInCooldown("firecrawl")) {
      markDegraded("firecrawl_fetch", "provider_cooldown_active");
      pushProviderStatus("firecrawl_fetch", "degraded", null, null, "provider_cooldown_active");
      throw new Error("firecrawl_cooldown_active");
    }
    const health = evaluateProviderMemoryHealth("firecrawl", forceProviderFail === "firecrawl", "forced_provider_fail");
    if (!health.ready) {
      pushProviderStatus("firecrawl_fetch", "unhealthy", null, null, health.healthRow?.failure_reason || "provider_unhealthy");
      updateProviderHealthGovernance({
        runId,
        provider: "firecrawl",
        healthy: false,
        failureReason: health.healthRow?.failure_reason || "provider_unhealthy"
      });
      markDegraded("firecrawl_fetch", health.healthRow?.failure_reason || "provider_unhealthy");
      throw new Error(`firecrawl_unavailable:${health.healthRow?.failure_reason || "missing_key"}`);
    }
    providerChain.push("firecrawl_fetch");
    markProviderUsed("firecrawl_fetch");
    roundsUsed += 1;
    if (firecrawlMode === "extract" || fetchTargets.length > 1 || Boolean(options.structured_extract)) {
      try {
        const extractResult = await runFirecrawlExtract({
          runId,
          targetUrls: fetchTargets.length ? fetchTargets : [String(options.target_url || "").trim()].filter(Boolean),
          reasonCode: decision.reason_code,
          extractionGoal: options.extraction_goal
        });
        allSources.push(...extractResult.hits);
        rawContextRefs.push(extractResult.raw_context_ref);
        pushProviderStatus("firecrawl_fetch", "healthy", extractResult.latency_ms, extractResult.credits_estimate, null);
        updateProviderHealthGovernance({
          runId,
          provider: "firecrawl",
          healthy: true
        });
      } catch (error) {
        const reason = error instanceof Error ? error.message : String(error);
        pushProviderStatus("firecrawl_fetch", "unhealthy", null, null, reason);
        updateProviderHealthGovernance({
          runId,
          provider: "firecrawl",
          healthy: false,
          failureReason: reason
        });
        markDegraded("firecrawl_fetch", reason);
        throw error;
      }
    } else {
      const targetUrl = fetchTargets[0] || String(options.target_url || "").trim();
      try {
        const scrapeResult = await runFirecrawlScrape({
          runId,
          targetUrl,
          reasonCode: decision.reason_code
        });
        allSources.push(...scrapeResult.hits);
        rawContextRefs.push(scrapeResult.raw_context_ref);
        pushProviderStatus("firecrawl_fetch", "healthy", scrapeResult.latency_ms, scrapeResult.credits_estimate, null);
        updateProviderHealthGovernance({
          runId,
          provider: "firecrawl",
          healthy: true
        });
      } catch (error) {
        const reason = error instanceof Error ? error.message : String(error);
        pushProviderStatus("firecrawl_fetch", "unhealthy", null, null, reason);
        updateProviderHealthGovernance({
          runId,
          provider: "firecrawl",
          healthy: false,
          failureReason: reason
        });
        markDegraded("firecrawl_fetch", reason);
        throw error;
      }
    }
  } else {
    const firstHopOrder = preferredProvider === "exa" ? ["exa", "tavily"] : ["tavily", "exa"];
    let firstHopCompleted = false;
    for (const provider of firstHopOrder) {
      if (firstHopCompleted || roundsUsed >= maxRounds) break;
      if (!canUseProviderByBudget(provider)) {
        markDegraded(provider, "provider_budget_ceiling_reached");
        pushProviderStatus(provider, "degraded", null, null, "provider_budget_ceiling_reached");
        continue;
      }
      if (providerInCooldown(provider)) {
        markDegraded(provider, "provider_cooldown_active");
        pushProviderStatus(provider, "degraded", null, null, "provider_cooldown_active");
        continue;
      }
      const health = evaluateProviderMemoryHealth(provider, forceProviderFail === provider, "forced_provider_fail");
      if (!health.ready) {
        pushProviderStatus(provider, "unhealthy", null, null, health.healthRow?.failure_reason || "provider_unhealthy");
        updateProviderHealthGovernance({
          runId,
          provider,
          healthy: false,
          failureReason: health.healthRow?.failure_reason || "provider_unhealthy"
        });
        markDegraded(provider, health.healthRow?.failure_reason || "provider_unhealthy");
        continue;
      }
      try {
        if (provider === "tavily") {
          providerChain.push("tavily");
          const tavilyResult = await runTavilyMinimalSearch({
            runId,
            query,
            reasonCode: decision.reason_code,
            suppressBundle: true
          });
          allSources.push(...(tavilyResult.hits || []));
          rawContextRefs.push(tavilyResult.raw_context_ref || tavilyResult.bundle_path || null);
          pushProviderStatus("tavily", "healthy", tavilyResult.latency_ms || null, tavilyResult.credits_estimate || 1, null);
          updateProviderHealthGovernance({ runId, provider: "tavily", healthy: true });
          markProviderUsed("tavily");
          roundsUsed += 1;
          firstHopCompleted = true;
          const needExa = !disableSecondHop && roundsUsed < maxRounds && classifySecondHopNeed({
            query,
            tavilyHits: tavilyResult.hits || [],
            forceSecondHop: forceSecondHopExa
          });
          if (needExa) {
            if (!canUseProviderByBudget("exa")) {
              markDegraded("exa", "provider_budget_ceiling_reached");
              pushProviderStatus("exa", "degraded", null, null, "provider_budget_ceiling_reached");
              continue;
            }
            if (providerInCooldown("exa")) {
              markDegraded("exa", "provider_cooldown_active");
              pushProviderStatus("exa", "degraded", null, null, "provider_cooldown_active");
              continue;
            }
            const exaHealth = evaluateProviderMemoryHealth("exa", forceProviderFail === "exa", "forced_provider_fail");
            if (!exaHealth.ready) {
              pushProviderStatus("exa", "unhealthy", null, null, exaHealth.healthRow?.failure_reason || "provider_unhealthy");
              updateProviderHealthGovernance({
                runId,
                provider: "exa",
                healthy: false,
                failureReason: exaHealth.healthRow?.failure_reason || "provider_unhealthy",
                fallbackDecision: "skip_second_hop"
              });
              markDegraded("exa", exaHealth.healthRow?.failure_reason || "provider_unhealthy");
            } else {
              providerChain.push("exa");
              const exaResult = await runExaSecondHopSearch({ runId, query, reasonCode: decision.reason_code });
              allSources.push(...exaResult.hits);
              rawContextRefs.push(exaResult.raw_context_ref);
              pushProviderStatus("exa", "healthy", exaResult.latency_ms, exaResult.credits_estimate, null);
              updateProviderHealthGovernance({ runId, provider: "exa", healthy: true });
              markProviderUsed("exa");
              roundsUsed += 1;
            }
          }
        } else {
          providerChain.push("exa");
          const exaResult = await runExaSecondHopSearch({ runId, query, reasonCode: decision.reason_code });
          allSources.push(...exaResult.hits);
          rawContextRefs.push(exaResult.raw_context_ref);
          pushProviderStatus("exa", "healthy", exaResult.latency_ms, exaResult.credits_estimate, null);
          updateProviderHealthGovernance({ runId, provider: "exa", healthy: true });
          markProviderUsed("exa");
          roundsUsed += 1;
          firstHopCompleted = true;
        }
      } catch (error) {
        const reason = error instanceof Error ? error.message : String(error);
        pushProviderStatus(provider, "unhealthy", null, null, reason);
        updateProviderHealthGovernance({
          runId,
          provider,
          healthy: false,
          failureReason: reason,
          fallbackDecision: "try_next_provider"
        });
        markDegraded(provider, reason);
      }
    }
  }

  if (Boolean(options.inject_conflict_sources)) {
    const dupUrl = "https://nodejs.org/en/download/";
    const dup1 = toSourceHit({
      provider: "synthetic",
      url: dupUrl,
      title: "Node.js downloads",
      snippet: "Latest Node.js LTS is 22.15.1.",
      score: 0.88,
      fetchReason: "search",
      citationLabel: `S${allSources.length + 1}`
    });
    const dup2 = toSourceHit({
      provider: "synthetic",
      url: "https://nodejs.org/en/download",
      title: "Node.js downloads mirror",
      snippet: "Latest Node.js LTS is 22.15.1 stable release.",
      score: 0.8,
      fetchReason: "search",
      citationLabel: `S${allSources.length + 2}`
    });
    const conflictHit = toSourceHit({
      provider: "synthetic",
      url: "https://example.blogspot.com/node-lts",
      title: "Community mirror note",
      snippet: "Latest Node.js LTS is 23.0.0 according to mirror rumor.",
      score: 0.35,
      fetchReason: "search",
      citationLabel: `S${allSources.length + 3}`
    });
    for (const x of [dup1, dup2, conflictHit]) {
      const row = recordRetrievalHitRow({
        runId,
        provider: x.provider,
        url: x.url,
        canonicalUrl: x.canonical_url,
        title: x.title,
        domain: x.domain,
        score: x.score,
        citationLabel: x.citation_label
      });
      x.source_hit_id = row.id;
      allSources.push(x);
    }
  }

  if (allSources.length === 0) {
    throw new Error("retrieval_no_provider_succeeded");
  }

  const gate = applyCitationQualityGate({
    runId,
    reasonCode: decision.reason_code,
    sources: allSources
  });
  const conflictParts = buildConflictAwareBundleParts({
    runId,
    query,
    sources: gate.sources
  });
  const summaryBits = [];
  summaryBits.push(`provider_chain=${providerChain.join(" -> ") || "none"}`);
  summaryBits.push(`eligible_sources=${gate.eligibleCount}/${gate.sources.length}`);
  if (conflictParts.conflicts.length) {
    summaryBits.push(`conflicts=${conflictParts.conflicts.length}`);
  }
  const bundle = {
    decision: {
      search_needed: true,
      reason_code: normalizeRetrievalReason(decision.reason_code)
    },
    query_plan: {
      provider_chain: providerChain,
      query: summarizeText(query || "", 280),
      search_depth: "basic",
      max_results: 5,
      auto_parameters: false,
      fetch_targets: Array.isArray(fetchTargets) ? fetchTargets.map((x) => sanitizeUrlForRetrieval(x)) : []
    },
    sources: uniqueHitsByUrl(gate.sources),
    facts: conflictParts.facts,
    conflicts: conflictParts.conflicts,
    gaps: conflictParts.gaps,
    summary: summaryBits.join("; "),
    raw_context_refs: rawContextRefs.filter(Boolean),
    provider_status: providerStatus,
    final_bundle_status: conflictParts.finalBundleStatus
  };
  const bundlePath = writeRetrievalArtifact(runId, `evidence_bundle_${Date.now()}.json`, `${JSON.stringify(bundle, null, 2)}\n`, 512 * 1024);
  if (conflictParts.conflictRowId) {
    dbRun("UPDATE conflict_resolution_runs SET evidence_path = ? WHERE id = ?", bundlePath, conflictParts.conflictRowId);
  }
  const budgetExceeded = roundsUsed > maxRounds || urlsUsed > maxUrlsPerTask;
  if (budgetExceeded && retrievalBudgetPolicyContract?.degraded_mode_policy?.enter_when_budget_exceeded) {
    markDegraded("budget", "budget_exceeded");
  }
  const budgetStatus = budgetExceeded ? "budget_exceeded" : "within_budget";
  const budgetRow = recordRetrievalBudgetCheckRow({
    runId,
    providerChain,
    roundsUsed,
    urlsUsed,
    budgetStatus,
    degradedMode
  });
  emitEvent(runId, "retrieval.budget.checked", {
    budget_check_id: budgetRow.id,
    rounds_used: roundsUsed,
    urls_used: urlsUsed,
    budget_status: budgetStatus,
    degraded_mode: degradedMode
  });
  const bundleRow = recordRetrievalBundleRow({
    runId,
    provider: providerChain[providerChain.length - 1] || "none",
    providerChain,
    evidenceBundlePath: bundlePath,
    sourcesCount: bundle.sources.length,
    factsCount: bundle.facts.length,
    conflictsCount: bundle.conflicts.length,
    gapsCount: bundle.gaps.length,
    finalBundleStatus: bundle.final_bundle_status
  });
  emitEvent(runId, "retrieval.bundle_ready", {
    provider_chain: providerChain,
    provider_status: providerStatus,
    evidence_bundle_path: bundlePath,
    sources_count: bundleRow.sources_count,
    facts_count: bundleRow.facts_count,
    conflicts_count: bundleRow.conflicts_count,
    gaps_count: bundleRow.gaps_count,
    final_bundle_status: bundle.final_bundle_status,
    citation_eligible_count: gate.eligibleCount,
    citation_rejected_count: gate.rejectedCount
  });
  return {
    provider_chain: providerChain,
    hits: bundle.sources,
    bundle,
    bundle_path: bundlePath,
    provider_status: providerStatus,
    citation_eligible_count: gate.eligibleCount,
    citation_rejected_count: gate.rejectedCount,
    degraded_mode: degradedMode,
    budget_status: budgetStatus
  };
}

function checkRetrievalProviderBasicReadiness(provider) {
  const key = String(process.env[retrievalProviderEnvKey(provider)] || "").trim();
  return Boolean(key);
}

function runRetrievalReadinessCheck(runId) {
  const tavilyReady = checkRetrievalProviderBasicReadiness("tavily");
  const exaReady = checkRetrievalProviderBasicReadiness("exa");
  const firecrawlFetchReady = checkRetrievalProviderBasicReadiness("firecrawl");
  const firecrawlCrawlReady = false;
  const retrievalBrokerReady = tavilyReady && exaReady && firecrawlFetchReady;
  const multiProviderCloseoutReady = retrievalBrokerReady;
  const blockedModules = [];
  if (!tavilyReady) blockedModules.push("tavily_api_key_missing");
  if (!exaReady) blockedModules.push("exa_api_key_missing");
  if (!firecrawlFetchReady) blockedModules.push("firecrawl_api_key_missing");
  const payload = {
    retrieval_broker_ready: retrievalBrokerReady,
    tavily_ready: tavilyReady,
    exa_ready: exaReady,
    firecrawl_fetch_ready: firecrawlFetchReady,
    firecrawl_crawl_ready: firecrawlCrawlReady,
    multi_provider_closeout_ready: multiProviderCloseoutReady,
    blocked_modules: blockedModules
  };
  const disk = writeRetrievalArtifact(runId, `retrieval_readiness_${Date.now()}.json`, `${JSON.stringify(payload, null, 2)}\n`, 65536);
  const row = recordRetrievalReadinessRow({
    runId,
    retrievalBrokerReady,
    tavilyReady,
    exaReady,
    firecrawlFetchReady,
    firecrawlCrawlReady,
    multiProviderCloseoutReady,
    blockedModules,
    evidencePath: disk
  });
  emitEvent(runId, "retrieval.readiness.checked", {
    readiness_id: row.id,
    ...payload,
    evidence_path: disk
  });
  return { row, payload, evidencePath: disk };
}

function runRetrievalGovernanceReadinessCheck(runId) {
  const suiteDecisionRows = dbAll(
    "SELECT run_id FROM retrieval_decisions WHERE status LIKE 'governance_%' ORDER BY created_at DESC LIMIT 200"
  );
  const suiteRunIds = new Set([runId, ...suiteDecisionRows.map((row) => String(row.run_id || "")).filter(Boolean)]);
  const suiteRunIdList = [...suiteRunIds];
  const suitePlaceholders = suiteRunIdList.map(() => "?").join(", ");
  const queryRowsForSuite = (tableName) => {
    if (!suiteRunIdList.length) return [];
    return dbAll(
      `SELECT * FROM ${tableName} WHERE run_id IN (${suitePlaceholders}) ORDER BY created_at ASC`,
      ...suiteRunIdList
    );
  };

  const citationRows = queryRowsForSuite("citation_gate_checks");
  const conflictRows = queryRowsForSuite("conflict_resolution_runs");
  const budgetRows = queryRowsForSuite("retrieval_budget_checks");
  const healthRows = queryRowsForSuite("provider_health_governance");

  const citationQualityGateReady =
    citationRows.length > 0 &&
    citationRows.some((x) => Number(x.citation_eligible) === 1) &&
    citationRows.some((x) => Number(x.citation_eligible) !== 1);

  const canonicalizationReady =
    citationRows.length > 0 &&
    citationRows.every((x) => String(x.canonical_url || "").trim().length > 0) &&
    citationRows.some((x) => String(x.dedup_cluster_id || "").trim().length > 0);

  const conflictResolutionReady = conflictRows.length > 0;
  const budgetGovernanceReady = budgetRows.length > 0;
  const providerHealthGovernanceReady = healthRows.length > 0;

  const blockedModules = [];
  if (!citationQualityGateReady) blockedModules.push("citation_quality_gate_incomplete");
  if (!canonicalizationReady) blockedModules.push("canonicalization_incomplete");
  if (!conflictResolutionReady) blockedModules.push("conflict_resolution_incomplete");
  if (!budgetGovernanceReady) blockedModules.push("retrieval_budget_governance_incomplete");
  if (!providerHealthGovernanceReady) blockedModules.push("provider_health_governance_incomplete");

  const retrievalGovernanceCloseoutReady =
    citationQualityGateReady &&
    canonicalizationReady &&
    conflictResolutionReady &&
    budgetGovernanceReady &&
    providerHealthGovernanceReady;

  const payload = {
    scope_run_ids: suiteRunIdList,
    citation_quality_gate_ready: citationQualityGateReady,
    conflict_resolution_ready: conflictResolutionReady,
    canonicalization_ready: canonicalizationReady,
    budget_governance_ready: budgetGovernanceReady,
    provider_health_governance_ready: providerHealthGovernanceReady,
    retrieval_governance_closeout_ready: retrievalGovernanceCloseoutReady,
    blocked_modules: blockedModules
  };

  const evidencePath = writeRetrievalArtifact(
    runId,
    `retrieval_governance_readiness_${Date.now()}.json`,
    `${JSON.stringify(payload, null, 2)}\n`,
    65536
  );
  const row = recordRetrievalGovernanceReadinessRow({
    runId,
    citationQualityGateReady,
    conflictResolutionReady,
    canonicalizationReady,
    budgetGovernanceReady,
    providerHealthGovernanceReady,
    retrievalGovernanceCloseoutReady,
    blockedModules,
    evidencePath
  });
  emitEvent(runId, "retrieval.governance.readiness.checked", {
    governance_readiness_id: row.id,
    ...payload,
    evidence_path: evidencePath
  });
  return { row, payload, evidencePath };
}

function openAiValidationProbeBody() {
  return {
    model: OPENAI_VALIDATION_MODEL || OPENAI_DEFAULT_MODEL,
    input: "Validate OpenAI BYO key for local lite-codex host.",
    max_output_tokens: 1
  };
}

function classifyOpenAiTransportLayer({ status = 0, errorCode = "", errorType = "", errorMessage = "", baseUrl = OPENAI_BASE_URL }) {
  const code = String(errorCode || "").toLowerCase();
  const type = String(errorType || "").toLowerCase();
  const message = String(errorMessage || "").toLowerCase();
  const all = `${code} ${type} ${message}`;
  const official = String(baseUrl || "").trim().replace(/\/+$/, "").toLowerCase() === OPENAI_BASE_URL.toLowerCase();
  if (!official) {
    return { failure_layer: "wrong_base_url", failure_reason: "wrong_base_url" };
  }
  if (status === 404) {
    return { failure_layer: "wrong_endpoint", failure_reason: "wrong_endpoint" };
  }
  if (/model_not_found|unsupported_model|invalid_model|does not exist|do not have access to model|model .* not found|unknown model/.test(all)) {
    return { failure_layer: "wrong_model", failure_reason: "wrong_model" };
  }
  if (status === 401 || /invalid_api_key|api key invalid|incorrect api key/.test(all)) {
    return { failure_layer: "header_auth_error", failure_reason: "invalid_key" };
  }
  if (status === 403) {
    return { failure_layer: "header_auth_error", failure_reason: "permission_denied" };
  }
  if (status === 429) {
    return { failure_layer: "rate_limited", failure_reason: "rate_limited" };
  }
  if (status >= 500 && status <= 599) {
    return { failure_layer: "gateway_ambiguous", failure_reason: `gateway_http_${status}` };
  }
  if (status === 400 && /endpoint|path/.test(all)) {
    return { failure_layer: "wrong_endpoint", failure_reason: "wrong_endpoint" };
  }
  if (status > 0) {
    return { failure_layer: "unknown_auth_error", failure_reason: `http_${status}` };
  }
  if (/enotfound|getaddrinfo|name resolution/.test(all)) {
    return { failure_layer: "dns_failure", failure_reason: "dns_failure" };
  }
  if (/cert|certificate|ssl|tls/.test(all)) {
    return { failure_layer: "tls_failure", failure_reason: "tls_failure" };
  }
  if (/proxy/.test(all)) {
    return { failure_layer: "proxy_failure", failure_reason: "proxy_failure" };
  }
  if (/timed out|timeout|aborterror|aborted/.test(all)) {
    return { failure_layer: "network_timeout", failure_reason: "request_timeout" };
  }
  if (/econnrefused|econnreset|ehostunreach|network|fetch failed/.test(all)) {
    return { failure_layer: "firewall_or_network_failure", failure_reason: "network_unreachable" };
  }
  return { failure_layer: "network_unreachable", failure_reason: "network_unreachable" };
}

function normalizeProbeClassification({ status = 0, errorCode = "", errorType = "", errorMessage = "" }) {
  const layer = classifyOpenAiTransportLayer({ status, errorCode, errorType, errorMessage, baseUrl: OPENAI_BASE_URL });
  if (status === 401) {
    return {
      validation_status: "invalid_key",
      failure_reason: normalizeByoFailureReason(errorCode || errorType || errorMessage || layer.failure_reason),
      http_status: status,
      failure_layer: layer.failure_layer
    };
  }
  if (status === 403) {
    return {
      validation_status: "permission_denied",
      failure_reason: normalizeByoFailureReason(errorCode || errorType || errorMessage || layer.failure_reason),
      http_status: status,
      failure_layer: layer.failure_layer
    };
  }
  if (status === 429) {
    return {
      validation_status: "rate_limited",
      failure_reason: normalizeByoFailureReason(errorCode || errorType || errorMessage || layer.failure_reason),
      http_status: status,
      failure_layer: layer.failure_layer
    };
  }
  if (layer.failure_layer === "gateway_ambiguous") {
    return {
      validation_status: "gateway_ambiguous",
      failure_reason: normalizeByoFailureReason(errorCode || errorType || errorMessage || layer.failure_reason),
      http_status: status,
      failure_layer: layer.failure_layer
    };
  }
  if (status === 0 && ["dns_failure", "tls_failure", "proxy_failure", "network_timeout", "firewall_or_network_failure", "network_unreachable"].includes(layer.failure_layer)) {
    return {
      validation_status: "network_unreachable",
      failure_reason: normalizeByoFailureReason(errorCode || errorType || errorMessage || layer.failure_reason),
      http_status: 0,
      failure_layer: layer.failure_layer
    };
  }
  return {
    validation_status: "unknown_auth_error",
    failure_reason: normalizeByoFailureReason(errorCode || errorType || errorMessage || layer.failure_reason),
    http_status: status,
    failure_layer: layer.failure_layer
  };
}

function classifyOpenAiProbeResponse(response, bodyText) {
  const parsed = safeParseJson(bodyText);
  const errorObj = parsed?.error && typeof parsed.error === "object" ? parsed.error : null;
  const errorCode = String(errorObj?.code || "");
  const errorType = String(errorObj?.type || "");
  const errorMessage = String(errorObj?.message || "");
  if (response.ok) {
    return {
      validation_status: "valid",
      failure_reason: null,
      http_status: response.status,
      failure_layer: null
    };
  }
  return normalizeProbeClassification({
    status: Number(response.status || 0),
    errorCode,
    errorType,
    errorMessage: errorMessage || bodyText
  });
}

async function probeOpenAiResponsesViaFetch(apiKey, timeoutMs = 12000) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(OPENAI_RESPONSES_URL, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${apiKey}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify(openAiValidationProbeBody()),
      signal: controller.signal
    });
    const bodyText = await response.text();
    return classifyOpenAiProbeResponse(response, bodyText);
  } catch (error) {
    const message = error instanceof Error ? error.message : "network_error";
    return normalizeProbeClassification({
      status: 0,
      errorCode: "",
      errorType: "",
      errorMessage: message
    });
  } finally {
    clearTimeout(timer);
  }
}

function probeOpenAiByoKeyViaPowerShell(apiKey, timeoutMs = 12000) {
  if (process.platform !== "win32") return null;
  const timeoutSec = Math.max(3, Math.ceil(timeoutMs / 1000));
  const requestBody = JSON.stringify(openAiValidationProbeBody());
  const script = [
    "$ErrorActionPreference='Stop'",
    "$headers = @{ Authorization = ('Bearer ' + $env:LITECODEX_OPENAI_VALIDATE_KEY); 'Content-Type' = 'application/json' }",
    "$uri = $env:LITECODEX_OPENAI_VALIDATE_URL",
    "$body = $env:LITECODEX_OPENAI_VALIDATE_BODY",
    "$timeout = [int]$env:LITECODEX_OPENAI_VALIDATE_TIMEOUT",
    "$result = $null",
    "try {",
    "  $resp = Invoke-WebRequest -Uri $uri -Headers $headers -Method Post -Body $body -TimeoutSec $timeout -ErrorAction Stop",
    "  $okBody = ''",
    "  try { $okBody = [string]$resp.Content } catch { $okBody = '' }",
    "  $result = @{ ok = $true; status = [int]$resp.StatusCode; body = [string]$okBody }",
    "} catch {",
    "  $webResp = $null",
    "  try { $webResp = $_.Exception.Response } catch { $webResp = $null }",
    "  if ($null -ne $webResp) {",
    "    $status = 0",
    "    try { $status = [int]$webResp.StatusCode.value__ } catch {",
    "      try { $status = [int]$webResp.StatusCode } catch { $status = 0 }",
    "    }",
    "    $body = ''",
    "    try {",
    "      $stream = $webResp.GetResponseStream()",
    "      if ($null -ne $stream) {",
    "        $reader = New-Object System.IO.StreamReader($stream)",
    "        $body = $reader.ReadToEnd()",
    "        if ($body.Length -gt 4096) { $body = $body.Substring(0, 4096) }",
    "      }",
    "    } catch { $body = '' }",
    "    $result = @{ ok = $false; status = $status; body = [string]$body }",
    "  } else {",
    "    $result = @{ ok = $false; status = 0; error = [string]$_.Exception.Message }",
    "  }",
    "}",
    "$result | ConvertTo-Json -Compress"
  ].join(";");
  const candidates = ["powershell", "pwsh"];
  for (const cmd of candidates) {
    const childEnv = {
      ...process.env,
      LITECODEX_OPENAI_VALIDATE_KEY: apiKey,
      LITECODEX_OPENAI_VALIDATE_URL: OPENAI_RESPONSES_URL,
      LITECODEX_OPENAI_VALIDATE_BODY: requestBody,
      LITECODEX_OPENAI_VALIDATE_TIMEOUT: String(timeoutSec)
    };
    const result = spawnSync(cmd, ["-NoProfile", "-NonInteractive", "-Command", script], {
      encoding: "utf8",
      windowsHide: true,
      timeout: timeoutMs,
      maxBuffer: 512 * 1024,
      env: childEnv
    });
    if (typeof result.stdout === "string" && result.stdout.trim()) {
      const parsed = safeParseJson(result.stdout.trim());
      if (parsed && (typeof parsed.status === "number" || typeof parsed.ok === "boolean")) {
        if (Number(parsed.status) > 0) {
          return classifyOpenAiProbeResponse(
            { ok: Boolean(parsed.ok), status: Number(parsed.status) },
            String(parsed.body || "")
          );
        }
        if (parsed.error) {
          return {
            validation_status: "network_unreachable",
            failure_reason: normalizeByoFailureReason(String(parsed.error)),
            http_status: 0
          };
        }
      }
    }
    if (result.error) {
      if (result.error.name === "ETIMEDOUT") {
        return { validation_status: "network_unreachable", failure_reason: "request_timeout", http_status: 0 };
      }
      continue;
    }
    if (result.status === 0 && (!result.stdout || !String(result.stdout).trim())) {
      continue;
    }
  }
  return null;
}

async function probeOpenAiByoKey(apiKey, timeoutMs = 12000) {
  if (typeof apiKey !== "string" || !apiKey.trim()) {
    return { validation_status: "invalid_key", failure_reason: "api_key_missing", http_status: 0 };
  }
  const key = apiKey.trim();
  if (!key.startsWith("sk-")) {
    return { validation_status: "invalid_key", failure_reason: "api_key_format_invalid", http_status: 0 };
  }

  const fetchProbe = await probeOpenAiResponsesViaFetch(key, timeoutMs);
  if (fetchProbe.validation_status === "valid") {
    return fetchProbe;
  }
  const shouldTryPowerShell =
    fetchProbe.validation_status === "network_unreachable" ||
    fetchProbe.validation_status === "gateway_ambiguous";
  if (shouldTryPowerShell) {
    const psProbe = probeOpenAiByoKeyViaPowerShell(key, timeoutMs);
    if (psProbe && psProbe.validation_status === "valid") {
      return psProbe;
    }
    if (psProbe && psProbe.validation_status !== "network_unreachable") {
      return psProbe;
    }
  }
  return fetchProbe;
}

async function bindOpenAiByo({ runId, profileId, bindingScope, apiKey, validateNow = true, proofReceipt = null }) {
  const now = nowIso();
  const scope = normalizeByoScope(bindingScope);
  const profile = profileId || BYO_DEFAULT_PROFILE_ID;
  const profileHash = browserProfileHash(profile);
  const machineHash = MACHINE_SCOPE_ID_HASH;
  const publicKeyFingerprint = proofReceipt?.public_key_fingerprint || null;

  emitRunEventIfExists(runId, "byo.bind.started", {
    provider: BYO_PROVIDER_OPENAI,
    binding_scope: scope,
    browser_profile_id_hash: profileHash,
    machine_scope_id_hash: machineHash,
    host_memory_only: true,
    challenge_response_required: true,
    challenge_id: proofReceipt?.challenge_id || null
  });

  const bindingId = shortId("byobind");
  const fingerprint = computeKeyFingerprint(BYO_PROVIDER_OPENAI, apiKey);
  dbRun(
    "INSERT INTO byo_key_bindings (id, provider, binding_scope, browser_profile_id_hash, machine_scope_id_hash, public_key_fingerprint, key_fingerprint_hash, status, created_at, deleted_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, NULL)",
    bindingId,
    BYO_PROVIDER_OPENAI,
    scope,
    profileHash,
    machineHash,
    publicKeyFingerprint,
    fingerprint,
    "bound",
    now
  );

  byoBindingSecretMemory.set(bindingId, {
    provider: BYO_PROVIDER_OPENAI,
    apiKey,
    binding_scope: scope,
    browser_profile_id_hash: profileHash,
    machine_scope_id_hash: machineHash,
    bound_at: now
  });
  byoApiKeyMemory = apiKey;

  let validation = {
    validation_status: "unknown_auth_error",
    failure_reason: "validation_skipped",
    last_verified_at: now
  };

  if (validateNow) {
    emitRunEventIfExists(runId, "byo.validation.started", {
      provider: BYO_PROVIDER_OPENAI,
      binding_id: bindingId,
      binding_scope: scope
    });
    const probe = await probeOpenAiByoKey(apiKey, parsePositiveInt(byoKeyValidationContract?.timeout_ms, 12000));
    const status = allowedByoValidationStatus(probe.validation_status);
    const reason = normalizeByoFailureReason(probe.failure_reason);
    const verifiedAt = nowIso();
    validation = {
      validation_status: status,
      failure_reason: reason,
      last_verified_at: verifiedAt
    };
    recordByoValidationRow({
      provider: BYO_PROVIDER_OPENAI,
      bindingId,
      validationStatus: status,
      failureReason: reason,
      ts: verifiedAt
    });
    recordCredentialHealthRow({
      provider: BYO_PROVIDER_OPENAI,
      source: "byo_binding",
      sourceScope: scope,
      grantState: status === "valid" ? "granted" : "degraded",
      healthStatus: status === "valid" ? "healthy" : "unhealthy",
      failureReason: reason,
      lastVerifiedAt: verifiedAt
    });
    upsertByoBindingStatus(bindingId, status === "valid" ? "valid" : "invalid", null);
    if (status !== "valid") {
      byoBindingSecretMemory.delete(bindingId);
      if (byoApiKeyMemory === apiKey) {
        byoApiKeyMemory = null;
      }
    }
    emitRunEventIfExists(runId, "byo.validation.completed", {
      provider: BYO_PROVIDER_OPENAI,
      binding_id: bindingId,
      validation_status: status,
      failure_reason: reason,
      last_verified_at: verifiedAt,
      challenge_response_verified: Boolean(proofReceipt?.ok),
      challenge_id: proofReceipt?.challenge_id || null
    });
  }

  const bindingRow = dbGet("SELECT * FROM byo_key_bindings WHERE id = ?", bindingId);
  emitRunEventIfExists(runId, "byo.bind.completed", {
    provider: BYO_PROVIDER_OPENAI,
    binding_id: bindingId,
    binding_scope: bindingRow.binding_scope,
    browser_profile_id_hash: bindingRow.browser_profile_id_hash,
    machine_scope_id_hash: bindingRow.machine_scope_id_hash,
    public_key_fingerprint: bindingRow.public_key_fingerprint || null,
    host_memory_only: true,
    browser_local_persistence: true,
    challenge_response_verified: Boolean(proofReceipt?.ok),
    challenge_id: proofReceipt?.challenge_id || null,
    status: bindingRow.status
  });

  return {
    binding: bindingRow,
    validation
  };
}

async function validateOpenAiBinding({ runId, bindingRow, profileHash, apiKeyOverride = null, proofReceipt = null }) {
  const now = nowIso();
  emitRunEventIfExists(runId, "byo.validation.started", {
    provider: BYO_PROVIDER_OPENAI,
    binding_id: bindingRow.id,
    binding_scope: bindingRow.binding_scope,
    challenge_id: proofReceipt?.challenge_id || null
  });

  const memorySecret = byoBindingSecretMemory.get(bindingRow.id);
  const apiKey =
    typeof apiKeyOverride === "string" && apiKeyOverride.trim()
      ? apiKeyOverride.trim()
      : memorySecret?.apiKey || null;

  let probe;
  if (!apiKey) {
    probe = { validation_status: "unknown_auth_error", failure_reason: "key_not_in_memory", http_status: 0 };
  } else {
    probe = await probeOpenAiByoKey(apiKey, parsePositiveInt(byoKeyValidationContract?.timeout_ms, 12000));
  }

  const status = allowedByoValidationStatus(probe.validation_status);
  const reason = normalizeByoFailureReason(probe.failure_reason);
  const verifiedAt = nowIso();

  recordByoValidationRow({
    provider: BYO_PROVIDER_OPENAI,
    bindingId: bindingRow.id,
    validationStatus: status,
    failureReason: reason,
    ts: verifiedAt
  });
  recordCredentialHealthRow({
    provider: BYO_PROVIDER_OPENAI,
    source: "byo_binding",
    sourceScope: bindingRow.binding_scope,
    grantState: status === "valid" ? "granted" : "degraded",
    healthStatus: status === "valid" ? "healthy" : "unhealthy",
    failureReason: reason,
    lastVerifiedAt: verifiedAt
  });
  upsertByoBindingStatus(bindingRow.id, status === "valid" ? "valid" : "invalid", bindingRow.deleted_at || null);
  if (status !== "valid") {
    byoBindingSecretMemory.delete(bindingRow.id);
    if (byoApiKeyMemory && memorySecret?.apiKey && byoApiKeyMemory === memorySecret.apiKey) {
      byoApiKeyMemory = null;
    }
  }

  emitRunEventIfExists(runId, "byo.validation.completed", {
    provider: BYO_PROVIDER_OPENAI,
    binding_id: bindingRow.id,
    binding_scope: bindingRow.binding_scope,
    browser_profile_id_hash: profileHash,
    validation_status: status,
    failure_reason: reason,
    last_verified_at: verifiedAt,
    challenge_response_verified: Boolean(proofReceipt?.ok),
    challenge_id: proofReceipt?.challenge_id || null
  });

  return {
    validation_status: status,
    failure_reason: reason,
    last_verified_at: verifiedAt
  };
}

function unbindOpenAiBinding({ runId, bindingRow }) {
  upsertByoBindingStatus(bindingRow.id, "unbound", bindingRow.deleted_at || null);
  byoBindingSecretMemory.delete(bindingRow.id);
  if (byoApiKeyMemory) {
    byoApiKeyMemory = null;
  }
  const row = dbGet("SELECT * FROM byo_key_bindings WHERE id = ?", bindingRow.id);
  emitRunEventIfExists(runId, "byo.unbound", {
    provider: BYO_PROVIDER_OPENAI,
    binding_id: row.id,
    binding_scope: row.binding_scope,
    browser_profile_id_hash: row.browser_profile_id_hash,
    status: row.status
  });
  return row;
}

function deleteOpenAiBinding({ runId, bindingRow }) {
  const deletedAt = nowIso();
  upsertByoBindingStatus(bindingRow.id, "deleted", deletedAt);
  byoBindingSecretMemory.delete(bindingRow.id);
  if (byoApiKeyMemory) {
    byoApiKeyMemory = null;
  }
  const row = dbGet("SELECT * FROM byo_key_bindings WHERE id = ?", bindingRow.id);
  emitRunEventIfExists(runId, "byo.deleted", {
    provider: BYO_PROVIDER_OPENAI,
    binding_id: row.id,
    binding_scope: row.binding_scope,
    browser_profile_id_hash: row.browser_profile_id_hash,
    status: row.status,
    deleted_at: row.deleted_at
  });
  return row;
}

function buildByoStatusForProfile(profileId) {
  const profileHash = browserProfileHash(profileId);
  let binding = dbGet(
    "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = 'browser_profile_scope' AND browser_profile_id_hash = ? AND status IN ('bound','valid','invalid') ORDER BY created_at DESC LIMIT 1",
    BYO_PROVIDER_OPENAI,
    profileHash
  );
  if (!binding) {
    binding = dbGet(
      "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = 'session_scope' AND status IN ('bound','valid','invalid') ORDER BY created_at DESC LIMIT 1",
      BYO_PROVIDER_OPENAI
    );
  }
  if (!binding) {
    binding = dbGet(
      "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = 'machine_scope' AND status IN ('bound','valid','invalid') ORDER BY created_at DESC LIMIT 1",
      BYO_PROVIDER_OPENAI
    );
  }
  if (!binding) {
    binding = dbGet(
    "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = 'browser_profile_scope' AND browser_profile_id_hash = ? AND status <> 'deleted' ORDER BY created_at DESC LIMIT 1",
    BYO_PROVIDER_OPENAI,
    profileHash
  );
    if (!binding) {
      binding = dbGet(
        "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = 'session_scope' AND status <> 'deleted' ORDER BY created_at DESC LIMIT 1",
        BYO_PROVIDER_OPENAI
      );
    }
    if (!binding) {
      binding = dbGet(
        "SELECT * FROM byo_key_bindings WHERE provider = ? AND binding_scope = 'machine_scope' AND status <> 'deleted' ORDER BY created_at DESC LIMIT 1",
        BYO_PROVIDER_OPENAI
      );
    }
  }
  if (!binding) {
    return {
      provider: BYO_PROVIDER_OPENAI,
      binding: null,
      validation: null,
      host_memory_only: true,
      browser_local_persistence: true,
      cross_browser_share: false
    };
  }
  const validation = dbGet(
    "SELECT * FROM byo_key_validations WHERE binding_id = ? ORDER BY created_at DESC LIMIT 1",
    binding.id
  );
  const memoryBound = byoBindingSecretMemory.has(binding.id);
  return {
    provider: BYO_PROVIDER_OPENAI,
    binding: {
      id: binding.id,
      binding_scope: binding.binding_scope,
      browser_profile_id_hash: binding.browser_profile_id_hash,
      machine_scope_id_hash: binding.machine_scope_id_hash,
      public_key_fingerprint: binding.public_key_fingerprint || null,
      status: binding.status,
      created_at: binding.created_at,
      deleted_at: binding.deleted_at,
      host_memory_only: true,
      browser_local_persistence: true,
      memory_bound: memoryBound
    },
    validation: validation
      ? {
          validation_status: validation.validation_status,
          failure_reason: validation.failure_reason,
          last_verified_at: validation.last_verified_at
        }
      : null,
    host_memory_only: true,
    browser_local_persistence: true,
    cross_browser_share: false
  };
}

function retrievalDesignFreezePayload(runId) {
  const enabled = Array.isArray(retrievalBrokerContract?.enabled_providers)
    ? retrievalBrokerContract.enabled_providers
    : Array.isArray(retrievalBrokerContract?.provider_routing?.enabled_providers)
      ? retrievalBrokerContract.provider_routing.enabled_providers
      : ["tavily", "exa", "firecrawl_fetch"];
  const disabled = Array.isArray(retrievalBrokerContract?.disabled_providers)
    ? retrievalBrokerContract.disabled_providers
    : Array.isArray(retrievalBrokerContract?.provider_routing?.disabled_providers)
      ? retrievalBrokerContract.provider_routing.disabled_providers
      : ["firecrawl_search", "firecrawl_crawl"];
  return {
    provider_contracts: [
      ...enabled.map((provider) => ({
        provider,
        status: "enabled_minimal",
        credential_model_ref: byoKeyBindingContract.version
      })),
      ...disabled.map((provider) => ({
        provider,
        status: "design_frozen_disabled",
        credential_model_ref: byoKeyBindingContract.version
      }))
    ],
    search_needed_decision: retrievalBrokerContract.search_needed_decision,
    reason_codes: retrievalBrokerContract.reason_codes,
    provider_routing: retrievalBrokerContract.provider_routing,
    evidence_bundle_contract: retrievalBrokerContract.evidence_bundle_contract,
    credential_model: retrievalBrokerContract.credential_model,
    replay_and_ledger_policy: retrievalBrokerContract.replay_and_ledger_policy,
    source_hit_contract: sourceHitContract.version,
    evidence_bundle_schema: evidenceBundleContract.version,
    frozen_at: nowIso(),
    run_id: runId
  };
}

function maskAccountId(input) {
  if (typeof input !== "string") {
    return input;
  }
  const s = input.trim();
  if (s.length < 12) {
    return s;
  }
  return `${s.slice(0, 6)}***${s.slice(-4)}`;
}

function maskProjectRef(input) {
  if (typeof input !== "string") {
    return input;
  }
  const s = input.trim();
  if (s.length < 12) {
    return s;
  }
  return `${s.slice(0, 6)}***${s.slice(-4)}`;
}

function redactSandboxId(input) {
  if (typeof input !== "string") {
    return "";
  }
  const s = input.trim();
  if (!s) {
    return "";
  }
  if (s.length <= 10) {
    return `${s.slice(0, 2)}***${s.slice(-2)}`;
  }
  return `${s.slice(0, 4)}***${s.slice(-4)}`;
}

function redactSensitiveText(input) {
  if (typeof input !== "string" || !input) {
    return "";
  }

  const maskedEmail = input.replace(
    /\b([A-Za-z0-9])([A-Za-z0-9._%+-]*)@([A-Za-z0-9.-]+\.[A-Za-z]{2,})\b/g,
    (_, first, _rest, domain) => `${first.toLowerCase()}***@${domain.toLowerCase()}`
  );

  return maskedEmail
    .replace(/\bsk-[A-Za-z0-9_-]{12,}\b/g, "[REDACTED]")
    .replace(/\b(fc|exa|tvly|vercel|cf|supabase|e2b)_[A-Za-z0-9_-]{16,}\b/gi, "[REDACTED]")
    .replace(/(Authorization:\s*Bearer\s+)[^\s]+/gi, "$1[REDACTED]")
    .replace(/(api[_-]?key\s*[:=]\s*)[^\s"'`]+/gi, "$1[REDACTED]")
    .replace(/\b([a-fA-F0-9]{32})\b/g, (_, id) => maskAccountId(id))
    .replace(/(token=)[^&\s]+/gi, "$1[REDACTED]")
    .replace(/(otp=)[^&\s]+/gi, "$1[REDACTED]")
    .replace(/(code=)[^&\s]+/gi, "$1[REDACTED]")
    .replace(/(cookie[:=]\s*)[^\s;]+/gi, "$1[REDACTED]");
}

function sanitizeExternalTargetUrl(input) {
  const raw = String(input || "").trim();
  if (!raw) {
    return "";
  }
  try {
    const parsed = new URL(raw);
    parsed.hash = "";
    for (const key of Array.from(parsed.searchParams.keys())) {
      if (/(token|otp|code|session|auth|key|secret|sig|signature|jwt)/i.test(key)) {
        parsed.searchParams.set(key, "[REDACTED]");
      }
    }
    const search = parsed.searchParams.toString();
    return search ? `${parsed.origin}${parsed.pathname}?${search}` : `${parsed.origin}${parsed.pathname}`;
  } catch {
    return summarizeText(redactSensitiveText(raw), 1024);
  }
}

function domainRuleMatch(hostname, rule) {
  const host = String(hostname || "").trim().toLowerCase();
  const rawRule = String(rule || "").trim().toLowerCase();
  if (!host || !rawRule) {
    return false;
  }
  if (rawRule.startsWith("*.")) {
    const suffix = rawRule.slice(2);
    return host === suffix || host.endsWith(`.${suffix}`);
  }
  return host === rawRule;
}

function pathRuleMatch(pathname, rule) {
  const p = String(pathname || "").trim();
  const rawRule = String(rule || "").trim();
  if (!p || !rawRule) {
    return false;
  }
  if (rawRule.includes("*")) {
    const regex = new RegExp(`^${rawRule.split("*").map(escapeRegExp).join(".*")}$`, "i");
    return regex.test(p);
  }
  if (p === rawRule) {
    return true;
  }
  if (rawRule === "/") {
    return true;
  }
  return p.startsWith(rawRule.endsWith("/") ? rawRule : `${rawRule}/`);
}

function escapeRegExp(s) {
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function redactWithSecrets(input, secretValues = []) {
  let text = typeof input === "string" ? input : "";
  for (const secret of secretValues) {
    if (typeof secret !== "string") {
      continue;
    }
    const trimmed = secret.trim();
    if (!trimmed) {
      continue;
    }
    text = text.replace(new RegExp(escapeRegExp(trimmed), "g"), "[REDACTED]");
  }
  return text;
}

function hashSecretToken(token) {
  return crypto.createHash("sha256").update(String(token || "")).digest("hex").slice(0, 16);
}

function resolveSupabaseExecutable() {
  const resolved = discoverTool("supabase_cli");
  return resolved.found ? resolved.executable : "supabase";
}

const commandEnvAllowlist = new Set([
  "PATH",
  "Path",
  "PATHEXT",
  "SystemRoot",
  "ComSpec",
  "TEMP",
  "TMP",
  "USERPROFILE",
  "HOMEDRIVE",
  "HOMEPATH",
  "USERNAME",
  "APPDATA",
  "LOCALAPPDATA",
  "ProgramData",
  "NUMBER_OF_PROCESSORS",
  "PROCESSOR_ARCHITECTURE",
  "PROCESSOR_IDENTIFIER",
  "TERM",
  "HOME",
  "SHELL",
  "LANG",
  "LC_ALL",
  "LC_CTYPE"
]);

const commandExtraEnvAllowlist = new Set([
  "ANDROID_HOME",
  "ANDROID_SDK_ROOT",
  "JAVA_HOME",
  "KOTLIN_HOME",
  "RUSTUP_HOME",
  "CARGO_HOME",
  "GOPATH",
  "GOBIN",
  "FLUTTER_ROOT",
  "PUB_CACHE",
  "VERCEL_TOKEN",
  "SUPABASE_ACCESS_TOKEN",
  "SUPABASE_DB_PASSWORD",
  "WRANGLER_API_TOKEN",
  "NO_COLOR",
  "FORCE_COLOR",
  "CI"
]);

function buildCommandEnvReport(extraEnv = null, allowedExtraKeys = null) {
  const env = {};
  for (const [k, v] of Object.entries(process.env || {})) {
    if (commandEnvAllowlist.has(k) && typeof v === "string") {
      env[k] = v;
    }
  }
  const forwardedKeys = [];
  const blockedKeys = [];
  const explicitAllow = new Set(
    Array.isArray(allowedExtraKeys) ? allowedExtraKeys.map((x) => String(x || "").trim()).filter(Boolean) : []
  );
  if (extraEnv && typeof extraEnv === "object") {
    for (const [k, v] of Object.entries(extraEnv)) {
      const key = String(k || "").trim();
      if (!key) {
        continue;
      }
      const allowed = commandEnvAllowlist.has(key) || commandExtraEnvAllowlist.has(key) || explicitAllow.has(key);
      if (!allowed) {
        blockedKeys.push(key);
        continue;
      }
      if (v === null || v === undefined || v === "") {
        delete env[key];
      } else {
        env[key] = String(v);
        forwardedKeys.push(key);
      }
    }
  }
  return {
    env,
    forwarded_keys: Array.from(new Set(forwardedKeys)).sort(),
    blocked_keys: Array.from(new Set(blockedKeys)).sort()
  };
}

function buildCommandEnv(extraEnv = null, allowedExtraKeys = null) {
  return buildCommandEnvReport(extraEnv, allowedExtraKeys).env;
}

function runLocalCommand(command, args, timeoutMs = 12000, options = {}) {
  const envReport =
    options?.env && typeof options.env === "object"
      ? buildCommandEnvReport(options.env, options.allowed_env_keys)
      : buildCommandEnvReport(null, null);
  const env = envReport.env;
  const secretValues = Array.isArray(options?.secret_values) ? options.secret_values : [];
  const requestedCwd = typeof options?.cwd === "string" && options.cwd.trim() ? options.cwd.trim() : repoRoot;
  let cwd = requestedCwd;
  let workspaceRoot = typeof options?.workspace_root === "string" && options.workspace_root.trim()
    ? path.resolve(options.workspace_root)
    : typeof options?.workspaceRoot === "string" && options.workspaceRoot.trim()
      ? path.resolve(options.workspaceRoot)
      : null;
  if (!workspaceRoot) {
    const cwdProbe = path.isAbsolute(cwd) ? path.resolve(cwd) : path.resolve(repoRoot, cwd);
    workspaceRoot = inferWorkspaceRootForPath(cwdProbe);
  }
  if (workspaceRoot) {
    const guard = createBoundaryGuard({
      workspaceRoot,
      forbiddenSubpaths: workspaceRootBindingContract?.forbidden_subpaths || [],
      onCheck: (guardResult) => {
        const targetPath =
          typeof guardResult?.target === "string" && guardResult.target
            ? guardResult.target
            : path.isAbsolute(cwd)
              ? path.resolve(cwd)
              : path.resolve(workspaceRoot, cwd);
        recordBoundaryCheck({
          workspaceRootPath: workspaceRoot,
          targetPath,
          checkType: "cwd",
          runId: options.run_id || null,
          stepId: options.step_id || null,
          caseId: options.case_id || null,
          evaluatedResult: guardResult || null
        });
      }
    });
    cwd = guard.guardedCwd(cwd, {
      run_id: options.run_id || null,
      step_id: options.step_id || null,
      case_id: options.case_id || null
    });
  } else {
    cwd = path.resolve(cwd);
  }
  const shellMode = typeof options?.shell === "boolean" ? options.shell : process.platform === "win32";
  const result = spawnSync(command, args, {
    cwd,
    env,
    encoding: "utf8",
    windowsHide: true,
    shell: shellMode,
    timeout: parsePositiveInt(timeoutMs, 12000)
  });

  const stdout = redactWithSecrets(redactSensitiveText(result.stdout || ""), secretValues);
  const stderr = redactWithSecrets(redactSensitiveText(result.stderr || ""), secretValues);
  return {
    ok: result.status === 0,
    status: result.status,
    signal: result.signal || null,
    cwd,
    stdout,
    stderr,
    error_message: result.error
      ? redactWithSecrets(redactSensitiveText(String(result.error.message || result.error)), secretValues)
      : null,
    env_forwarded_keys: envReport.forwarded_keys,
    env_blocked_keys: envReport.blocked_keys
  };
}

const runtimeSandboxAllowedCommands = new Set(["node", "python", "powershell", "pwsh", "cmd", "npm", "npx"]);
const runtimeDestructivePattern =
  /\b(rm\s+-rf|del\s+\/f|format\s+[a-z]:|shutdown|reboot|mkfs|dd\s+if=|git\s+reset\s+--hard|git\s+clean\s+-fd)\b/i;

function evaluateRuntimePolicyDecision(input = {}) {
  const commandText = String(input.command_text || "").trim();
  const actionClass = String(input.action_class || "command").trim().toLowerCase();
  const approvalGranted = input.approval_granted === true;
  const verificationPassed = input.verification_passed === true;
  const requireVerification = input.require_verification === true;
  const requireApproval = input.require_approval === true;
  const deployPolicy = commandText ? evaluateDeployPolicyAction(commandText) : null;
  const containsDestructivePattern = runtimeDestructivePattern.test(commandText);
  const deployRejected = deployPolicy?.policy_action === "reject";
  const highRisk = containsDestructivePattern || deployRejected || actionClass === "destructive" || actionClass === "deploy";
  if ((requireApproval || highRisk) && !approvalGranted) {
    return {
      policy_action: "blocked",
      reason: "approval_required",
      high_risk: true,
      deploy_policy_status: deployPolicy?.policy_action || null
    };
  }
  if ((actionClass === "deploy" || requireVerification || deployRejected) && !verificationPassed) {
    return {
      policy_action: "blocked",
      reason: "verification_required",
      high_risk: Boolean(highRisk),
      deploy_policy_status: deployPolicy?.policy_action || null
    };
  }
  if (deployRejected && !approvalGranted) {
    return {
      policy_action: "blocked",
      reason: "destructive_or_deploy_rejected",
      high_risk: true,
      deploy_policy_status: deployPolicy.policy_action
    };
  }
  return {
    policy_action: "allow",
    reason: "policy_passed",
    high_risk: Boolean(highRisk),
    deploy_policy_status: deployPolicy?.policy_action || null
  };
}

const discoveredToolCache = new Map();

function toolProbe(command, args = ["--version"]) {
  return runLocalCommand(command, Array.isArray(args) ? args : ["--version"], 10000);
}

function normalizeExecutableCandidate(raw) {
  const value = String(raw || "").trim();
  if (!value) {
    return "";
  }
  const pathLike = value.includes("/") || value.includes("\\");
  if (!pathLike) {
    return value;
  }
  if (path.isAbsolute(value)) {
    return path.normalize(value);
  }
  return path.resolve(repoRoot, value);
}

function discoverTool(toolId) {
  if (discoveredToolCache.has(toolId)) {
    return discoveredToolCache.get(toolId);
  }

  const spec = toolRegistryById.get(toolId) || {};
  const probeArgs = Array.isArray(spec.probe_args) && spec.probe_args.length > 0 ? spec.probe_args : ["--version"];
  const candidates = [];

  if (typeof spec.env_var === "string" && spec.env_var.trim()) {
    const envHit = process.env[spec.env_var.trim()];
    if (typeof envHit === "string" && envHit.trim()) {
      candidates.push({ executable: normalizeExecutableCandidate(envHit.trim()), source: "env_var" });
    }
  }

  for (const fixed of Array.isArray(spec.path_candidates) ? spec.path_candidates : []) {
    if (typeof fixed === "string" && fixed.trim()) {
      candidates.push({ executable: normalizeExecutableCandidate(fixed.trim()), source: "registry_path" });
    }
  }

  if (typeof spec.path_lookup === "string" && spec.path_lookup.trim()) {
    candidates.push({ executable: spec.path_lookup.trim(), source: "path_lookup" });
  }

  if (candidates.length === 0 && typeof toolId === "string" && toolId.trim()) {
    candidates.push({ executable: toolId.trim(), source: "tool_id_fallback" });
  }

  for (const item of candidates) {
    const probe = toolProbe(item.executable, probeArgs);
    if (probe.ok) {
      const hit = { found: true, tool_id: toolId, executable: item.executable, source: item.source, probe };
      discoveredToolCache.set(toolId, hit);
      return hit;
    }
  }

  const miss = {
    found: false,
    tool_id: toolId,
    executable: candidates[0]?.executable || toolId,
    source: candidates[0]?.source || "not_found",
    probe: null
  };
  discoveredToolCache.set(toolId, miss);
  return miss;
}

function invalidateToolDiscovery(toolId) {
  discoveredToolCache.delete(toolId);
}

const supabaseExecutable = resolveSupabaseExecutable();

function buildWranglerCommandEnv() {
  const env = buildCommandEnv(null);
  delete env.CLOUDFLARE_API_TOKEN;
  return env;
}

function runWranglerCommand(args, timeoutMs = 12000) {
  return runLocalCommand(wranglerExecutable, args, timeoutMs, { env: buildWranglerCommandEnv() });
}

function buildSupabaseCommandEnv(token) {
  const env = buildCommandEnv(null);
  delete env.SUPABASE_ACCESS_TOKEN;
  if (typeof token === "string" && token.trim()) {
    env.SUPABASE_ACCESS_TOKEN = token.trim();
  }
  return env;
}

function runSupabaseCommand(args, token = null, timeoutMs = 15000) {
  const secretValues = [];
  if (typeof token === "string" && token.trim()) {
    secretValues.push(token.trim());
  }
  return runLocalCommand(supabaseExecutable, args, timeoutMs, {
    env: buildSupabaseCommandEnv(token),
    secret_values: secretValues
  });
}

function resolveWranglerLoginCommand() {
  const help = runWranglerCommand(["login", "--help"], 12000);
  const supportsScopes = help.ok && /--scopes\b/i.test(`${help.stdout}\n${help.stderr}`);
  return {
    command: supportsScopes ? "wrangler login --scopes account:read user:read" : "wrangler login",
    scopes_supported: supportsScopes,
    fallback_reason: supportsScopes ? null : "wrangler_login_scopes_not_supported_or_unavailable"
  };
}

function resolveProjectLinkInspectCapability() {
  const projectFile = path.join(repoRoot, ".vercel", "project.json");
  if (!fs.existsSync(projectFile)) {
    return null;
  }
  try {
    const raw = fs.readFileSync(projectFile, "utf8");
    JSON.parse(raw);
    return "vercel.project.link.inspect";
  } catch {
    return null;
  }
}

function runVercelVerifierProbe() {
  const whoami = runLocalCommand(vercelExecutable, ["whoami"], 12000);
  if (!whoami.ok) {
    return {
      ok: false,
      retryable: true,
      error_code: "vercel_not_logged_in",
      verified_capabilities: []
    };
  }

  const accountRaw = whoami.stdout
    .split(/\r?\n/)
    .map((x) => x.trim())
    .filter(Boolean)
    .pop() || "unknown";
  const accountHint = redactSensitiveText(accountRaw);

  const verified = ["vercel.account.authenticated"];

  let scopeHint = "workspace";
  const teamsLs = runLocalCommand(vercelExecutable, ["teams", "ls"], 15000);
  if (teamsLs.ok) {
    verified.push("vercel.scope.inspect");
    const teamLine =
      teamsLs.stdout
        .split(/\r?\n/)
        .map((x) => x.trim())
        .find((x) => x && !/^\d+$/.test(x)) || "scope-list-ok";
    scopeHint = redactSensitiveText(teamLine);
  }

  const projectsLs =
    runLocalCommand(vercelExecutable, ["projects", "ls"], 15000).ok ||
    runLocalCommand(vercelExecutable, ["project", "ls"], 15000).ok;
  if (projectsLs) {
    verified.push("vercel.project.read");
  }

  const linkInspect = resolveProjectLinkInspectCapability();
  if (linkInspect) {
    verified.push(linkInspect);
  }

  return {
    ok: true,
    retryable: false,
    error_code: null,
    verified_capabilities: Array.from(new Set(verified)),
    platform: "vercel",
    platform_auth_type: "cli_login",
    platform_account_hint: accountHint,
    platform_scope_hint: scopeHint
  };
}

function safeParseJson(text) {
  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
}

function normalizeCloudflareAccountHint(whoamiJson) {
  const first = Array.isArray(whoamiJson?.accounts) ? whoamiJson.accounts[0] : null;
  if (!first) {
    return "no-account";
  }
  const name = redactSensitiveText(String(first.name || "unknown-account"));
  const id = maskAccountId(String(first.id || "unknown"));
  return `${name} (${id})`;
}

function normalizeSupabaseProjectRows(rawRows) {
  const rows = Array.isArray(rawRows) ? rawRows : [];
  return rows.map((row) => ({
    ref: maskProjectRef(String(row?.ref || row?.id || "unknown")),
    name: redactSensitiveText(String(row?.name || "unknown-project")),
    org: maskProjectRef(String(row?.organization_id || row?.organization_slug || "unknown-org")),
    region: redactSensitiveText(String(row?.region || "unknown-region")),
    linked: Boolean(row?.linked)
  }));
}

function runWranglerVerifierProbe() {
  const whoamiJsonCall = runWranglerCommand(["whoami", "--json"], 15000);
  if (!whoamiJsonCall.ok) {
    return {
      ok: false,
      retryable: true,
      error_code: "wrangler_not_logged_in",
      verified_capabilities: []
    };
  }

  const whoamiJson = safeParseJson(whoamiJsonCall.stdout);
  if (!whoamiJson || whoamiJson.loggedIn !== true) {
    return {
      ok: false,
      retryable: true,
      error_code: "wrangler_whoami_json_invalid_or_not_logged_in",
      verified_capabilities: []
    };
  }

  const authTypeRaw = String(whoamiJson.authType || "unknown");
  const authType = redactSensitiveText(authTypeRaw);
  const verified = new Set(["cloudflare.account.authenticated"]);

  if (/oauth/i.test(authTypeRaw)) {
    verified.add("wrangler.oauth.authenticated");
  }

  if (typeof whoamiJson.email === "string" && whoamiJson.email.trim()) {
    verified.add("cloudflare.user.read");
  }

  if (Array.isArray(whoamiJson.accounts) && whoamiJson.accounts.length > 0) {
    verified.add("cloudflare.account.read");
    verified.add("cloudflare.account.membership.read");
  }

  const permissions = Array.isArray(whoamiJson.tokenPermissions) ? whoamiJson.tokenPermissions : [];
  if (permissions.includes("user:read")) {
    verified.add("cloudflare.user.read");
  }
  if (permissions.includes("account:read")) {
    verified.add("cloudflare.account.read");
  }

  const versionCall = runWranglerCommand(["--version"], 10000);
  const version = versionCall.ok
    ? redactSensitiveText(`${versionCall.stdout}\n${versionCall.stderr}`.trim().split(/\r?\n/).find(Boolean) || "unknown")
    : "unknown";

  return {
    ok: true,
    retryable: false,
    error_code: null,
    verified_capabilities: Array.from(verified),
    platform: "cloudflare_wrangler",
    platform_auth_type: authType,
    platform_account_hint: normalizeCloudflareAccountHint(whoamiJson),
    platform_scope_hint: redactSensitiveText(
      (permissions.filter((x) => /read/i.test(String(x))).slice(0, 4) || []).join(", ") || "scopes-unavailable"
    ),
    platform_user_hint: redactSensitiveText(String(whoamiJson.email || "unknown-user")),
    wrangler_version: version
  };
}

function runSupabaseVerifierProbe(token) {
  const tokenValue = typeof token === "string" ? token.trim() : "";
  if (!tokenValue) {
    return {
      ok: false,
      retryable: true,
      error_code: "supabase_token_required",
      verified_capabilities: []
    };
  }

  const version = runSupabaseCommand(["--version"], null, 10000);
  if (!version.ok) {
    return {
      ok: false,
      retryable: false,
      error_code: "supabase_cli_unavailable",
      verified_capabilities: []
    };
  }

  const projectsJson = runSupabaseCommand(["projects", "list", "--output", "json"], tokenValue, 30000);
  if (!projectsJson.ok) {
    const projectsPlain = runSupabaseCommand(["projects", "list"], tokenValue, 30000);
    if (!projectsPlain.ok) {
      return {
        ok: false,
        retryable: true,
        error_code: "supabase_projects_list_failed",
        verified_capabilities: []
      };
    }
    const lineCount = projectsPlain.stdout
      .split(/\r?\n/)
      .map((x) => x.trim())
      .filter(Boolean).length;
    const verifiedFallback = ["supabase.account.authenticated", "supabase.project.read"];
    return {
      ok: true,
      retryable: false,
      error_code: null,
      verified_capabilities: verifiedFallback,
      platform: "supabase",
      platform_auth_type: "token_input_env",
      platform_account_hint: `projects_table_rows:${Math.max(0, lineCount - 2)}`,
      platform_scope_hint: "projects:list(table)",
      platform_verification_command: "supabase projects list"
    };
  }

  const parsed = safeParseJson(projectsJson.stdout);
  if (!Array.isArray(parsed)) {
    return {
      ok: false,
      retryable: true,
      error_code: "supabase_projects_json_invalid",
      verified_capabilities: []
    };
  }

  const sanitizedRows = normalizeSupabaseProjectRows(parsed);
  const hasOrgInfo = parsed.some((x) => Boolean(String(x?.organization_id || x?.organization_slug || "").trim()));
  const verified = new Set(["supabase.account.authenticated", "supabase.project.read"]);
  if (hasOrgInfo) {
    verified.add("supabase.org.read");
  }

  const firstProject = sanitizedRows[0] || null;
  return {
    ok: true,
    retryable: false,
    error_code: null,
    verified_capabilities: Array.from(verified),
    platform: "supabase",
    platform_auth_type: "token_input_env",
    platform_account_hint: firstProject ? `${firstProject.org}` : "org-unavailable",
    platform_scope_hint: `projects:list(json:${sanitizedRows.length})`,
    platform_verification_command: "supabase projects list --output json"
  };
}

function setCorsHeaders(res) {
  res.setHeader("Access-Control-Allow-Origin", "*");
  res.setHeader("Access-Control-Allow-Methods", "GET,POST,DELETE,OPTIONS");
  res.setHeader("Access-Control-Allow-Headers", "Content-Type, X-Browser-Profile-Id");
}

function sendJson(res, status, body) {
  setCorsHeaders(res);
  res.writeHead(status, { "Content-Type": "application/json; charset=utf-8" });
  res.end(JSON.stringify(body, null, 2));
}

function readJsonBody(req) {
  return new Promise((resolve, reject) => {
    let raw = "";
    req.on("data", (chunk) => {
      raw += chunk;
      if (raw.length > 1024 * 1024) {
        reject(new Error("Request body too large"));
      }
    });
    req.on("end", () => {
      if (!raw.trim()) {
        resolve({});
        return;
      }
      try {
        resolve(JSON.parse(raw));
      } catch {
        reject(new Error("Invalid JSON body"));
      }
    });
    req.on("error", reject);
  });
}

function dbGet(sql, ...args) {
  return db.prepare(sql).get(...args);
}

function dbAll(sql, ...args) {
  return db.prepare(sql).all(...args);
}

function dbRun(sql, ...args) {
  return db.prepare(sql).run(...args);
}

function normalizeEntryWorkspaceName(input) {
  const fallback = `workspace-${Date.now()}`;
  const raw = typeof input === "string" && input.trim() ? input.trim() : fallback;
  const clean = raw
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/^-+/, "")
    .replace(/-+$/, "")
    .slice(0, 64);
  return clean || fallback;
}

function currentAccessGrant() {
  return dbGet(
    "SELECT * FROM host_access_grants WHERE access_scope = 'host_full_access' ORDER BY updated_at DESC LIMIT 1"
  );
}

function writeAccessGrant({ granted, source }) {
  const id = shortId("hacc");
  const ts = nowIso();
  dbRun(
    `INSERT INTO host_access_grants (
      id, access_scope, status, source, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?)`,
    id,
    "host_full_access",
    granted ? "granted" : "revoked",
    source ? summarizeText(source, 160) : null,
    ts,
    ts
  );
  return dbGet("SELECT * FROM host_access_grants WHERE id = ?", id);
}

function entryAccessStatusPayload() {
  const row = currentAccessGrant();
  return {
    full_access_granted: row ? String(row.status || "") === "granted" : false,
    status: row ? String(row.status || "revoked") : "revoked",
    source: row?.source || null,
    updated_at: row?.updated_at || null
  };
}

function ensureEntryWorkspaceRow(workspacePath, { name = null, source = "entry_workspace" } = {}) {
  const abs = sanitizeWorkspacePath(workspacePath);
  const existing = dbGet("SELECT * FROM entry_workspaces WHERE workspace_path = ? LIMIT 1", abs);
  if (existing) {
    return existing;
  }
  const id = shortId("ework");
  const ts = nowIso();
  const workspaceName = summarizeText(name || path.basename(abs) || "workspace", 96);
  dbRun(
    `INSERT INTO entry_workspaces (
      id, name, workspace_path, status, source, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?)`,
    id,
    workspaceName,
    abs,
    "active",
    summarizeText(source, 96),
    ts,
    ts
  );
  return dbGet("SELECT * FROM entry_workspaces WHERE id = ?", id);
}

function listEntryWorkspaces(limit = 200) {
  const rows = dbAll("SELECT * FROM entry_workspaces WHERE status = 'active' ORDER BY updated_at DESC LIMIT ?", limit);
  const existingPaths = new Set(rows.map((x) => String(x.workspace_path || "")));
  const dirs = fs
    .readdirSync(workspacesRoot, { withFileTypes: true })
    .filter((x) => x.isDirectory())
    .map((x) => path.join(workspacesRoot, x.name));
  for (const abs of dirs) {
    if (existingPaths.has(abs)) {
      continue;
    }
    ensureEntryWorkspaceRow(abs, { name: path.basename(abs), source: "workspace_dir_discovery" });
  }
  return dbAll("SELECT * FROM entry_workspaces WHERE status = 'active' ORDER BY updated_at DESC LIMIT ?", limit);
}

function recordEntryWorkspaceSelection({ workspaceId = null, workspacePath = null, source = "entry_select" }) {
  const id = shortId("ewsel");
  dbRun(
    `INSERT INTO entry_workspace_selections (
      id, workspace_id, workspace_path, source, selected_at
    ) VALUES (?, ?, ?, ?, ?)`,
    id,
    workspaceId || null,
    workspacePath || null,
    summarizeText(source, 96),
    nowIso()
  );
  return dbGet("SELECT * FROM entry_workspace_selections WHERE id = ?", id);
}

function currentEntryWorkspaceSelection() {
  return dbGet("SELECT * FROM entry_workspace_selections ORDER BY selected_at DESC LIMIT 1");
}

function resolveCurrentEntryWorkspace() {
  const sel = currentEntryWorkspaceSelection();
  if (!sel?.workspace_path) {
    return { selection: sel || null, workspace: null };
  }
  const workspace = dbGet("SELECT * FROM entry_workspaces WHERE workspace_path = ? LIMIT 1", sel.workspace_path);
  if (workspace) {
    return { selection: sel, workspace };
  }
  const ensured = ensureEntryWorkspaceRow(sel.workspace_path, {
    name: path.basename(sel.workspace_path),
    source: "selection_backfill"
  });
  return { selection: sel, workspace: ensured };
}

function createEntryWorkspace(name, source = "entry_create") {
  const workspaceName = normalizeEntryWorkspaceName(name);
  const workspacePath = sanitizeWorkspacePath(path.join(workspacesRoot, workspaceName));
  fs.mkdirSync(workspacePath, { recursive: true });
  return ensureEntryWorkspaceRow(workspacePath, { name: workspaceName, source });
}

function selectEntryWorkspace({ workspaceId = null, workspacePath = null, source = "entry_select" } = {}) {
  if (!workspaceId && !workspacePath) {
    const row = recordEntryWorkspaceSelection({ workspaceId: null, workspacePath: null, source: `${source}_clear` });
    return { selection: row, workspace: null };
  }
  let workspace = null;
  if (workspaceId) {
    workspace = dbGet("SELECT * FROM entry_workspaces WHERE id = ? AND status = 'active' LIMIT 1", workspaceId);
  } else if (workspacePath) {
    workspace = ensureEntryWorkspaceRow(workspacePath, {
      name: path.basename(path.resolve(workspacePath)),
      source
    });
  }
  if (!workspace) {
    return { error: "workspace_not_found" };
  }
  const selection = recordEntryWorkspaceSelection({
    workspaceId: workspace.id,
    workspacePath: workspace.workspace_path,
    source
  });
  return { selection, workspace };
}

function recordEntrySession({
  workspaceId = null,
  workspacePath,
  runId,
  title = "Entry session",
  status = "active"
}) {
  const id = shortId("esess");
  const ts = nowIso();
  dbRun(
    `INSERT INTO entry_sessions (
      id, workspace_id, workspace_path, run_id, title, status, created_at, updated_at, last_active_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    id,
    workspaceId || null,
    workspacePath,
    runId,
    summarizeText(title, 160),
    summarizeText(status, 32),
    ts,
    ts,
    ts
  );
  return dbGet("SELECT * FROM entry_sessions WHERE id = ?", id);
}

function patchEntrySession(sessionId, patch = {}) {
  const allowed = ["status", "title", "run_id", "updated_at", "last_active_at"];
  const keys = Object.keys(patch || {}).filter((k) => allowed.includes(k));
  if (keys.length === 0) {
    return dbGet("SELECT * FROM entry_sessions WHERE id = ?", sessionId);
  }
  const assigns = keys.map((k) => `${k} = ?`).join(", ");
  const args = keys.map((k) => patch[k]);
  args.push(sessionId);
  dbRun(`UPDATE entry_sessions SET ${assigns} WHERE id = ?`, ...args);
  return dbGet("SELECT * FROM entry_sessions WHERE id = ?", sessionId);
}

function touchEntrySession(sessionId) {
  const ts = nowIso();
  return patchEntrySession(sessionId, {
    updated_at: ts,
    last_active_at: ts
  });
}

function latestEntrySession(workspacePath = null) {
  if (typeof workspacePath === "string" && workspacePath.trim()) {
    return dbGet("SELECT * FROM entry_sessions WHERE workspace_path = ? ORDER BY updated_at DESC LIMIT 1", workspacePath.trim());
  }
  return dbGet("SELECT * FROM entry_sessions ORDER BY updated_at DESC LIMIT 1");
}

function listEntrySessions(limit = 100) {
  return dbAll("SELECT * FROM entry_sessions ORDER BY updated_at DESC LIMIT ?", limit);
}

function normalizeEntryTurnLane(input) {
  const lane = String(input || "").trim().toLowerCase();
  return lane === "task" ? "task" : "chat";
}

function nextEntrySessionTurnIndex(sessionId) {
  const row = dbGet("SELECT COALESCE(MAX(turn_index), 0) + 1 AS n FROM entry_session_turns WHERE session_id = ?", sessionId);
  return Number.isFinite(Number(row?.n)) ? Number(row.n) : 1;
}

function recordEntrySessionTurn({
  sessionId,
  runId,
  turnIndex,
  lane,
  promptSummary = null,
  stepId = null,
  status = "running"
}) {
  const id = shortId("eturn");
  const ts = nowIso();
  dbRun(
    `INSERT INTO entry_session_turns (
      id, session_id, run_id, turn_index, lane, prompt_summary, step_id, status, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    id,
    sessionId,
    runId,
    Number.isFinite(Number(turnIndex)) ? Math.max(1, Math.trunc(Number(turnIndex))) : 1,
    normalizeEntryTurnLane(lane),
    promptSummary ? summarizeText(promptSummary, 300) : null,
    stepId || null,
    summarizeText(status || "running", 64),
    ts,
    ts
  );
  return dbGet("SELECT * FROM entry_session_turns WHERE id = ?", id);
}

function patchEntrySessionTurn(turnId, patch = {}) {
  const allowed = ["lane", "prompt_summary", "step_id", "status", "updated_at"];
  const keys = Object.keys(patch || {}).filter((k) => allowed.includes(k));
  if (keys.length === 0) {
    return dbGet("SELECT * FROM entry_session_turns WHERE id = ?", turnId);
  }
  const assigns = keys.map((k) => `${k} = ?`).join(", ");
  const args = keys.map((k) => patch[k]);
  args.push(turnId);
  dbRun(`UPDATE entry_session_turns SET ${assigns} WHERE id = ?`, ...args);
  return dbGet("SELECT * FROM entry_session_turns WHERE id = ?", turnId);
}

function listEntrySessionTurns(sessionId, limit = 120) {
  const capped = Math.max(1, Math.min(500, Number(limit || 120)));
  return dbAll(
    `SELECT * FROM (
      SELECT * FROM entry_session_turns WHERE session_id = ? ORDER BY turn_index DESC LIMIT ?
    ) AS recent_turns
    ORDER BY turn_index ASC`,
    sessionId,
    capped
  );
}

function normalizeComposerMode(input) {
  const mode = String(input || "").trim().toLowerCase();
  return mode === "task" ? "task" : "chat";
}

function normalizeProjectRelPath(input) {
  if (typeof input !== "string") {
    return "";
  }
  const raw = input.trim().replace(/^["'`]+|["'`]+$/g, "");
  if (!raw) {
    return "";
  }
  if (path.isAbsolute(raw)) {
    return "";
  }
  const normalized = normalizeRelativeFilePath(raw);
  const parts = normalized
    .split("/")
    .map((part) => part.trim())
    .filter(Boolean);
  if (!parts.length || parts.some((part) => part === "." || part === "..")) {
    return "";
  }
  return parts.join("/");
}

function normalizeSearchPathQuery(input) {
  return String(input || "")
    .trim()
    .replace(/^@+/, "")
    .replace(/^["'`]+|["'`]+$/g, "")
    .replace(/\\/g, "/")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeComposerToken(token, index = 0) {
  if (!token || typeof token !== "object") {
    return null;
  }
  const kindRaw = String(token.kind || token.type || "").trim().toLowerCase();
  if (!kindRaw) {
    return null;
  }
  if (kindRaw === "command") {
    const alias = String(token.command || token.id || token.value || "").trim().toLowerCase();
    const spec = composerCommandsByAlias.get(alias);
    if (!spec) {
      return null;
    }
    return {
      id: `tok_cmd_${index}`,
      kind: "command",
      command: spec.id,
      label: `/${spec.id}`,
      source: "composer_token"
    };
  }
  if (kindRaw === "reference" || kindRaw === "file" || kindRaw === "directory" || kindRaw === "symbol") {
    const relPath = normalizeProjectRelPath(token.rel_path || token.path || token.value || "");
    const symbol = String(token.symbol || "").trim();
    if (!relPath && !symbol) {
      return null;
    }
    return {
      id: `tok_ref_${index}`,
      kind: kindRaw === "symbol" ? "symbol" : kindRaw === "directory" ? "directory" : "reference",
      rel_path: relPath || null,
      symbol: symbol || null,
      label: String(token.label || token.name || (relPath ? `@${relPath}` : symbol)).trim() || `@${relPath || symbol}`,
      source: "composer_token"
    };
  }
  return null;
}

function normalizeComposerTokens(tokens) {
  if (!Array.isArray(tokens)) {
    return [];
  }
  const out = [];
  const dedupe = new Set();
  for (let i = 0; i < tokens.length && out.length < 32; i += 1) {
    const normalized = normalizeComposerToken(tokens[i], i);
    if (!normalized) {
      continue;
    }
    const key = JSON.stringify([normalized.kind, normalized.command || null, normalized.rel_path || null, normalized.symbol || null]);
    if (dedupe.has(key)) {
      continue;
    }
    dedupe.add(key);
    out.push(normalized);
  }
  return out;
}

function parseSlashCommandFromRawText(rawText) {
  const trimmed = String(rawText || "").trim();
  const match = trimmed.match(/^\/([a-z0-9._-]+)(?:\s+([\s\S]*))?$/i);
  if (!match) {
    return null;
  }
  const alias = String(match[1] || "").trim().toLowerCase();
  const spec = composerCommandsByAlias.get(alias);
  if (!spec) {
    return {
      command: alias,
      arg_text: String(match[2] || "").trim(),
      known: false
    };
  }
  return {
    command: spec.id,
    spec,
    arg_text: String(match[2] || "").trim(),
    known: true
  };
}

function detectComposerTrigger(rawText) {
  const text = String(rawText || "");
  const slash = text.match(/(?:^|\s)\/([a-z0-9._-]*)$/i);
  if (slash) {
    return {
      kind: "slash",
      query: String(slash[1] || "").trim().toLowerCase()
    };
  }
  const at = text.match(/(?:^|\s)@([^\s@]*)$/);
  if (at) {
    return {
      kind: "reference",
      query: normalizeSearchPathQuery(at[1] || "")
    };
  }
  return null;
}

function extractMentionsFromRawText(rawText) {
  const text = String(rawText || "");
  const out = new Set();
  for (const match of text.matchAll(/@([^\s@]+)/g)) {
    const cleaned = normalizeSearchPathQuery(match[1] || "");
    if (cleaned) {
      out.add(cleaned);
    }
  }
  for (const match of text.matchAll(/([a-zA-Z0-9._/-]+\.[a-zA-Z0-9._-]+|[a-zA-Z0-9._-]+\/[a-zA-Z0-9._/-]+)/g)) {
    const cleaned = normalizeSearchPathQuery(match[1] || "");
    if (cleaned) {
      out.add(cleaned);
    }
  }
  for (const match of text.matchAll(/\b[a-z0-9._-]+-[a-z0-9]{2,6}\b/gi)) {
    const cleaned = normalizeSearchPathQuery(match[0] || "");
    if (cleaned) {
      out.add(cleaned);
    }
  }
  for (const match of text.matchAll(/(?:打开|open|查找|搜索|找一下|定位|对齐|align)\s+([^\s，。,；;！？!?]+)/gi)) {
    const cleaned = normalizeSearchPathQuery(match[1] || "");
    if (cleaned) {
      out.add(cleaned);
    }
  }
  return Array.from(out).slice(0, 12);
}

function pickBestTargetQuery(candidates) {
  const list = Array.isArray(candidates) ? candidates.filter(Boolean) : [];
  if (!list.length) {
    return "";
  }
  const sorted = [...list].sort((a, b) => {
    const sa =
      (/[/.]/.test(a) ? 3 : 0) +
      (/-/.test(a) ? 2 : 0) +
      (a.length >= 8 ? 1 : 0) +
      (/[a-z]/i.test(a) ? 1 : 0);
    const sb =
      (/[/.]/.test(b) ? 3 : 0) +
      (/-/.test(b) ? 2 : 0) +
      (b.length >= 8 ? 1 : 0) +
      (/[a-z]/i.test(b) ? 1 : 0);
    if (sa !== sb) {
      return sb - sa;
    }
    return b.length - a.length;
  });
  return sorted[0] || "";
}

function isConfidentDirectTarget(target) {
  if (!target || typeof target !== "object") {
    return false;
  }
  const confidence = Number(target.confidence || 0);
  const reasons = Array.isArray(target.reasons) ? target.reasons.map((x) => String(x || "")) : [];
  if (reasons.includes("token_bound_path")) {
    return true;
  }
  if (
    reasons.includes("exact_rel_path") ||
    reasons.includes("exact_basename") ||
    reasons.includes("suffix_path_match") ||
    reasons.includes("fuzzy_path_match")
  ) {
    return true;
  }
  return confidence >= 0.78;
}

function resolveEntryProjectContext({ projectId = null, threadId = null, fallbackWorkspacePath = null } = {}) {
  let session = null;
  if (typeof threadId === "string" && threadId.trim()) {
    session = dbGet("SELECT * FROM entry_sessions WHERE id = ? LIMIT 1", threadId.trim()) || null;
  }

  let workspace = null;
  if (typeof projectId === "string" && projectId.trim()) {
    workspace = dbGet("SELECT * FROM entry_workspaces WHERE id = ? AND status = 'active' LIMIT 1", projectId.trim()) || null;
  }
  if (!workspace && session?.workspace_id) {
    workspace = dbGet("SELECT * FROM entry_workspaces WHERE id = ? AND status = 'active' LIMIT 1", session.workspace_id) || null;
  }
  if (!workspace && session?.workspace_path) {
    workspace = ensureEntryWorkspaceRow(session.workspace_path, {
      name: path.basename(session.workspace_path),
      source: "entry_session_workspace_backfill"
    });
  }
  if (!workspace && typeof fallbackWorkspacePath === "string" && fallbackWorkspacePath.trim()) {
    workspace = ensureEntryWorkspaceRow(fallbackWorkspacePath.trim(), {
      name: path.basename(fallbackWorkspacePath.trim()),
      source: "entry_fallback_workspace"
    });
  }
  if (!workspace) {
    workspace = resolveCurrentEntryWorkspace().workspace || null;
  }
  if (!workspace) {
    return { session, project: null };
  }
  let rootPath = null;
  try {
    rootPath = sanitizeWorkspacePath(workspace.workspace_path);
  } catch {
    rootPath = null;
  }
  if (!rootPath) {
    return { session, project: null };
  }
  return {
    session,
    project: {
      id: workspace.id,
      name: workspace.name || path.basename(rootPath),
      workspace_path: rootPath,
      root_path: rootPath
    }
  };
}

function upsertEntryProjectRecentFile({ workspaceId, relPath, source = "composer_resolve" }) {
  const normalizedRel = normalizeProjectRelPath(relPath);
  if (!workspaceId || !normalizedRel) {
    return null;
  }
  const now = nowIso();
  const basename = path.basename(normalizedRel);
  const existing = dbGet(
    "SELECT * FROM entry_project_recent_files WHERE workspace_id = ? AND rel_path = ? LIMIT 1",
    workspaceId,
    normalizedRel
  );
  if (existing) {
    dbRun(
      `UPDATE entry_project_recent_files
         SET hit_count = hit_count + 1, source = ?, updated_at = ?, last_used_at = ?, basename = ?
       WHERE id = ?`,
      summarizeText(source, 96),
      now,
      now,
      basename,
      existing.id
    );
    return dbGet("SELECT * FROM entry_project_recent_files WHERE id = ?", existing.id);
  }
  const id = shortId("eprf");
  dbRun(
    `INSERT INTO entry_project_recent_files (
      id, workspace_id, rel_path, basename, hit_count, source, created_at, updated_at, last_used_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    id,
    workspaceId,
    normalizedRel,
    basename,
    1,
    summarizeText(source, 96),
    now,
    now,
    now
  );
  return dbGet("SELECT * FROM entry_project_recent_files WHERE id = ?", id);
}

function upsertEntrySessionTargetFile({ sessionId, workspaceId, relPath, source = "composer_resolve" }) {
  const normalizedRel = normalizeProjectRelPath(relPath);
  if (!sessionId || !workspaceId || !normalizedRel) {
    return null;
  }
  const now = nowIso();
  const basename = path.basename(normalizedRel);
  const existing = dbGet(
    "SELECT * FROM entry_session_target_files WHERE session_id = ? AND rel_path = ? LIMIT 1",
    sessionId,
    normalizedRel
  );
  if (existing) {
    dbRun(
      `UPDATE entry_session_target_files
         SET hit_count = hit_count + 1, source = ?, updated_at = ?, last_used_at = ?, basename = ?, workspace_id = ?
       WHERE id = ?`,
      summarizeText(source, 96),
      now,
      now,
      basename,
      workspaceId,
      existing.id
    );
    return dbGet("SELECT * FROM entry_session_target_files WHERE id = ?", existing.id);
  }
  const id = shortId("estf");
  dbRun(
    `INSERT INTO entry_session_target_files (
      id, session_id, workspace_id, rel_path, basename, hit_count, source, created_at, updated_at, last_used_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    id,
    sessionId,
    workspaceId,
    normalizedRel,
    basename,
    1,
    summarizeText(source, 96),
    now,
    now,
    now
  );
  return dbGet("SELECT * FROM entry_session_target_files WHERE id = ?", id);
}

function touchEntryTargetFileHistory({ workspaceId, sessionId = null, relPath, source = "composer_resolve" }) {
  const normalizedRel = normalizeProjectRelPath(relPath);
  if (!workspaceId || !normalizedRel) {
    return;
  }
  upsertEntryProjectRecentFile({ workspaceId, relPath: normalizedRel, source });
  if (sessionId) {
    upsertEntrySessionTargetFile({ sessionId, workspaceId, relPath: normalizedRel, source });
  }
}

function listEntryProjectRecentFiles(workspaceId, limit = 30) {
  if (!workspaceId) {
    return [];
  }
  return dbAll(
    "SELECT * FROM entry_project_recent_files WHERE workspace_id = ? ORDER BY last_used_at DESC LIMIT ?",
    workspaceId,
    Math.max(1, Math.min(200, Number(limit || 30)))
  );
}

function listEntrySessionTargetFiles(sessionId, limit = 30) {
  if (!sessionId) {
    return [];
  }
  return dbAll(
    "SELECT * FROM entry_session_target_files WHERE session_id = ? ORDER BY last_used_at DESC LIMIT ?",
    sessionId,
    Math.max(1, Math.min(200, Number(limit || 30)))
  );
}

function collectProjectIndex(projectRootPath) {
  const root = path.resolve(projectRootPath);
  const files = [];
  const directories = [];
  const stack = [root];
  while (stack.length > 0) {
    const current = stack.pop();
    if (!current) {
      continue;
    }
    let entries = [];
    try {
      entries = fs.readdirSync(current, { withFileTypes: true });
    } catch {
      continue;
    }
    for (const entry of entries) {
      const full = path.join(current, entry.name);
      const rel = normalizeRelativeFilePath(path.relative(root, full));
      if (!rel) {
        continue;
      }
      if (entry.isDirectory()) {
        if (directories.length < PROJECT_INDEX_MAX_DIRS) {
          directories.push({
            type: "directory",
            rel_path: rel,
            rel_lower: rel.toLowerCase(),
            basename: entry.name,
            basename_lower: entry.name.toLowerCase()
          });
        }
        if (!PROJECT_SEARCH_IGNORED_DIRS.has(entry.name.toLowerCase())) {
          stack.push(full);
        }
        continue;
      }
      if (!entry.isFile()) {
        continue;
      }
      if (files.length < PROJECT_INDEX_MAX_FILES) {
        files.push({
          type: "file",
          rel_path: rel,
          rel_lower: rel.toLowerCase(),
          basename: entry.name,
          basename_lower: entry.name.toLowerCase()
        });
      }
      if (files.length >= PROJECT_INDEX_MAX_FILES && directories.length >= PROJECT_INDEX_MAX_DIRS) {
        break;
      }
    }
  }
  return {
    indexed_at: nowIso(),
    file_count: files.length,
    directory_count: directories.length,
    files,
    directories
  };
}

function getProjectIndex(projectRootPath, { refresh = false } = {}) {
  const key = normalizeFsPath(projectRootPath);
  const nowMs = Date.now();
  const cached = projectIndexCache.get(key);
  if (!refresh && cached && nowMs - cached.cached_at < PROJECT_INDEX_CACHE_TTL_MS) {
    return cached.value;
  }
  const value = collectProjectIndex(projectRootPath);
  projectIndexCache.set(key, {
    cached_at: nowMs,
    value
  });
  return value;
}

function buildSearchQueryVariants(query) {
  const q = normalizeSearchPathQuery(query);
  const out = new Set();
  if (q) {
    out.add(q);
    out.add(q.replace(/\\/g, "/"));
    out.add(q.replace(/\s+/g, ""));
    out.add(q.replace(/_/g, "-"));
    out.add(q.replace(/-/g, "."));
    const extensionFix = q.replace(/-([a-z0-9]{1,6})$/i, ".$1");
    if (extensionFix !== q) {
      out.add(extensionFix);
    }
    const dashedFix = q.replace(/\.([a-z0-9]{1,6})$/i, "-$1");
    if (dashedFix !== q) {
      out.add(dashedFix);
    }
  }
  return Array.from(out)
    .map((item) => normalizeSearchPathQuery(item))
    .filter(Boolean);
}

function parseSymbolQuery(rawQuery) {
  const query = normalizeSearchPathQuery(rawQuery);
  const match = query.match(/^(.*?)(?:#|::)([a-zA-Z_][\w$-]*)$/);
  if (!match) {
    return {
      path_query: query,
      symbol_query: ""
    };
  }
  return {
    path_query: normalizeSearchPathQuery(match[1] || ""),
    symbol_query: String(match[2] || "").trim().toLowerCase()
  };
}

function scoreProjectIndexEntry(entry, context = {}) {
  const query = String(context.query || "").toLowerCase();
  const variants = Array.isArray(context.variants) ? context.variants : [];
  const tokens = Array.isArray(context.tokens) ? context.tokens : [];
  const relLower = String(entry.rel_lower || "").toLowerCase();
  const basenameLower = String(entry.basename_lower || "").toLowerCase();
  const reasons = [];
  let score = 0;

  if (!query && context.from_recent_hint) {
    const hasRecentHint = context.session_hint_set?.has(entry.rel_path) || context.project_hint_set?.has(entry.rel_path);
    if (hasRecentHint) {
      score = 0.63;
      reasons.push("recent_hint");
    } else {
      return null;
    }
  }

  for (const variant of variants) {
    if (!variant) {
      continue;
    }
    const variantBasename = path.basename(variant);
    if (relLower === variant) {
      score = Math.max(score, 1);
      reasons.push("exact_rel_path");
      continue;
    }
    if (basenameLower === variantBasename) {
      score = Math.max(score, 0.95);
      reasons.push("exact_basename");
      if (variant !== query) {
        reasons.push("extension_corrected");
      }
      continue;
    }
    if (relLower.endsWith(`/${variant}`)) {
      score = Math.max(score, 0.91);
      reasons.push("suffix_path_match");
      continue;
    }
    if (relLower.includes(variant)) {
      score = Math.max(score, 0.76);
      reasons.push("fuzzy_path_match");
      continue;
    }
    if (basenameLower.includes(variantBasename)) {
      score = Math.max(score, 0.72);
      reasons.push("fuzzy_basename_match");
    }
  }

  if (tokens.length > 0 && tokens.every((token) => relLower.includes(token))) {
    score = Math.max(score, 0.68);
    reasons.push("token_cover_match");
  } else if (tokens.length > 0 && tokens.some((token) => relLower.includes(token))) {
    score = Math.max(score, 0.56);
    reasons.push("partial_token_match");
  }

  if (context.session_hint_set?.has(entry.rel_path)) {
    score += 0.12;
    reasons.push("thread_last_target_file");
  }
  if (context.project_hint_set?.has(entry.rel_path)) {
    score += 0.08;
    reasons.push("project_recent_file");
  }
  if (entry.type === "directory") {
    score -= 0.03;
  }
  score = Math.max(0, Math.min(0.999, score));
  if (score < 0.46) {
    return null;
  }
  return {
    type: entry.type,
    rel_path: entry.rel_path,
    basename: entry.basename,
    confidence: Number(score.toFixed(3)),
    reasons: Array.from(new Set(reasons))
  };
}

function extractFileSymbols(absPath, maxSymbols = 80) {
  try {
    const stat = fs.statSync(absPath);
    if (!stat.isFile() || stat.size > 1024 * 512) {
      return [];
    }
    const cacheKey = `${normalizeFsPath(absPath)}:${Math.trunc(stat.mtimeMs)}:${stat.size}`;
    if (projectSymbolCache.has(cacheKey)) {
      return projectSymbolCache.get(cacheKey);
    }
    const text = fs.readFileSync(absPath, "utf8");
    const lines = text.split(/\r?\n/);
    const symbols = [];
    const seen = new Set();
    const pushSymbol = (name) => {
      const clean = String(name || "").trim();
      if (!clean || seen.has(clean)) {
        return;
      }
      seen.add(clean);
      symbols.push(clean);
    };
    for (const line of lines) {
      if (symbols.length >= maxSymbols) {
        break;
      }
      let match = line.match(/^\s*(?:export\s+)?(?:async\s+)?function\s+([a-zA-Z_$][\w$]*)/);
      if (match) {
        pushSymbol(match[1]);
        continue;
      }
      match = line.match(/^\s*(?:export\s+)?class\s+([a-zA-Z_$][\w$]*)/);
      if (match) {
        pushSymbol(match[1]);
        continue;
      }
      match = line.match(/^\s*(?:export\s+)?(?:const|let|var)\s+([a-zA-Z_$][\w$]*)\s*=/);
      if (match) {
        pushSymbol(match[1]);
        continue;
      }
      match = line.match(/^\s*def\s+([a-zA-Z_][\w]*)\s*\(/);
      if (match) {
        pushSymbol(match[1]);
        continue;
      }
      match = line.match(/^\s*class\s+([a-zA-Z_][\w]*)/);
      if (match) {
        pushSymbol(match[1]);
      }
    }
    projectSymbolCache.set(cacheKey, symbols);
    return symbols;
  } catch {
    return [];
  }
}

function searchProjectFiles({
  project,
  sessionId = null,
  query = "",
  limit = 12,
  includeDirectories = true,
  includeSymbols = true
}) {
  if (!project?.root_path) {
    return {
      candidates: [],
      query: normalizeSearchPathQuery(query),
      project: null
    };
  }
  const parsedSymbol = parseSymbolQuery(query);
  const queryText = parsedSymbol.path_query || normalizeSearchPathQuery(query);
  const variants = buildSearchQueryVariants(queryText).map((x) => x.toLowerCase());
  const tokenParts = queryText
    .toLowerCase()
    .split(/[\\/._\- ]+/)
    .map((part) => part.trim())
    .filter((part) => part.length >= 2);

  const sessionHints = listEntrySessionTargetFiles(sessionId, 60);
  const projectHints = listEntryProjectRecentFiles(project.id, 60);
  const sessionHintSet = new Set(sessionHints.map((row) => String(row.rel_path || "")));
  const projectHintSet = new Set(projectHints.map((row) => String(row.rel_path || "")));
  const queryContext = {
    query: queryText.toLowerCase(),
    variants,
    tokens: tokenParts,
    session_hint_set: sessionHintSet,
    project_hint_set: projectHintSet,
    from_recent_hint: !queryText
  };

  const index = getProjectIndex(project.root_path, { refresh: false });
  const candidates = [];
  for (const file of index.files || []) {
    const scored = scoreProjectIndexEntry(file, queryContext);
    if (scored) {
      candidates.push(scored);
    }
  }
  if (includeDirectories) {
    for (const dir of index.directories || []) {
      const scored = scoreProjectIndexEntry(dir, queryContext);
      if (scored) {
        candidates.push(scored);
      }
    }
  }

  candidates.sort((a, b) => {
    if (b.confidence !== a.confidence) {
      return b.confidence - a.confidence;
    }
    if (a.rel_path.length !== b.rel_path.length) {
      return a.rel_path.length - b.rel_path.length;
    }
    return a.rel_path.localeCompare(b.rel_path);
  });
  let trimmed = candidates.slice(0, Math.max(1, Math.min(100, Number(limit || 12))));

  if (includeSymbols && parsedSymbol.symbol_query) {
    const symbolQuery = parsedSymbol.symbol_query;
    const symbolCandidates = [];
    for (const candidate of trimmed.filter((item) => item.type === "file").slice(0, 5)) {
      const abs = path.join(project.root_path, candidate.rel_path);
      const symbols = extractFileSymbols(abs, 80);
      for (const symbol of symbols) {
        const lower = symbol.toLowerCase();
        if (!lower.includes(symbolQuery)) {
          continue;
        }
        symbolCandidates.push({
          type: "symbol",
          rel_path: candidate.rel_path,
          basename: candidate.basename,
          symbol,
          confidence: Number(Math.max(0.5, candidate.confidence - 0.03).toFixed(3)),
          reasons: ["symbol_match", "file_candidate_match"]
        });
      }
    }
    trimmed = [...symbolCandidates, ...trimmed].slice(0, Math.max(1, Math.min(100, Number(limit || 12))));
  }

  return {
    project: {
      id: project.id,
      name: project.name,
      root_path: project.root_path
    },
    query: queryText,
    symbol_query: parsedSymbol.symbol_query || null,
    index: {
      indexed_at: index.indexed_at,
      file_count: Number(index.file_count || 0),
      directory_count: Number(index.directory_count || 0)
    },
    candidates: trimmed,
    recent_files: projectHints.slice(0, 20).map((row) => ({
      rel_path: row.rel_path,
      hit_count: Number(row.hit_count || 0),
      last_used_at: row.last_used_at
    })),
    last_target_files: sessionHints.slice(0, 20).map((row) => ({
      rel_path: row.rel_path,
      hit_count: Number(row.hit_count || 0),
      last_used_at: row.last_used_at
    }))
  };
}

function resolveProjectRelPath(project, relPath) {
  const normalizedRel = normalizeProjectRelPath(relPath);
  const rawRel = String(relPath || "");
  if (!project?.root_path) {
    return { ok: false, error: "target_rel_path_required" };
  }
  if (!normalizedRel) {
    if (rawRel.trim()) {
      throw makePathBoundaryError({
        reason: "outside_working_root",
        checkType: "project_target_resolve",
        pathValue: rawRel,
        workspaceRoot: project.root_path
      });
    }
    return { ok: false, error: "target_rel_path_required" };
  }
  const abs = path.resolve(project.root_path, normalizedRel);
  const boundary = recordBoundaryCheck({
    workspaceRootPath: project.root_path,
    targetPath: abs,
    checkType: "project_target_resolve"
  });
  if (!boundary?.approved || !isWithinWorkspace(abs, project.root_path)) {
    throw makePathBoundaryError({
      reason: String(boundary?.reason || "outside_working_root"),
      checkType: String(boundary?.checkType || "project_target_resolve"),
      pathValue: abs,
      workspaceRoot: project.root_path
    });
  }
  if (!fs.existsSync(abs)) {
    return {
      ok: false,
      error: "target_not_found",
      rel_path: normalizedRel
    };
  }
  let real = abs;
  try {
    real = fs.realpathSync(abs);
  } catch {
    real = abs;
  }
  if (!isWithinWorkspace(real, project.root_path)) {
    throw makePathBoundaryError({
      reason: "outside_working_root",
      checkType: "project_target_realpath",
      pathValue: real,
      workspaceRoot: project.root_path
    });
  }
  return {
    ok: true,
    rel_path: normalizeRelativeFilePath(path.relative(project.root_path, real)),
    abs_path: real,
    type: fs.statSync(real).isDirectory() ? "directory" : "file"
  };
}

function inferComposerIntent({ rawText, lane, slashCommand, mentionQueries }) {
  const text = String(rawText || "").trim();
  const hasMentions = Array.isArray(mentionQueries) && mentionQueries.length > 0;
  const bestMention = pickBestTargetQuery(mentionQueries || []);
  if (slashCommand?.known && slashCommand?.spec) {
    if (slashCommand.spec.host_action) {
      return {
        id: `host.${slashCommand.spec.host_action}`,
        type: "host_action",
        host_action: slashCommand.spec.host_action,
        requires_target: !!slashCommand.spec.needs_target,
        target_query: normalizeSearchPathQuery(slashCommand.arg_text || bestMention || "")
      };
    }
    return {
      id: `composer.${slashCommand.spec.id}`,
      type: slashCommand.spec.id === "search-file" ? "search_action" : "task_action",
      requires_target: !!slashCommand.spec.needs_target,
      target_query: normalizeSearchPathQuery(slashCommand.arg_text || bestMention || "")
    };
  }

  if (/(?:^|\s)(打开|open)\s*(?:当前)?(?:项目|工程|工作区|workspace|folder|目录|文件夹)(?:\s|$)/i.test(text)) {
    return {
      id: "host.open-folder",
      type: "host_action",
      host_action: "open-folder",
      requires_target: false,
      target_query: ""
    };
  }
  if (/(定位|reveal|show\s+in\s+(?:explorer|finder)|在资源管理器|在文件夹中显示)/i.test(text)) {
    return {
      id: "host.reveal-path",
      type: "host_action",
      host_action: "reveal-path",
      requires_target: true,
      target_query: bestMention
    };
  }
  if (/(打开|\bopen\b|\bshow\b)/i.test(text) && hasMentions) {
    return {
      id: "host.open-file",
      type: "host_action",
      host_action: "open-file",
      requires_target: true,
      target_query: bestMention
    };
  }
  if (/(找一下|查找|搜索|search|find|locate)/i.test(text) && hasMentions) {
    return {
      id: "task.search-file",
      type: "search_action",
      requires_target: true,
      target_query: bestMention
    };
  }
  if (/(对齐|align|同步|sync|修复|修改|patch|更新)/i.test(text) && hasMentions) {
    return {
      id: "task.targeted_patch",
      type: "task_action",
      requires_target: true,
      target_query: bestMention
    };
  }
  if (lane === "task" && hasMentions) {
    return {
      id: "task.targeted_existing_file",
      type: "task_action",
      requires_target: true,
      target_query: bestMention
    };
  }
  return {
    id: lane === "task" ? "task.generic" : "chat.generic",
    type: lane === "task" ? "task_action" : "chat",
    requires_target: false,
    target_query: ""
  };
}

function buildComposerSuggestions({ trigger, project, sessionId }) {
  const suggestions = {
    commands: [],
    references: []
  };
  if (!trigger || !project?.root_path) {
    return suggestions;
  }
  if (trigger.kind === "slash") {
    const query = String(trigger.query || "").trim().toLowerCase();
    suggestions.commands = COMPOSER_COMMAND_CATALOG
      .filter((cmd) => {
        if (!query) {
          return true;
        }
        return cmd.id.includes(query) || cmd.aliases.some((alias) => String(alias).includes(query));
      })
      .slice(0, 12)
      .map((cmd) => ({
        id: cmd.id,
        label: `/${cmd.id}`,
        description: cmd.description,
        needs_target: !!cmd.needs_target
      }));
    return suggestions;
  }
  if (trigger.kind === "reference") {
    const query = normalizeSearchPathQuery(trigger.query || "");
    const lookup = searchProjectFiles({
      project,
      sessionId,
      query,
      limit: 12,
      includeDirectories: true,
      includeSymbols: true
    });
    suggestions.references = (lookup.candidates || []).map((item) => ({
      type: item.type,
      rel_path: item.rel_path,
      symbol: item.symbol || null,
      label: item.type === "symbol" ? `@${item.rel_path}#${item.symbol}` : `@${item.rel_path}`,
      confidence: item.confidence,
      reasons: item.reasons
    }));
  }
  return suggestions;
}

function resolveComposerRequest({ threadId = null, projectId = null, rawText = "", tokens = [], mode = "chat" } = {}) {
  const lane = normalizeComposerMode(mode);
  const cleanRawText = String(rawText || "").trim();
  const normalizedTokens = normalizeComposerTokens(tokens);
  const slashFromRaw = parseSlashCommandFromRawText(cleanRawText);
  const commandToken = normalizedTokens.find((token) => token.kind === "command") || null;
  const commandSpec = commandToken ? composerCommandsByAlias.get(commandToken.command) || null : slashFromRaw?.spec || null;
  const effectiveCommand = commandSpec
    ? {
        known: true,
        spec: commandSpec,
        arg_text: slashFromRaw?.arg_text || ""
      }
    : slashFromRaw;
  const mentionQueries = extractMentionsFromRawText(cleanRawText);
  const projectContext = resolveEntryProjectContext({
    projectId,
    threadId
  });
  const project = projectContext.project;
  const sessionId = projectContext.session?.id || (typeof threadId === "string" && threadId.trim() ? threadId.trim() : null);
  const intent = inferComposerIntent({
    rawText: cleanRawText,
    lane,
    slashCommand: effectiveCommand,
    mentionQueries
  });
  const result = {
    intent: {
      id: intent.id,
      type: intent.type,
      lane,
      host_action: intent.host_action || null
    },
    entities: {
      thread_id: sessionId || null,
      project_id: project?.id || null,
      mode: lane,
      raw_text: cleanRawText,
      command: commandSpec?.id || slashFromRaw?.command || null,
      mention_queries: mentionQueries,
      tokens: normalizedTokens
    },
    resolvedTargets: [],
    needsClarification: {
      required: false,
      reason: null,
      message: null
    },
    hostAction: null,
    taskAction: null,
    suggestions: buildComposerSuggestions({
      trigger: detectComposerTrigger(cleanRawText),
      project,
      sessionId
    })
  };

  if (!project?.id) {
    result.needsClarification = {
      required: true,
      reason: "project_required",
      message: "Select a project workspace before using composer actions."
    };
    return result;
  }

  const tokenTargetCandidates = normalizedTokens
    .filter((token) => token.kind === "reference" || token.kind === "directory" || token.kind === "symbol")
    .map((token) => token.rel_path)
    .filter(Boolean);

  const queryCandidates = [];
  if (intent.target_query) {
    queryCandidates.push(intent.target_query);
  }
  if (slashFromRaw?.arg_text) {
    queryCandidates.push(normalizeSearchPathQuery(slashFromRaw.arg_text));
  }
  queryCandidates.push(...mentionQueries);
  queryCandidates.push(...tokenTargetCandidates);
  const uniqueQueryCandidates = Array.from(new Set(queryCandidates.map((x) => normalizeSearchPathQuery(x)).filter(Boolean))).slice(0, 6);

  const resolvedTargets = [];
  for (const tokenRel of tokenTargetCandidates) {
    const resolved = resolveProjectRelPath(project, tokenRel);
    if (resolved.ok) {
      resolvedTargets.push({
        type: resolved.type,
        rel_path: resolved.rel_path,
        confidence: 1,
        reasons: ["token_bound_path"]
      });
    }
  }
  for (const candidateQuery of uniqueQueryCandidates) {
    if (resolvedTargets.length >= 8) {
      break;
    }
    const lookedUp = searchProjectFiles({
      project,
      sessionId,
      query: candidateQuery,
      limit: 6,
      includeDirectories: true,
      includeSymbols: true
    });
    if (!Array.isArray(lookedUp.candidates) || lookedUp.candidates.length === 0) {
      continue;
    }
    const top = lookedUp.candidates[0];
    if (!top?.rel_path) {
      continue;
    }
    const dedupeKey = `${top.type}:${top.rel_path}:${top.symbol || ""}`;
    if (resolvedTargets.some((item) => `${item.type}:${item.rel_path}:${item.symbol || ""}` === dedupeKey)) {
      continue;
    }
    resolvedTargets.push({
      type: top.type,
      rel_path: top.rel_path,
      symbol: top.symbol || null,
      confidence: top.confidence,
      reasons: top.reasons || [],
      query: candidateQuery
    });
  }
  result.resolvedTargets = resolvedTargets;

  if (intent.requires_target && resolvedTargets.length === 0) {
    const targetQuery = pickBestTargetQuery(uniqueQueryCandidates);
    result.needsClarification = {
      required: true,
      reason: "target_not_found_in_project",
      message: `No matching file was found in project root ${project.root_path}. Copy the file into this project and retry.`,
      target_query: targetQuery || null
    };
    result.taskAction = intent.type === "task_action"
      ? {
          type: intent.id,
          allow_create: false,
          create_policy: "existing_only",
          targets: []
        }
      : null;
    return result;
  }

  if (intent.type === "host_action") {
    if (intent.host_action === "open-folder") {
      result.hostAction = {
        type: "open-folder",
        project_id: project.id
      };
    } else {
      const target = resolvedTargets.find((item) => item.rel_path && isConfidentDirectTarget(item)) || null;
      if (!target) {
        result.needsClarification = {
          required: true,
          reason: "target_not_found_in_project",
          message: `No confident file match was found in project root ${project.root_path}. Copy the file into this project and retry.`,
          target_query: pickBestTargetQuery(uniqueQueryCandidates) || null
        };
        result.hostAction = null;
        return result;
      }
      result.hostAction = {
        type: intent.host_action,
        project_id: project.id,
        rel_path: target.rel_path
      };
    }
    return result;
  }

  if (intent.type === "task_action" || intent.type === "search_action") {
    result.taskAction = {
      type: intent.id,
      allow_create: false,
      create_policy: "existing_only",
      targets: resolvedTargets
        .filter((item) => item.rel_path)
        .map((item) => ({
          type: item.type,
          rel_path: item.rel_path,
          symbol: item.symbol || null,
          confidence: item.confidence
        }))
    };
  }

  return result;
}

function buildHostActionLaunchPlan(actionType, targetPath) {
  const abs = path.resolve(targetPath);
  if (process.platform === "win32") {
    if (actionType === "reveal-path") {
      return {
        method: "windows_explorer_reveal",
        command: "explorer.exe",
        args: [`/select,${abs}`]
      };
    }
    if (actionType === "open-file") {
      return {
        method: "windows_open_file",
        command: "cmd.exe",
        args: ["/c", "start", "", abs]
      };
    }
    return {
      method: "windows_explorer_open_folder",
      command: "explorer.exe",
      args: [abs]
    };
  }
  if (process.platform === "darwin") {
    if (actionType === "reveal-path") {
      return {
        method: "mac_open_reveal",
        command: "open",
        args: ["-R", abs]
      };
    }
    return {
      method: "mac_open",
      command: "open",
      args: [abs]
    };
  }
  if (actionType === "reveal-path") {
    return {
      method: "linux_xdg_open_parent",
      command: "xdg-open",
      args: [path.dirname(abs)]
    };
  }
  return {
    method: "linux_xdg_open",
    command: "xdg-open",
    args: [abs]
  };
}

function launchDetachedHostAction(actionType, targetPath) {
  const plan = buildHostActionLaunchPlan(actionType, targetPath);
  const child = spawn(plan.command, plan.args, {
    detached: true,
    windowsHide: true,
    stdio: "ignore"
  });
  child.unref();
  return {
    ok: true,
    method: plan.method,
    command: plan.command,
    args: plan.args,
    pid: child.pid || null
  };
}

function executeHostAction({ actionType, projectId, relPath = null, sessionId = null, source = "api_host_action" }) {
  const context = resolveEntryProjectContext({
    projectId,
    threadId: sessionId
  });
  const project = context.project;
  if (!project?.id) {
    return {
      ok: false,
      status: 404,
      error: "project_not_found",
      message: "Project not found for host action."
    };
  }
  let target = project.root_path;
  let normalizedRel = null;
  if (actionType === "open-folder") {
    if (typeof relPath === "string" && relPath.trim()) {
      const resolved = resolveProjectRelPath(project, relPath);
      if (!resolved.ok) {
        return {
          ok: false,
          status: 404,
          error: resolved.error || "path_not_found",
          rel_path: normalizeProjectRelPath(relPath),
          message: "Folder target not found in project root."
        };
      }
      if (resolved.type !== "directory") {
        return {
          ok: false,
          status: 409,
          error: "target_not_directory",
          rel_path: resolved.rel_path,
          message: "open-folder requires a directory target."
        };
      }
      target = resolved.abs_path;
      normalizedRel = resolved.rel_path;
    } else {
      target = project.root_path;
    }
  } else {
    const resolved = resolveProjectRelPath(project, relPath || "");
    if (!resolved.ok) {
      return {
        ok: false,
        status: 404,
        error: resolved.error || "path_not_found",
        rel_path: normalizeProjectRelPath(relPath || ""),
        message: "Target path not found in project root."
      };
    }
    if (actionType === "open-file" && resolved.type !== "file") {
      return {
        ok: false,
        status: 409,
        error: "target_not_file",
        rel_path: resolved.rel_path,
        message: "open-file requires an existing file target."
      };
    }
    target = resolved.abs_path;
    normalizedRel = resolved.rel_path;
  }

  const launch = launchDetachedHostAction(actionType, target);
  if (!launch.ok) {
    return {
      ok: false,
      status: 500,
      error: "host_action_launch_failed",
      message: "Failed to launch host action."
    };
  }
  if (normalizedRel) {
    touchEntryTargetFileHistory({
      workspaceId: project.id,
      sessionId: sessionId || context.session?.id || null,
      relPath: normalizedRel,
      source
    });
  }
  return {
    ok: true,
    status: 202,
    accepted: true,
    action: actionType,
    project_id: project.id,
    rel_path: normalizedRel,
    target_path: target,
    method: launch.method,
    pid: launch.pid
  };
}

function normalizeResolvedTargetsForTurn(rawTargets) {
  if (!Array.isArray(rawTargets)) {
    return [];
  }
  const out = [];
  const dedupe = new Set();
  for (const item of rawTargets.slice(0, 24)) {
    if (!item || typeof item !== "object") {
      continue;
    }
    const relPath = normalizeProjectRelPath(item.rel_path || item.path || "");
    const symbol = String(item.symbol || "").trim() || null;
    if (!relPath) {
      continue;
    }
    const type = String(item.type || "file").trim().toLowerCase();
    const normalizedType = type === "directory" ? "directory" : type === "symbol" ? "symbol" : "file";
    const key = `${normalizedType}:${relPath}:${symbol || ""}`;
    if (dedupe.has(key)) {
      continue;
    }
    dedupe.add(key);
    out.push({
      type: normalizedType,
      rel_path: relPath,
      symbol,
      confidence: Number.isFinite(Number(item.confidence)) ? Number(item.confidence) : null,
      reasons: Array.isArray(item.reasons) ? item.reasons.map((x) => String(x || "")).filter(Boolean).slice(0, 6) : []
    });
  }
  return out;
}

function buildEntryTurnStepId(sessionId, lane) {
  const laneTag = normalizeEntryTurnLane(lane);
  const sessionTag = String(sessionId || "session").replace(/[^a-zA-Z0-9]/g, "").slice(-8) || "session";
  return `step.entry.turn.${laneTag}.${Date.now()}.${sessionTag}`;
}

function normalizeEntryTurnAttachments(rawAttachments) {
  if (!Array.isArray(rawAttachments)) {
    return [];
  }
  const out = [];
  for (const item of rawAttachments.slice(0, 24)) {
    if (!item || typeof item !== "object") {
      continue;
    }
    const source = String(item.source || "").trim().toLowerCase();
    const sourceType = source === "paste" ? "paste" : source === "screenshot" ? "screenshot" : "upload";
    const originalName =
      summarizeText(String(item.name || item.file_name || `${sourceType}-${Date.now()}`), 160) ||
      `${sourceType}-${Date.now()}`;
    let mimeType = String(item.mime || item.mime_type || "").trim() || null;
    let buffer = null;
    if (sourceType === "paste") {
      const text = typeof item.text === "string" ? item.text : "";
      if (!text.trim()) {
        continue;
      }
      if (!mimeType) {
        mimeType = "text/plain";
      }
      buffer = Buffer.from(text, "utf8");
    } else {
      const rawBase64 =
        typeof item.content_base64 === "string"
          ? item.content_base64.trim()
          : typeof item.content === "string"
            ? item.content.trim()
            : "";
      if (!rawBase64) {
        continue;
      }
      try {
        buffer = Buffer.from(rawBase64, "base64");
      } catch {
        buffer = null;
      }
      if (!(buffer && buffer.length > 0)) {
        continue;
      }
      if (!mimeType && sourceType === "screenshot") {
        mimeType = "image/png";
      }
    }
    out.push({
      sourceType,
      ingestChannel: sourceType === "paste" ? "entry_turn_paste" : sourceType === "screenshot" ? "entry_turn_screenshot" : "entry_turn_upload",
      originalName,
      mimeType,
      buffer
    });
  }
  return out;
}

function buildEntryTurnUserMessage(promptText, attachmentSpecs = []) {
  const prompt = String(promptText || "").trim();
  const base = prompt || "(attachment-only message)";
  const names = attachmentSpecs
    .map((x) => String(x?.originalName || "").trim())
    .filter(Boolean);
  if (!names.length) {
    return base;
  }
  return `${base}\nAttachments: ${names.join(", ")}`;
}

function buildEntryTurnChatReply({ promptText, runId, workspacePath, turnIndex, resolver = null }) {
  const prompt = String(promptText || "").trim();
  const workspaceLabel = workspacePath ? path.basename(workspacePath) || workspacePath : "workspace";
  if (/^(hi|hello|hey|你好|您好|嗨|哈喽)[!！,.，。?？ ]*$/i.test(prompt)) {
    return `Hi，runtime 已接通。run=${runId}，workspace=${workspaceLabel}。`;
  }
  if (/^ops$/i.test(prompt)) {
    return `ops: runtime=online, run=${runId}, turn=${Number.isFinite(Number(turnIndex)) ? Number(turnIndex) : 0}, workspace=${workspaceLabel}`;
  }
  const resolvedTargets = normalizeResolvedTargetsForTurn(resolver?.resolvedTargets || resolver?.resolved_targets || []);
  if (resolvedTargets.length > 0) {
    const preview = resolvedTargets
      .slice(0, 4)
      .map((item) => item.symbol ? `${item.rel_path}#${item.symbol}` : item.rel_path)
      .join(", ");
    return `已识别目标文件：${preview}\nrun=${runId}\nworkspace=${workspaceLabel}`;
  }
  const preview = summarizeText(prompt || "(empty_prompt)", 220);
  return `已通过 runtime 执行本轮请求：${preview}\nrun=${runId}\nworkspace=${workspaceLabel}`;
}

function buildEntryTurnTaskCommandPlan(promptText, options = {}) {
  const prompt = String(promptText || "");
  const resolvedTargets = normalizeResolvedTargetsForTurn(options.resolvedTargets || []);
  if (resolvedTargets.length > 0 && /(找一下|查找|搜索|search|find|locate|对齐|align|同步|sync|修复|修改|patch|更新)/i.test(prompt)) {
    const lines = resolvedTargets.slice(0, 12).map((item) => item.symbol ? `${item.rel_path}#${item.symbol}` : item.rel_path);
    const escaped = JSON.stringify(lines.join("\n"));
    return {
      command: "node",
      args: ["-e", `console.log(${escaped})`],
      summary: "print_resolved_target_candidates"
    };
  }
  if (/node\s*-v|node version|node版本/i.test(prompt)) {
    return {
      command: "node",
      args: ["--version"],
      summary: "node_version_probe"
    };
  }
  if (/pwd|当前路径|工作目录|where am i|workspace path/i.test(prompt)) {
    return {
      command: "node",
      args: ["-e", "console.log(process.cwd())"],
      summary: "print_working_directory"
    };
  }
  if (/列出|目录|文件|list files?|\bls\b|\bdir\b/i.test(prompt)) {
    return {
      command: "node",
      args: [
        "-e",
        "const fs=require('fs');const list=fs.readdirSync(process.cwd(),{withFileTypes:true}).slice(0,80).map((d)=>d.name+(d.isDirectory()?'/':''));console.log(list.join('\\n'));"
      ],
      summary: "list_workspace_entries"
    };
  }
  if (/git status|仓库状态/i.test(prompt)) {
    return {
      command: "git",
      args: ["status", "--short"],
      summary: "git_status_short"
    };
  }
  return {
    command: "node",
    args: ["-e", "console.log('entry task runtime executed')"],
    summary: "runtime_heartbeat"
  };
}

function finalizeRunSilently(runId, status = "completed", marker = "entry.session.initialized") {
  const ts = nowIso();
  dbRun("UPDATE runs SET status = ?, updated_at = ?, last_event_type = ? WHERE id = ?", status, ts, marker, runId);
  if (activeRunId === runId && !["running", "pending_approval"].includes(String(status || "").toLowerCase())) {
    activeRunId = null;
  }
  writeRunMeta(runId);
}

function executeEntryTurnRun(runId, plan = {}) {
  const lane = normalizeEntryTurnLane(plan.lane);
  const stepId = typeof plan.stepId === "string" && plan.stepId.trim() ? plan.stepId.trim() : `step.entry.turn.${lane}`;
  const sessionId = typeof plan.sessionId === "string" && plan.sessionId.trim() ? plan.sessionId.trim() : null;
  const turnId = typeof plan.turnId === "string" && plan.turnId.trim() ? plan.turnId.trim() : null;
  const turnIndex = Number.isFinite(Number(plan.turnIndex)) ? Number(plan.turnIndex) : null;
  const promptText = String(plan.promptText || "").trim();
  const resolver = plan.resolver && typeof plan.resolver === "object" ? plan.resolver : null;
  const resolvedTargets = normalizeResolvedTargetsForTurn(plan.resolvedTargets || resolver?.resolvedTargets || resolver?.resolved_targets || []);
  const workspacePath =
    typeof plan.workspacePath === "string" && plan.workspacePath.trim()
      ? sanitizeWorkspacePath(plan.workspacePath)
      : repoRoot;

  try {
    emitEvent(runId, "planner.started", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      turn_index: turnIndex,
      lane,
      prompt_summary: summarizeText(promptText, 260),
      resolved_target_count: resolvedTargets.length,
      composer_intent: summarizeText(String(resolver?.intent?.id || ""), 96) || null
    });

    if (lane === "chat") {
      emitEvent(runId, "planner.completed", {
        step_id: stepId,
        session_id: sessionId,
        turn_id: turnId,
        lane,
        executor: "entry_chat_executor",
        adapter: "chat.runtime"
      });
      emitEvent(runId, "executor.started", {
        step_id: stepId,
        session_id: sessionId,
        turn_id: turnId,
        lane,
        executor: "entry_chat_executor"
      });
      const startedAt = nowIso();
      const reply = buildEntryTurnChatReply({
        promptText,
        runId,
        workspacePath,
        turnIndex,
        resolver
      });
      const adapterRow = recordAdapterRun({
        runId,
        adapterId: "chat.runtime",
        commandOrAction: "compose_reply",
        cwd: workspacePath,
        status: "completed",
        startedAt,
        completedAt: nowIso(),
        exitCode: 0,
        stdoutSummary: summarizeText(reply, 1200),
        stderrSummary: null
      });
      emitEvent(runId, "adapter.chat.completed", {
        step_id: stepId,
        session_id: sessionId,
        turn_id: turnId,
        lane,
        adapter_run_id: adapterRow.id
      });
      emitEvent(runId, "executor.completed", {
        step_id: stepId,
        session_id: sessionId,
        turn_id: turnId,
        lane,
        executor: "entry_chat_executor",
        adapter_run_id: adapterRow.id
      });
      emitEvent(runId, "step.completed", {
        step_id: stepId,
        session_id: sessionId,
        turn_id: turnId,
        turn_index: turnIndex,
        lane,
        message: reply,
        adapter_run_id: adapterRow.id
      });
      if (turnId) {
        patchEntrySessionTurn(turnId, {
          status: "completed",
          updated_at: nowIso()
        });
      }
      if (sessionId) {
        touchEntrySession(sessionId);
      }
      return;
    }

    const commandPlan = buildEntryTurnTaskCommandPlan(promptText, {
      resolvedTargets
    });
    emitEvent(runId, "planner.completed", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      lane,
      executor: "entry_task_executor",
      adapter: "shell",
      command: commandPlan.command,
      args: commandPlan.args,
      route_reason: commandPlan.summary,
      resolved_targets: resolvedTargets.map((item) => ({
        type: item.type,
        rel_path: item.rel_path,
        symbol: item.symbol || null
      }))
    });
    emitEvent(runId, "executor.started", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      lane,
      executor: "entry_task_executor"
    });
    emitEvent(runId, "adapter.shell.started", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      lane,
      command: commandPlan.command,
      args: commandPlan.args
    });

    const startedAt = nowIso();
    const result = runLocalCommand(commandPlan.command, commandPlan.args, 15000, {
      cwd: workspacePath,
      workspace_root: workspacePath,
      run_id: runId,
      step_id: stepId,
      shell: false
    });
    const completedAt = nowIso();
    const adapterRow = recordAdapterRun({
      runId,
      adapterId: "shell",
      commandOrAction: [commandPlan.command, ...(Array.isArray(commandPlan.args) ? commandPlan.args : [])].join(" ").trim(),
      cwd: result.cwd || workspacePath,
      status: result.ok ? "completed" : "failed_controlled",
      startedAt,
      completedAt,
      exitCode: result.status,
      stdoutSummary: result.stdout,
      stderrSummary: result.stderr || result.error_message || null
    });

    emitEvent(runId, "adapter.shell.completed", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      lane,
      adapter_run_id: adapterRow.id,
      ok: result.ok,
      exit_code: result.status,
      signal: result.signal || null
    });
    emitEvent(runId, "executor.completed", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      lane,
      executor: "entry_task_executor",
      adapter_run_id: adapterRow.id,
      ok: result.ok
    });

    if (!result.ok) {
      const reason =
        summarizeText(result.error_message || result.stderr || `command_exit_${String(result.status ?? "unknown")}`, 220) ||
        "entry_task_failed";
      emitEvent(runId, "step.failed_controlled", {
        step_id: stepId,
        session_id: sessionId,
        turn_id: turnId,
        turn_index: turnIndex,
        lane,
        reason,
        adapter_run_id: adapterRow.id
      });
      if (turnId) {
        patchEntrySessionTurn(turnId, {
          status: "failed_controlled",
          updated_at: nowIso()
        });
      }
      if (sessionId) {
        touchEntrySession(sessionId);
      }
      return;
    }

    const stdoutText = summarizeText(String(result.stdout || "").trim(), 1200);
    const stderrText = summarizeText(String(result.stderr || "").trim(), 300);
    let finalMessage = stdoutText || "Task executed successfully (no stdout).";
    if (stderrText) {
      finalMessage = `${finalMessage}\nstderr: ${stderrText}`;
    }
    emitEvent(runId, "step.completed", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      turn_index: turnIndex,
      lane,
      message: finalMessage,
      adapter_run_id: adapterRow.id
    });
    if (turnId) {
      patchEntrySessionTurn(turnId, {
        status: "completed",
        updated_at: nowIso()
      });
    }
    if (sessionId) {
      touchEntrySession(sessionId);
    }
  } catch (error) {
    const reason = summarizeText(error instanceof Error ? error.message : String(error), 240) || "entry_turn_runtime_error";
    emitEvent(runId, "step.failed_controlled", {
      step_id: stepId,
      session_id: sessionId,
      turn_id: turnId,
      turn_index: turnIndex,
      lane,
      reason
    });
    if (turnId) {
      patchEntrySessionTurn(turnId, {
        status: "failed_controlled",
        updated_at: nowIso()
      });
    }
    if (sessionId) {
      touchEntrySession(sessionId);
    }
  }
}

function createEntryTurnRun({
  sessionRow,
  promptText,
  lane,
  classification = null,
  attachments = [],
  stepId = null,
  rawText = null,
  tokens = [],
  resolver = null
}) {
  if (!sessionRow?.id || !sessionRow?.workspace_path) {
    return { error: "entry_session_not_found" };
  }
  const prompt = String(promptText || "").trim();
  const rawPrompt = String(rawText || promptText || "").trim();
  const normalizedTokens = normalizeComposerTokens(tokens);
  const normalizedResolvedTargets = normalizeResolvedTargetsForTurn(resolver?.resolvedTargets || resolver?.resolved_targets || []);
  const attachmentSpecs = normalizeEntryTurnAttachments(attachments);
  if (!prompt && attachmentSpecs.length === 0) {
    return { error: "prompt_or_attachment_required" };
  }

  const turnLane = normalizeEntryTurnLane(lane);
  const resolvedStepId = typeof stepId === "string" && stepId.trim() ? stepId.trim() : buildEntryTurnStepId(sessionRow.id, turnLane);
  const id = shortId("run");
  const ts = nowIso();
  const runTitle = summarizeText(`entry turn ${turnLane}: ${prompt || "attachment-only"}`, 160) || `entry turn ${turnLane}`;

  dbRun(
    "INSERT INTO runs (id, title, status, created_at, updated_at, last_event_type) VALUES (?, ?, ?, ?, ?, ?)",
    id,
    runTitle,
    "running",
    ts,
    ts,
    null
  );
  activeRunId = id;
  writeRunMeta(id);

  const turnIndex = nextEntrySessionTurnIndex(sessionRow.id);
  const turn = recordEntrySessionTurn({
    sessionId: sessionRow.id,
    runId: id,
    turnIndex,
    lane: turnLane,
    promptSummary: prompt,
    stepId: resolvedStepId,
    status: "running"
  });
  const session = patchEntrySession(sessionRow.id, {
    run_id: id,
    status: "active",
    updated_at: ts,
    last_active_at: ts
  });
  const workspaceIdForHistory =
    session.workspace_id ||
    sessionRow.workspace_id ||
    ensureEntryWorkspaceRow(session.workspace_path, {
      name: path.basename(session.workspace_path),
      source: "entry_turn_workspace_backfill"
    })?.id ||
    null;
  for (const target of normalizedResolvedTargets) {
    touchEntryTargetFileHistory({
      workspaceId: workspaceIdForHistory,
      sessionId: session.id,
      relPath: target.rel_path,
      source: "entry_turn_resolved_target"
    });
  }

  emitEvent(id, "run.created", {
    title: runTitle,
    phase: "entry-turn-runtime",
    runtime_profile: runtimeProfile.id,
    session_id: session.id,
    turn_id: turn.id,
    turn_index: turn.turn_index,
    lane: turnLane,
    workspace_path: session.workspace_path,
    composer:
      rawPrompt || normalizedTokens.length > 0 || normalizedResolvedTargets.length > 0
        ? {
            raw_text: summarizeText(rawPrompt, 1200),
            token_count: normalizedTokens.length,
            resolved_target_count: normalizedResolvedTargets.length,
            intent_id: summarizeText(String(resolver?.intent?.id || ""), 96) || null
          }
        : null,
    classification:
      classification && typeof classification === "object"
        ? {
            lane: normalizeEntryTurnLane(classification.lane || turnLane),
            intent: summarizeText(String(classification.intent || ""), 96),
            mode: summarizeText(String(classification.mode || ""), 96),
            risk_level: summarizeText(String(classification.riskLevel || ""), 96)
          }
        : null
  });
  emitEvent(id, "step.requested", {
    step_id: resolvedStepId,
    session_id: session.id,
    turn_id: turn.id,
    turn_index: turn.turn_index,
    lane: turnLane,
    task_type: turnLane === "task" ? "entry_task" : "entry_chat",
    workspace_path: session.workspace_path
  });

  const userMessage = buildEntryTurnUserMessage(prompt, attachmentSpecs);
  emitEvent(id, "user.message", {
    step_id: resolvedStepId,
    session_id: session.id,
    turn_id: turn.id,
    turn_index: turn.turn_index,
    lane: turnLane,
    message: userMessage,
    raw_text: rawPrompt || null,
    token_count: normalizedTokens.length
  });

  let attachmentFailedCount = 0;
  for (const spec of attachmentSpecs) {
    const ingested = ingestAttachmentBufferForRun({
      runId: id,
      stepId: resolvedStepId,
      sessionId: session.id,
      sourceType: spec.sourceType,
      ingestChannel: spec.ingestChannel,
      originalName: spec.originalName,
      mimeType: spec.mimeType,
      buffer: spec.buffer,
      metadata: {
        entry_turn: true,
        lane: turnLane,
        turn_id: turn.id
      }
    });
    if (!ingested.ok) {
      attachmentFailedCount += 1;
      emitEvent(id, "attachment.ingest.failed", {
        step_id: resolvedStepId,
        session_id: session.id,
        turn_id: turn.id,
        source_type: spec.sourceType,
        original_name: spec.originalName,
        reason: ingested.error || "attachment_ingest_failed"
      });
    }
  }
  if (attachmentSpecs.length > 0) {
    emitEvent(id, "entry.turn.attachments.bound", {
      step_id: resolvedStepId,
      session_id: session.id,
      turn_id: turn.id,
      total: attachmentSpecs.length,
      failed: attachmentFailedCount
    });
  }

  setTimeout(() => {
    void executeEntryTurnRun(id, {
      sessionId: session.id,
      turnId: turn.id,
      turnIndex: turn.turn_index,
      lane: turnLane,
      promptText: prompt,
      workspacePath: session.workspace_path,
      stepId: resolvedStepId,
      resolver,
      resolvedTargets: normalizedResolvedTargets
    });
  }, 10);

  return {
    run: dbGet("SELECT id, title, status, created_at, updated_at, last_event_type FROM runs WHERE id = ?", id),
    session,
    turn,
    step_id: resolvedStepId
  };
}

function isOpenAiByoBound(statusPayload) {
  const bindingStatus = String(statusPayload?.binding?.status || "").toLowerCase();
  if (bindingStatus === "bound" || bindingStatus === "valid" || bindingStatus === "invalid") {
    return true;
  }
  if (bindingStatus === "unbound" || bindingStatus === "deleted" || bindingStatus === "revoked" || bindingStatus === "cleared") {
    return false;
  }
  const validationStatus = String(statusPayload?.validation?.validation_status || "").toLowerCase();
  if (validationStatus === "valid") {
    return true;
  }
  return false;
}

function buildEntryPreflightPayload() {
  const access = entryAccessStatusPayload();
  const byoStatus = buildByoStatusForProfile(BYO_DEFAULT_PROFILE_ID);
  const currentWorkspace = resolveCurrentEntryWorkspace();
  const selectedWorkspacePath =
    typeof currentWorkspace.workspace?.workspace_path === "string" && currentWorkspace.workspace.workspace_path.trim()
      ? currentWorkspace.workspace.workspace_path.trim()
      : null;
  const lastSession = selectedWorkspacePath ? latestEntrySession(selectedWorkspacePath) : null;
  return {
    host_connected: true,
    full_access_granted: access.full_access_granted,
    openai_byo_bound: isOpenAiByoBound(byoStatus),
    workspace_available: Boolean(currentWorkspace.workspace?.workspace_path && fs.existsSync(currentWorkspace.workspace.workspace_path)),
    selected_workspace: currentWorkspace.workspace
      ? {
          id: currentWorkspace.workspace.id,
          name: currentWorkspace.workspace.name,
          workspace_path: currentWorkspace.workspace.workspace_path
        }
      : { id: null, name: null, workspace_path: null },
    last_session_available: Boolean(lastSession),
    last_session: lastSession
      ? {
          id: lastSession.id,
          workspace_path: lastSession.workspace_path,
          run_id: lastSession.run_id,
          status: lastSession.status,
          updated_at: lastSession.updated_at
        }
      : { id: null, workspace_path: null, run_id: null, status: null, updated_at: null },
    contracts: {
      preflight: entryPreflightContract.version,
      workspace: entryWorkspaceContract.version,
      session: entrySessionContract.version,
      attachment: entryAttachmentContract.version,
      access: entryAccessContract.version,
      byo_openai: entryByoOpenAiContract.version
    }
  };
}

function createEntrySession({ workspaceRow, title = "Entry session" }) {
  if (!workspaceRow?.workspace_path) {
    return { error: "workspace_required" };
  }
  const run = createUtilityRun({
    title: `entry session ${title}`,
    phase: "entry-session-shell",
    stepId: "step.entry.session.requested",
    workspacePath: workspaceRow.workspace_path
  });
  finalizeRunSilently(run.id, "completed", "entry.session.initialized");
  const row = recordEntrySession({
    workspaceId: workspaceRow.id,
    workspacePath: workspaceRow.workspace_path,
    runId: run.id,
    title
  });
  return { session: row, run };
}

function currentRun() {
  if (activeRunId) {
    const hit = dbGet("SELECT id, status FROM runs WHERE id = ?", activeRunId);
    if (hit && ["running", "pending_approval"].includes(hit.status)) {
      return hit;
    }
    activeRunId = null;
  }
  const dbActive = dbGet(
    "SELECT id, status FROM runs WHERE status IN ('running', 'pending_approval') ORDER BY created_at DESC LIMIT 1"
  );
  if (dbActive) {
    activeRunId = dbActive.id;
    return dbActive;
  }
  return null;
}

function currentAuthSession() {
  if (activeAuthSessionId) {
    const hit = dbGet(
      "SELECT id, status FROM auth_sessions WHERE id = ?",
      activeAuthSessionId
    );
    if (hit && ACTIVE_AUTH_STATUSES.includes(hit.status)) {
      return hit;
    }
    activeAuthSessionId = null;
  }

  const sql = `SELECT id, status FROM auth_sessions WHERE status IN (${ACTIVE_AUTH_STATUSES.map(() => "?").join(",")}) ORDER BY created_at DESC LIMIT 1`;
  const dbActive = dbGet(sql, ...ACTIVE_AUTH_STATUSES);
  if (dbActive) {
    activeAuthSessionId = dbActive.id;
    return dbActive;
  }
  return null;
}

function runDir(runId) {
  return path.join(runsRoot, runId);
}

function writeRunMeta(runId) {
  const run = dbGet(
    "SELECT id, title, status, created_at, updated_at, last_event_type FROM runs WHERE id = ?",
    runId
  );
  if (!run) {
    return;
  }
  fs.mkdirSync(runDir(runId), { recursive: true });
  fs.writeFileSync(path.join(runDir(runId), "meta.json"), `${JSON.stringify(run, null, 2)}\n`, "utf8");
}

function nextRunStatus(oldStatus, eventType) {
  if (eventType === "step.completed") {
    return "completed";
  }
  if (eventType === "step.failed_controlled") {
    return "failed_controlled";
  }
  if (eventType === "step.failed") {
    return "failed";
  }
  if (eventType === "approval.pending.created" || eventType === "approval.pending.restored") {
    return "pending_approval";
  }
  if (eventType === "approval.continue.started") {
    return "running";
  }
  if (oldStatus === "pending_approval") {
    return "pending_approval";
  }
  if (oldStatus === "completed" || oldStatus === "failed" || oldStatus === "failed_controlled") {
    return oldStatus;
  }
  return "running";
}

function emitEvent(runId, type, payload) {
  const now = nowIso();
  const nextSeq = dbGet("SELECT COALESCE(MAX(seq), 0) + 1 AS n FROM events WHERE run_id = ?", runId).n;
  const frontendCheck = validateFrontendContractPayload(type, payload);
  const eventEnvelope = {
    event_id: `evt_${runId}_${nextSeq}`,
    run_id: runId,
    seq: nextSeq,
    type,
    ts: now,
    payload
  };
  if (frontendCheck.covered) {
    eventEnvelope.frontend_contract = {
      version: frontendEventContract.version,
      frozen_type: frontendCheck.frozen_type,
      valid: frontendCheck.valid,
      errors: frontendCheck.valid ? [] : frontendCheck.errors
    };
  }
  const displayEvent = projectRuntimeEventToDisplayEvent({
    seq: nextSeq,
    type,
    created_at: now,
    payload
  });
  if (displayEvent) {
    eventEnvelope.display_event = displayEvent;
    eventEnvelope.visibility = "projected_display";
  } else {
    eventEnvelope.visibility = "internal_only";
  }

  dbRun(
    "INSERT INTO events (run_id, seq, type, payload_json, created_at) VALUES (?, ?, ?, ?, ?)",
    runId,
    nextSeq,
    type,
    JSON.stringify(payload),
    now
  );

  const oldRun = dbGet("SELECT status FROM runs WHERE id = ?", runId);
  const status = nextRunStatus(oldRun?.status || "running", type);
  dbRun("UPDATE runs SET status = ?, updated_at = ?, last_event_type = ? WHERE id = ?", status, now, type, runId);

  if (["completed", "failed", "failed_controlled"].includes(status) && activeRunId === runId) {
    activeRunId = null;
  }

  fs.mkdirSync(runDir(runId), { recursive: true });
  fs.appendFileSync(path.join(runDir(runId), "events.ndjson"), `${JSON.stringify(eventEnvelope)}\n`, "utf8");
  writeRunMeta(runId);

  try {
    maybeEnsureWorkspaceBindingForEvent(runId, type, payload);
  } catch (error) {
    console.error(`[agent-host] workspace_binding_hook_error: ${error instanceof Error ? error.message : String(error)}`);
  }
  if (type === "step.requested") {
    try {
      maybeAssembleAutoContextForStep(runId, payload);
    } catch (error) {
      console.error(`[agent-host] autocontext_assemble_error: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  try {
    maybeAutoCompactRun(runId, type);
  } catch (error) {
    console.error(`[agent-host] auto_compact_error: ${error instanceof Error ? error.message : String(error)}`);
  }

  const frame = `data: ${JSON.stringify(eventEnvelope)}\n\n`;
  for (const client of sseClients) {
    try {
      client.write(frame);
    } catch {
      sseClients.delete(client);
    }
  }

  return eventEnvelope;
}

function patchAuthSession(authSessionId, patch) {
  const allowed = ["status", "timeout_at", "cancelled_at", "last_error_code"];
  const keys = Object.keys(patch).filter((k) => allowed.includes(k));
  if (keys.length === 0) {
    return;
  }
  const assigns = keys.map((k) => `${k} = ?`).join(", ");
  const args = keys.map((k) => patch[k]);
  args.push(nowIso(), authSessionId);
  dbRun(`UPDATE auth_sessions SET ${assigns}, updated_at = ? WHERE id = ?`, ...args);
}

function patchGrant(grantId, patch) {
  const allowed = ["status", "expires_at", "revoked_at", "revoke_reason"];
  const keys = Object.keys(patch).filter((k) => allowed.includes(k));
  if (keys.length === 0) {
    return;
  }
  const assigns = keys.map((k) => `${k} = ?`).join(", ");
  const args = keys.map((k) => patch[k]);
  args.push(nowIso(), grantId);
  dbRun(`UPDATE capability_grants SET ${assigns}, updated_at = ? WHERE id = ?`, ...args);
}

function normalizeFsPath(input) {
  const resolved = path
    .resolve(String(input || ""))
    .replace(/\\/g, "/")
    .replace(/\/+$/, "");
  if (process.platform === "win32") {
    return resolved.toLowerCase();
  }
  return resolved;
}

function isWithinWorkspace(targetPath, workspaceRootPath) {
  const target = normalizeFsPath(targetPath);
  const root = normalizeFsPath(workspaceRootPath);
  return target === root || target.startsWith(`${root}/`);
}

function assertWorkspacePath(targetPath, workspaceRootPath) {
  if (!isWithinWorkspace(targetPath, workspaceRootPath)) {
    throw new Error(`path_outside_workspace:${targetPath}`);
  }
}

function inferBoundaryRunContext(workspaceRootPath) {
  const row = dbGet(
    "SELECT run_id FROM workspace_root_bindings WHERE working_root = ? ORDER BY created_at DESC LIMIT 1",
    path.resolve(workspaceRootPath)
  );
  return row?.run_id || null;
}

function inferWorkspaceRootForPath(targetPath) {
  const abs = path.resolve(targetPath);
  const rows = dbAll("SELECT DISTINCT working_root FROM task_storage_roots ORDER BY LENGTH(working_root) DESC LIMIT 300");
  for (const row of rows) {
    const root = path.resolve(String(row.working_root || ""));
    if (isWithinWorkspace(abs, root)) {
      return root;
    }
  }
  return null;
}

function recordBoundaryCheck({
  workspaceRootPath,
  targetPath,
  checkType,
  runId = null,
  stepId = null,
  caseId = null,
  evaluatedResult = null
}) {
  const targetAbs = path.resolve(typeof targetPath === "string" && targetPath.trim() ? targetPath : workspaceRootPath);
  const forbidden = Array.isArray(workspaceRootBindingContract?.forbidden_subpaths)
    ? workspaceRootBindingContract.forbidden_subpaths
    : [];
  const result =
    evaluatedResult && typeof evaluatedResult === "object"
      ? evaluatedResult
      : evaluateBoundaryPathWithGuard({
          workspaceRoot: path.resolve(workspaceRootPath),
          targetPath: targetAbs,
          forbiddenSubpaths: forbidden
        });
  const boundRunId = typeof runId === "string" && runId.trim() ? runId.trim() : inferBoundaryRunContext(workspaceRootPath);
  if (boundRunId) {
    const row = recordPathJailCheck({
      runId: boundRunId,
      pathChecked: targetAbs,
      checkType: checkType || result.checkType || "path_access",
      policyStatus: result.status || (result.approved ? "approved" : "rejected"),
      rejectReason: result.approved ? null : result.reason || "path_rejected",
      createdAt: nowIso()
    });
    emitEvent(boundRunId, "path.jail.checked", {
      step_id: stepId || "step.boundary.guard",
      case_id: caseId || "boundary_guard",
      path_jail_check_id: row.id,
      path_checked: row.path_checked,
      policy_status: row.policy_status,
      reject_reason: row.reject_reason
    });
  }
  return result;
}

function isForbiddenFilePath(targetPath) {
  const target = normalizeFsPath(targetPath).toLowerCase();
  for (const forbidden of fileAdapterContract?.forbidden_paths || []) {
    const f = normalizeFsPath(forbidden).toLowerCase();
    if (target === f || target.startsWith(`${f}/`)) {
      return true;
    }
  }
  return false;
}

function textHash(input) {
  return crypto.createHash("sha256").update(String(input || "")).digest("hex");
}

function summarizeText(input, maxLen = 512) {
  const clean = redactSensitiveText(String(input || "")).replace(/\s+/g, " ").trim();
  if (clean.length <= maxLen) {
    return clean;
  }
  return `${clean.slice(0, maxLen)}...`;
}

function promptRuntimeSnapshot(runId, promptPhase, promptContext = null) {
  const snapshot = {
    run_id: typeof runId === "string" && runId.trim() ? runId.trim() : null,
    phase: summarizeText(promptPhase || "generic", 96),
    generated_at: nowIso(),
    source_of_truth: ["runs", "events", "auth_sessions", "capability_grants"]
  };
  if (!snapshot.run_id) {
    return { ...snapshot, run_status: "not_bound", auth_status: null, capability_grants: [] };
  }
  const runRow = dbGet("SELECT id, status, last_event_type, updated_at FROM runs WHERE id = ?", snapshot.run_id);
  const authRow = dbGet(
    "SELECT id, status, mode, required_capability, selected_recipe_id, selected_verifier_id, updated_at FROM auth_sessions WHERE run_id = ? ORDER BY updated_at DESC LIMIT 1",
    snapshot.run_id
  );
  const grantRows = dbAll(
    "SELECT capability_key, status, scope_type, scope_value, expires_at FROM capability_grants WHERE run_id = ? ORDER BY verified_at DESC LIMIT 5",
    snapshot.run_id
  );
  return {
    ...snapshot,
    run_status: runRow?.status || "unknown",
    last_event_type: runRow?.last_event_type || null,
    run_updated_at: runRow?.updated_at || null,
    auth_status: authRow
      ? {
          id: authRow.id,
          status: authRow.status,
          mode: authRow.mode,
          required_capability: authRow.required_capability,
          selected_recipe_id: authRow.selected_recipe_id,
          selected_verifier_id: authRow.selected_verifier_id,
          updated_at: authRow.updated_at
        }
      : null,
    capability_grants: grantRows.map((row) => ({
      capability_key: row.capability_key,
      status: row.status,
      scope_type: row.scope_type,
      scope_value: summarizeText(row.scope_value || "", 180),
      expires_at: row.expires_at || null
    })),
    prompt_context: promptContext && typeof promptContext === "object" ? promptContext : null
  };
}

function loadAgentsInstructionBodies(workingRoot) {
  const discovery = discoverAgentsResolution(workingRoot);
  const chain = [];
  for (const src of discovery.active_instruction_sources || []) {
    const abs = path.resolve(repoRoot, src.path);
    if (!fs.existsSync(abs)) {
      continue;
    }
    const body = fs.readFileSync(abs, "utf8");
    chain.push({
      path: src.path,
      scope: src.scope,
      precedence: src.precedence,
      status: src.status,
      instruction_text: summarizeText(body, 6000)
    });
  }
  return {
    discovery,
    chain
  };
}

function loadSelectedSkillInstructions(skillIds = []) {
  const selected = [];
  for (const id of Array.isArray(skillIds) ? skillIds : []) {
    const skillId = String(id || "").trim();
    if (!skillId) {
      continue;
    }
    const skillFile = path.join(repoSkillsRoot, skillId, "SKILL.md");
    if (!fs.existsSync(skillFile)) {
      continue;
    }
    const text = fs.readFileSync(skillFile, "utf8");
    selected.push({
      skill_id: skillId,
      path: toRepoRelative(skillFile),
      instruction_text: summarizeText(text, 5000)
    });
  }
  return selected;
}

function buildPromptAssembly({
  runId = null,
  systemPrompt = "",
  userPrompt = "",
  promptPhase = "generic",
  promptContext = null,
  skillInput = {},
  workingRoot = null
}) {
  const effectiveWorkingRoot =
    typeof workingRoot === "string" && workingRoot.trim()
      ? workingRoot.trim()
      : typeof promptContext?.working_root === "string" && promptContext.working_root.trim()
        ? promptContext.working_root.trim()
        : repoRoot;
  const runtimeSnapshot = promptRuntimeSnapshot(runId, promptPhase, promptContext);
  const agentsPayload = loadAgentsInstructionBodies(effectiveWorkingRoot);
  const skillResolutionInputs = {
    ...(skillInput && typeof skillInput === "object" ? skillInput : {}),
    prompt: userPrompt,
    user_prompt: userPrompt,
    working_root: effectiveWorkingRoot,
    run_id: runId
  };
  const skillResolution = resolveRepoSkills(skillResolutionInputs);
  const selectedSkillBodies = loadSelectedSkillInstructions(skillResolution.selected_skills);
  const instructionSources = [
    {
      source_type: "prompt_contract",
      path: promptContractRelativePath,
      bytes: Buffer.byteLength(promptContractText, "utf8")
    },
    ...agentsPayload.chain.map((x) => ({
      source_type: "agents",
      path: x.path,
      scope: x.scope,
      precedence: x.precedence
    })),
    ...selectedSkillBodies.map((x) => ({
      source_type: "skill",
      skill_id: x.skill_id,
      path: x.path
    })),
    {
      source_type: "runtime_snapshot",
      fields: Object.keys(runtimeSnapshot || {})
    }
  ];

  const rawAssembled = [
    "### LITECODEX STATIC PROMPT CONTRACT (v1)",
    promptContractText,
    "### AGENTS INSTRUCTION CHAIN (root -> subdir precedence resolved)",
    agentsPayload.chain.length
      ? agentsPayload.chain
          .map(
            (x) =>
              `#### ${x.path}\n(scope=${x.scope}; precedence=${x.precedence})\n${String(x.instruction_text || "").trim()}`
          )
          .join("\n\n")
      : "no_active_agents_instructions",
    "### REPO SKILL RESOLUTION",
    JSON.stringify(
      {
        selected_skills: skillResolution.selected_skills,
        reasons: skillResolution.reasons,
        unresolved_skills: skillResolution.unresolved_skills,
        no_match_reason: skillResolution.no_match_reason
      },
      null,
      2
    ),
    "### SELECTED SKILL INSTRUCTIONS",
    selectedSkillBodies.length
      ? selectedSkillBodies.map((x) => `#### ${x.skill_id}\n${String(x.instruction_text || "").trim()}`).join("\n\n")
      : "no_selected_skill_instructions",
    "### RUNTIME SNAPSHOT (dynamic, do not persist back into static layers)",
    JSON.stringify(runtimeSnapshot, null, 2),
    "### TASK-SPECIFIC SYSTEM PROMPT",
    String(systemPrompt || "")
  ].join("\n\n");

  const assembledPrompt = redactSensitiveText(rawAssembled);
  const redactionResult = {
    redaction_applied: assembledPrompt !== rawAssembled,
    raw_sha256: textHash(rawAssembled),
    redacted_sha256: textHash(assembledPrompt),
    raw_bytes: Buffer.byteLength(rawAssembled, "utf8"),
    redacted_bytes: Buffer.byteLength(assembledPrompt, "utf8")
  };
  return {
    assembled_prompt: assembledPrompt,
    proof: {
      instruction_sources: instructionSources,
      agents_chain: agentsPayload.discovery.discovered_sources,
      active_agents_chain: agentsPayload.discovery.active_instruction_sources,
      skill_resolution_inputs: {
        required_capability: String(skillResolutionInputs.required_capability || ""),
        auth_mode: String(skillResolutionInputs.auth_mode || skillResolutionInputs.mode || ""),
        requested_action: String(skillResolutionInputs.requested_action || ""),
        task_type: String(skillResolutionInputs.task_type || ""),
        prompt_excerpt: summarizeText(userPrompt || "", 240)
      },
      selected_skills: skillResolution.selected_skills,
      dynamic_snapshot_fields: Object.keys(runtimeSnapshot || {}),
      redaction_result: redactionResult,
      working_root: agentsPayload.discovery.effective_working_root,
      path_policy_status: agentsPayload.discovery.path_policy_status
    }
  };
}

function composeSystemPromptWithContract({
  systemPrompt,
  userPrompt = "",
  runId = null,
  promptPhase = "generic",
  promptContext = null,
  skillInput = {},
  workingRoot = null,
  persistReceipt = true
}) {
  if (runId && persistReceipt) {
    emitRunEventIfExists(runId, "prompt.assembly.started", {
      prompt_phase: promptPhase,
      source: "model_call"
    });
  }
  const assembly = buildPromptAssembly({
    runId,
    systemPrompt,
    userPrompt,
    promptPhase,
    promptContext,
    skillInput,
    workingRoot
  });
  if (runId && persistReceipt) {
    const receiptPathAbs = writeRunArtifact(
      runId,
      `prompt_assembly_${Date.now()}.json`,
      `${JSON.stringify(
        {
          run_id: runId,
          prompt_phase: promptPhase,
          proof: assembly.proof,
          assembled_prompt_preview: summarizeText(assembly.assembled_prompt, 1500)
        },
        null,
        2
      )}\n`,
      200 * 1024
    );
    const receipt = {
      run_id: runId,
      prompt_phase: promptPhase,
      receipt_path: toRepoRelative(receiptPathAbs),
      generated_at: nowIso(),
      proof: assembly.proof
    };
    promptAssemblyReceiptMemory.set(runId, receipt);
    emitRunEventIfExists(runId, "prompt.assembly.completed", {
      prompt_phase: promptPhase,
      source: "model_call",
      receipt_path: receipt.receipt_path,
      instruction_source_count: Array.isArray(assembly.proof?.instruction_sources)
        ? assembly.proof.instruction_sources.length
        : 0
    });
  }
  return assembly.assembled_prompt;
}

function extractMarkdownSection(text, heading) {
  const raw = String(text || "");
  const title = String(heading || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const re = new RegExp(`^##\\s*${title}\\s*$([\\s\\S]*?)(?=^##\\s+|\\Z)`, "im");
  const match = raw.match(re);
  if (!match) {
    return "";
  }
  return summarizeText(match[1].replace(/^\n+/, "").trim(), 1200);
}

function discoverRepoSkills() {
  if (!fs.existsSync(repoSkillsRoot)) {
    return [];
  }
  const skills = [];
  for (const entry of fs.readdirSync(repoSkillsRoot, { withFileTypes: true })) {
    if (!entry.isDirectory()) {
      continue;
    }
    const skillId = entry.name;
    const skillDoc = path.join(repoSkillsRoot, skillId, "SKILL.md");
    if (!fs.existsSync(skillDoc)) {
      continue;
    }
    const body = fs.readFileSync(skillDoc, "utf8");
    skills.push({
      skill_id: skillId,
      path: toRepoRelative(skillDoc),
      description: extractMarkdownSection(body, "description"),
      when_to_use: extractMarkdownSection(body, "when_to_use"),
      when_not_to_use: extractMarkdownSection(body, "when_not_to_use"),
      required_inputs: extractMarkdownSection(body, "required_inputs"),
      supported: skillsCatalogSet.size === 0 ? true : skillsCatalogSet.has(skillId)
    });
  }
  return skills.sort((a, b) => a.skill_id.localeCompare(b.skill_id));
}

function resolveRepoSkills(input = {}) {
  const requiredCapability = String(input.required_capability || "").trim();
  const authMode = String(input.auth_mode || input.mode || "").trim();
  const requestedAction = String(input.requested_action || "").trim().toLowerCase();
  const taskType = String(input.task_type || "").trim().toLowerCase();
  const promptText = String(input.prompt || input.user_prompt || input.query || "").trim().toLowerCase();
  const intentText = [requestedAction, taskType, promptText].filter(Boolean).join(" ");
  const selected = new Set();
  const reasons = [];
  const trace = [];

  const hasInstallMissingSignal = /\b(install|missing|not found|cannot find|toolchain|enoent|command not found)\b/i.test(
    intentText
  );
  const hasAuthIntentSignal = /\b(auth|oauth|login|token|grant|permission|re-auth|reauth)\b/i.test(intentText);
  const hasDeploySignal = /\bdeploy|release|publish\b/i.test(intentText);
  const hasVerifyRepairSignal = /\bverify|verification|repair|fix|retry|lint|typecheck|test\b/i.test(intentText);
  const hasWorkspaceSignal = /\bworkspace|bootstrap|init root|task root\b/i.test(intentText);

  if (requiredCapability) {
    selected.add("capability-probe");
    selected.add("auth-broker-dispatch");
    reasons.push("required_capability_present");
    trace.push("required_capability=>capability-probe+auth-broker-dispatch");
  }
  if (authMode === "browser_oauth") {
    selected.add("auth-browser-oauth");
    reasons.push("auth_mode_browser_oauth");
    trace.push("auth_mode_browser_oauth=>auth-browser-oauth");
  } else if (authMode === "cli_login") {
    selected.add("auth-cli-login");
    reasons.push("auth_mode_cli_login");
    trace.push("auth_mode_cli_login=>auth-cli-login");
  } else if (authMode === "token_input") {
    selected.add("auth-token-session");
    reasons.push("auth_mode_token_input");
    trace.push("auth_mode_token_input=>auth-token-session");
  }
  if (!requiredCapability && !authMode && hasAuthIntentSignal && !hasInstallMissingSignal) {
    selected.add("auth-broker-dispatch");
    reasons.push("auth_intent_detected");
    trace.push("auth_intent_detected=>auth-broker-dispatch");
  }
  if (hasWorkspaceSignal || requestedAction.includes("workspace") || taskType.includes("workspace")) {
    selected.add("workspace-bootstrap");
    reasons.push("workspace_bootstrap_required");
    trace.push("workspace_signal=>workspace-bootstrap");
  }
  if (hasVerifyRepairSignal || requestedAction.includes("verify") || requestedAction.includes("repair") || taskType.includes("repair")) {
    selected.add("verify-and-repair");
    reasons.push("verify_or_repair_requested");
    trace.push("verify_or_repair_signal=>verify-and-repair");
  }
  if (hasInstallMissingSignal) {
    selected.add("verify-and-repair");
    reasons.push("install_or_missing_tool_signal");
    trace.push("install_or_missing_tool_signal=>verify-and-repair");
  }
  if (hasDeploySignal || requestedAction.includes("deploy") || taskType.includes("deploy")) {
    selected.add("deploy-with-proof");
    selected.add("verify-and-repair");
    reasons.push("deploy_with_proof_required");
    trace.push("deploy_signal=>deploy-with-proof+verify-and-repair");
  }
  if (selected.size === 0 && !hasInstallMissingSignal) {
    selected.add("workspace-bootstrap");
    reasons.push("default_workspace_bootstrap");
    trace.push("no_specific_match=>workspace-bootstrap");
  }

  const available = discoverRepoSkills();
  const availableSet = new Set(available.map((x) => x.skill_id));
  const finalSelection = Array.from(selected).filter((skillId) => availableSet.has(skillId));
  const noMatchReason =
    finalSelection.length === 0
      ? hasInstallMissingSignal
        ? "install_or_missing_tool_not_auth_route"
        : "no_skill_matched"
      : null;
  return {
    selected_skills: finalSelection,
    reasons: Array.from(new Set(reasons)),
    unresolved_skills: Array.from(selected).filter((skillId) => !availableSet.has(skillId)),
    available_skills: available,
    no_match_reason: noMatchReason,
    resolution_trace: trace
  };
}

const AGENTS_FILE_MAX_BYTES = 128 * 1024;

function classifyAgentsFile(absPath) {
  const size = fs.statSync(absPath).size;
  if (size === 0) {
    return { sizeBytes: size, status: "empty_file", warning: "agents_file_empty" };
  }
  if (size > AGENTS_FILE_MAX_BYTES) {
    return { sizeBytes: size, status: "oversize_ignored", warning: "agents_file_too_large" };
  }
  return { sizeBytes: size, status: "active", warning: null };
}

function discoverAgentsResolution(inputWorkingRoot = null) {
  const requestedRoot = path.resolve(
    typeof inputWorkingRoot === "string" && inputWorkingRoot.trim() ? inputWorkingRoot.trim() : repoRoot
  );
  const repoAbs = path.resolve(repoRoot);
  const pathAllowed = isWithinWorkspace(requestedRoot, repoAbs);
  const effectiveRoot = pathAllowed ? requestedRoot : repoAbs;
  const chain = [];
  const warnings = [];
  let cursor = effectiveRoot;
  let precedence = 0;
  while (true) {
    const file = path.join(cursor, "AGENTS.md");
    if (fs.existsSync(file)) {
      const cls = classifyAgentsFile(file);
      chain.push({
        path: toRepoRelative(file),
        size_bytes: cls.sizeBytes,
        status: cls.status,
        warning: cls.warning,
        precedence,
        scope: cursor === repoAbs ? "repo_root" : "subdir_override",
        applies_to: toRepoRelative(cursor)
      });
      if (cls.warning) {
        warnings.push({
          path: toRepoRelative(file),
          warning: cls.warning
        });
      }
    }
    if (cursor === repoAbs) {
      break;
    }
    const parent = path.dirname(cursor);
    if (parent === cursor || !isWithinWorkspace(parent, repoAbs)) {
      break;
    }
    cursor = parent;
    precedence += 1;
  }
  return {
    requested_working_root: requestedRoot,
    effective_working_root: effectiveRoot,
    path_policy_status: pathAllowed ? "allowed" : "outside_repo_rejected",
    active_instruction_sources: chain.filter((x) => x.status === "active"),
    discovered_sources: chain,
    warnings,
    count: chain.length
  };
}

function discoverAgentsFiles(inputWorkingRoot = null) {
  return discoverAgentsResolution(inputWorkingRoot).discovered_sources.map((x) => ({
    path: x.path,
    size_bytes: x.size_bytes
  }));
}

function normalizeExitCode(value) {
  if (value === null || value === undefined || value === "") {
    return null;
  }
  const n = Number(value);
  if (!Number.isFinite(n)) {
    return null;
  }
  return Math.trunc(n);
}

function pickCommandExitCode(result) {
  if (!result || typeof result !== "object") {
    return null;
  }
  // Support SDK result variants without treating 0 as falsy.
  const raw = result.exitCode ?? result.exit_code ?? result.code ?? null;
  return normalizeExitCode(raw);
}

function artifactPath(runId, relativeName) {
  const safe = String(relativeName || "").replace(/\\/g, "/").replace(/^\/+/, "");
  return path.join(runDir(runId), "artifacts", safe);
}

function writeRunArtifact(runId, relativeName, content, maxBytes = 65536) {
  const target = artifactPath(runId, relativeName);
  fs.mkdirSync(path.dirname(target), { recursive: true });
  const text = redactSensitiveText(String(content || ""));
  const bytes = Buffer.byteLength(text, "utf8");
  let out = text;
  if (bytes > maxBytes) {
    out = `${text.slice(0, maxBytes)}\n[TRUNCATED ${bytes - maxBytes} BYTES]\n`;
  }
  fs.writeFileSync(target, out, "utf8");
  return target;
}

function recordAdapterRun({
  runId,
  adapterId,
  commandOrAction,
  cwd,
  status,
  startedAt,
  completedAt,
  exitCode,
  stdoutSummary,
  stderrSummary
}) {
  const id = shortId("arun");
  dbRun(
    `INSERT INTO adapter_runs (
      id, run_id, adapter_id, command_or_action, cwd, status, started_at, completed_at, exit_code, stdout_summary, stderr_summary
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    id,
    runId,
    adapterId,
    commandOrAction,
    cwd || null,
    status,
    startedAt || nowIso(),
    completedAt || null,
    normalizeExitCode(exitCode),
    summarizeText(stdoutSummary || ""),
    summarizeText(stderrSummary || "")
  );
  return dbGet("SELECT * FROM adapter_runs WHERE id = ?", id);
}

