function patchRepairDecision(decisionId, patch) {
  const allowed = [
    "applied_at",
    "status",
    "reason",
    "planner_confidence",
    "candidate_files_json",
    "patch_proposal_id",
    "policy_status"
  ];
  const keys = Object.keys(patch || {}).filter((k) => allowed.includes(k));
  if (keys.length === 0) {
    return;
  }
  const assigns = keys.map((k) => `${k} = ?`).join(", ");
  const args = keys.map((k) => {
    if (k === "reason") {
      return summarizeText(patch[k] || "");
    }
    if (k === "planner_confidence") {
      return Number.isFinite(Number(patch[k])) ? Number(patch[k]) : null;
    }
    return patch[k];
  });
  args.push(decisionId);
  dbRun(`UPDATE repair_decisions SET ${assigns} WHERE id = ?`, ...args);
}

