function patchResumeSession(resumeSessionId, patch) {
  const allowed = [
    "status_before_resume",
    "resumable",
    "resume_reason",
    "resume_cursor",
    "status",
    "completed_at"
  ];
  const keys = Object.keys(patch || {}).filter((k) => allowed.includes(k));
  if (keys.length === 0) {
    return;
  }
  const assigns = keys.map((k) => `${k} = ?`).join(", ");
  const args = keys.map((k) => {
    if (k === "resume_reason") {
      return summarizeText(patch[k] || "");
    }
    if (k === "resumable") {
      return patch[k] ? 1 : 0;
    }
    return patch[k];
  });
  args.push(resumeSessionId);
  dbRun(`UPDATE resume_sessions SET ${assigns} WHERE id = ?`, ...args);
}

