const attachmentIngestor = createAttachmentIngestor({
  db,
  repoRoot,
  runsRoot,
  nowIso,
  shortId,
  getTaskStorageRootForRun: latestTaskStorageRootForRun
});

function emitAttachmentIngested(runId, attachment, manifest, extra = {}) {
  emitEvent(runId, "attachment.ingested", {
    run_id: runId,
    attachment_id: attachment.id,
    step_id: attachment.step_id,
    session_id: attachment.session_id,
    manifest_id: manifest.id,
    manifest_path: manifest.manifest_path,
    source_type: attachment.source_type,
    ingest_channel: attachment.ingest_channel,
    mime_type: attachment.mime_type,
    artifact_path: attachment.artifact_path,
    content_hash: attachment.content_hash,
    size_bytes: attachment.size_bytes,
    ...extra
  });
}

function ingestAttachmentBufferForRun({
  runId,
  stepId = null,
  sessionId = null,
  sourceType,
  ingestChannel,
  originalName = null,
  mimeType = null,
  buffer,
  metadata = {}
}) {
  const ingested = attachmentIngestor.ingestBuffer({
    runId,
    stepId,
    sessionId,
    sourceType,
    ingestChannel,
    originalName,
    mimeType,
    buffer,
    metadata
  });
  if (!ingested.ok) {
    return ingested;
  }
  emitAttachmentIngested(runId, ingested.attachment, ingested.manifest, {
    attachment_manifest_version: attachmentManifestContract.version
  });
  return ingested;
}

