function patchDeployRun(id, patch) {
  const allowed = [
    "provider",
    "deploy_mode",
    "command_summary",
    "auth_status",
    "deploy_status",
    "release_url_redacted",
    "receipt_path",
    "completed_at"
  ];
  const keys = Object.keys(patch || {}).filter((k) => allowed.includes(k));
  if (keys.length === 0) {
    return dbGet("SELECT * FROM deploy_runs WHERE id = ?", id);
  }
  const assigns = keys.map((k) => `${k} = ?`).join(", ");
  const args = keys.map((k) => patch[k]);
  args.push(id);
  dbRun(`UPDATE deploy_runs SET ${assigns} WHERE id = ?`, ...args);
  return dbGet("SELECT * FROM deploy_runs WHERE id = ?", id);
}

