function phase4bCasePlan(inputCaseId) {
  const caseId = String(inputCaseId || "case1_manual_compact_completed_run");
  const threshold = parsePositiveInt(compactPolicyContract?.event_count_threshold, 12);
  const base = {
    caseId,
    maxAttempts: 2,
    timeoutMs: parsePositiveInt(verifyLoopContract.timeout_ms, 3000),
    expectedStatus: "completed",
    scenario: "manual_compact_completed_run",
    eventBurst: 6
  };
  if (caseId === "case2_auto_compact_event_threshold") {
    return {
      ...base,
      scenario: "auto_compact_event_threshold",
      eventBurst: threshold + 8
    };
  }
  if (caseId === "case3_compact_reconnect_missed_events") {
    return {
      ...base,
      scenario: "compact_reconnect_missed_events",
      eventBurst: threshold + 10
    };
  }
  if (caseId === "case4_compact_active_run_resume") {
    return {
      ...base,
      scenario: "compact_active_run_resume",
      expectedStatus: "running",
      eventBurst: threshold + 4
    };
  }
  if (caseId === "case5_stale_running_seed") {
    return {
      ...base,
      scenario: "stale_running_seed",
      expectedStatus: "running",
      eventBurst: 4
    };
  }
  if (caseId === "case6_corrupt_compact_artifact_seed") {
    return {
      ...base,
      scenario: "corrupt_compact_artifact_seed",
      eventBurst: 8
    };
  }
  return base;
}

function emitPhase4bBurst(runId, stepId, caseId, workspacePath, count) {
  for (let i = 1; i <= count; i += 1) {
    const cmd = `echo phase4b-${caseId}-${i}`;
    emitEvent(runId, "shell.command.started", {
      step_id: stepId,
      case_id: caseId,
      command: cmd,
      cwd: workspacePath
    });
    emitEvent(runId, "shell.command.completed", {
      step_id: stepId,
      case_id: caseId,
      command: cmd,
      cwd: workspacePath,
      exit_code: 0,
      stdout_summary: `phase4b-${caseId}-${i}`,
      stderr_summary: ""
    });
  }
}

function executePhase4bRun(runId, plan) {
  const stepId = plan.stepId || "step.phase4b.compact-stale-recovery";
  const casePlan = phase4bCasePlan(plan.caseId);
  const workspacePath = sanitizeWorkspacePath(plan.workspacePath || phase4bFixtureRoot);
  emitEvent(runId, "step.requested", {
    step_id: stepId,
    required_capability: "local.verify.run",
    workspace_path: workspacePath,
    case_id: casePlan.caseId,
    max_attempts: casePlan.maxAttempts,
    timeout_ms: casePlan.timeoutMs
  });

  try {
    emitEvent(runId, "verify.started", {
      step_id: stepId,
      case_id: casePlan.caseId,
      attempt: 1,
      current_attempt: 1,
      max_attempts: casePlan.maxAttempts,
      command: "node test/run-all.test.js",
      cwd: workspacePath,
      timeout_ms: casePlan.timeoutMs
    });
    emitPhase4bBurst(runId, stepId, casePlan.caseId, workspacePath, parsePositiveInt(casePlan.eventBurst, 6));

    if (casePlan.scenario === "compact_active_run_resume") {
      const marker = dbGet(
        "SELECT * FROM resume_sessions WHERE run_id = ? AND status IN ('awaiting_resume','started') ORDER BY created_at DESC LIMIT 1",
        runId
      );
      const lastSeq = Number(dbGet("SELECT COALESCE(MAX(seq), 0) AS n FROM events WHERE run_id = ?", runId)?.n || 0);
      if (marker) {
        patchResumeSession(marker.id, {
          status_before_resume: "running",
          resumable: true,
          resume_reason: "phase4b_active_resume_seed",
          resume_cursor: lastSeq,
          status: "awaiting_resume",
          completed_at: null
        });
      } else {
        recordResumeSession({
          runId,
          statusBeforeResume: "running",
          resumable: true,
          resumeReason: "phase4b_active_resume_seed",
          resumeCursor: lastSeq,
          status: "awaiting_resume",
          createdAt: nowIso(),
          completedAt: null
        });
      }
      emitEvent(runId, "replay.evidence.written", {
        step_id: stepId,
        case_id: casePlan.caseId,
        replay_artifact_path: null,
        message: "phase4b active run seeded awaiting resume"
      });
      return;
    }

    if (casePlan.scenario === "stale_running_seed") {
      const staleTs = new Date(Date.now() - Math.max(2 * parsePositiveInt(staleRunningRecoveryContract?.heartbeat_timeout_ms, 60000), 120000)).toISOString();
      dbRun("UPDATE runs SET updated_at = ? WHERE id = ?", staleTs, runId);
      emitEvent(runId, "replay.evidence.written", {
        step_id: stepId,
        case_id: casePlan.caseId,
        replay_artifact_path: null,
        message: "phase4b stale running seed prepared"
      });
      return;
    }

    emitEvent(runId, "verify.passed", {
      step_id: stepId,
      case_id: casePlan.caseId,
      attempt: 1,
      exit_code: 0,
      stdout_summary: `phase4b ${casePlan.caseId} verify passed`,
      stderr_summary: ""
    });
    emitEvent(runId, "step.completed", {
      step_id: stepId,
      case_id: casePlan.caseId,
      message: `phase4b ${casePlan.caseId} completed`
    });
  } catch (error) {
    emitEvent(runId, "step.failed", {
      step_id: stepId,
      case_id: casePlan.caseId,
      reason: error instanceof Error ? error.message : String(error)
    });
  }
}

