function phase4cSourceCasePlan(inputCaseId) {
  const caseId = String(inputCaseId || "source_completed");
  if (caseId === "source_failed_controlled") {
    return {
      caseId,
      scenario: "failed_controlled",
      expectedStatus: "failed_controlled",
      eventBurst: 4
    };
  }
  if (caseId === "source_compacted_seed") {
    return {
      caseId,
      scenario: "completed_burst",
      expectedStatus: "completed",
      eventBurst: parsePositiveInt(compactPolicyContract?.event_count_threshold, 12) + 6
    };
  }
  return {
    caseId: "source_completed",
    scenario: "completed",
    expectedStatus: "completed",
    eventBurst: 4
  };
}

