function systemAcceptanceRequiredCheckpoints() {
  const fromContract = Array.isArray(systemAcceptanceRegressionContract?.required_checkpoints)
    ? systemAcceptanceRegressionContract.required_checkpoints
    : [];
  if (fromContract.length > 0) {
    return new Set(fromContract.map((x) => String(x || "").trim()).filter(Boolean));
  }
  return new Set([
    "checkpoint1_workspace_root_and_task_root",
    "checkpoint2_openai_byo_exact_validation",
    "checkpoint3_retrieval_decision",
    "checkpoint4_local_code_eval_fix_verify",
    "checkpoint8_real_deploy_closeout",
    "checkpoint9_online_verification",
    "checkpoint10_final_system_acceptance_readiness"
  ]);
}

function systemAcceptanceOptionalCheckpoints() {
  const fromContract = Array.isArray(systemAcceptanceRegressionContract?.optional_checkpoints)
    ? systemAcceptanceRegressionContract.optional_checkpoints
    : [];
  if (fromContract.length > 0) {
    return new Set(fromContract.map((x) => String(x || "").trim()).filter(Boolean));
  }
  return new Set([
    "checkpoint5_approval_pending_same_run_continue",
    "checkpoint6_browser_readonly_verification",
    "checkpoint7_e2b_second_lane_writeback"
  ]);
}

function systemAcceptanceChain() {
  const fromContract = Array.isArray(systemAcceptanceContract?.acceptance_chain)
    ? systemAcceptanceContract.acceptance_chain
    : [];
  if (fromContract.length > 0) {
    return fromContract.map((x) => String(x || "").trim()).filter(Boolean);
  }
  return [
    "checkpoint1_workspace_root_and_task_root",
    "checkpoint2_openai_byo_exact_validation",
    "checkpoint3_retrieval_decision",
    "checkpoint4_local_code_eval_fix_verify",
    "checkpoint5_approval_pending_same_run_continue",
    "checkpoint6_browser_readonly_verification",
    "checkpoint7_e2b_second_lane_writeback",
    "checkpoint8_real_deploy_closeout",
    "checkpoint9_online_verification",
    "checkpoint10_final_system_acceptance_readiness"
  ];
}

async function executeSystemAcceptanceCloseout(runId, plan) {
  const stepId =
    typeof plan.stepId === "string" && plan.stepId.trim()
      ? plan.stepId.trim()
      : "step.system.acceptance.closeout";
  const storyId =
    typeof plan.storyId === "string" && plan.storyId.trim()
      ? plan.storyId.trim()
      : String(systemAcceptanceRegressionContract?.selected_story || "global_system_acceptance_chain_v1");
  const chain = systemAcceptanceChain();
  const requiredSet = systemAcceptanceRequiredCheckpoints();
  const optionalSet = systemAcceptanceOptionalCheckpoints();
  const checkpoints = [];
  const exercisedModules = new Set();
  const nonBlockingIssues = [];
  const deferredItems = [];
  let uniqueBlocker = null;

  function markCheckpoint(checkpointId, status, payload = {}) {
    const id = String(checkpointId || "").trim();
    const row = {
      checkpoint_id: id,
      status: String(status || "unknown"),
      ts: nowIso(),
      details: payload || {}
    };
    checkpoints.push(row);
    emitEvent(runId, "acceptance.chain.checkpoint.completed", {
      step_id: stepId,
      story_id: storyId,
      checkpoint_id: id,
      status: row.status,
      required: requiredSet.has(id),
      optional: optionalSet.has(id),
      ...payload
    });

    const modules = Array.isArray(payload?.exercised_modules) ? payload.exercised_modules : [];
    for (const m of modules) {
      const clean = String(m || "").trim();
      if (clean) exercisedModules.add(clean);
    }

    if (optionalSet.has(id) && row.status === "not_needed_for_this_story") {
      deferredItems.push({
        checkpoint_id: id,
        reason: payload?.reason || "not_needed_for_this_story"
      });
    } else if (optionalSet.has(id) && row.status.startsWith("failed")) {
      nonBlockingIssues.push({
        checkpoint_id: id,
        reason: payload?.reason || "optional_checkpoint_failed"
      });
    }

    if (requiredSet.has(id) && row.status !== "completed" && !uniqueBlocker) {
      uniqueBlocker = payload?.reason || `${id}_failed`;
    }
  }

  emitEvent(runId, "step.requested", {
    step_id: stepId,
    story_id: storyId,
    acceptance_chain: chain
  });

  emitEvent(runId, "acceptance.chain.started", {
    step_id: stepId,
    story_id: storyId,
    acceptance_chain: chain,
    required_checkpoints: [...requiredSet],
    optional_checkpoints: [...optionalSet]
  });

  let workingRoot = null;
  let deployAttempt = null;
  let onlineVerification = null;

  try {
    workingRoot = ensureDeployFixtureState(plan.workspacePath || deployFixtureRoot);

    // Checkpoint 1
    {
      const checkpointId = "checkpoint1_workspace_root_and_task_root";
      try {
        ensureLocalCapability(runId, stepId, "local.file.read", workingRoot);
        ensureLocalCapability(runId, stepId, "local.file.write", workingRoot);
        ensureLocalCapability(runId, stepId, "local.shell.run", workingRoot);
        const bound = bindWorkspaceRootAndStorage({
          runId,
          stepId,
          caseId: checkpointId,
          workingRoot
        });
        emitPathJailCheck(runId, stepId, checkpointId, workingRoot, evaluatePathJailForTarget(workingRoot, workingRoot));
        emitPathJailCheck(
          runId,
          stepId,
          checkpointId,
          bound.taskRoot,
          evaluatePathJailForTarget(workingRoot, bound.taskRoot)
        );
        markCheckpoint(checkpointId, "completed", {
          working_root: workingRoot,
          task_root: bound.taskRoot,
          artifact_root: bound.artifactRoot,
          scratch_root: bound.scratchRoot,
          exercised_modules: ["workspace-root-binding", "task-storage-root", "path-jail-policy"]
        });
      } catch (error) {
        markCheckpoint(checkpointId, "failed", {
          reason: error instanceof Error ? error.message : String(error)
        });
      }
    }

    // Checkpoint 2
    {
      const checkpointId = "checkpoint2_openai_byo_exact_validation";
      const openAiKey =
        typeof plan.apiKey === "string" && plan.apiKey.trim()
          ? plan.apiKey.trim()
          : String(process.env.OPENAI_API_KEY || "").trim();
      if (!openAiKey) {
        markCheckpoint(checkpointId, "failed", {
          reason: "openai_api_key_missing_for_acceptance"
        });
      } else {
        const profileId =
          typeof plan.profileId === "string" && plan.profileId.trim()
            ? plan.profileId.trim()
            : BYO_DEFAULT_PROFILE_ID;
        const scope =
          typeof plan.bindingScope === "string" && plan.bindingScope.trim()
            ? normalizeByoScope(plan.bindingScope)
            : BYO_DEFAULT_SCOPE;
        try {
          const proof = await buildSyntheticByoProof({
            action: "bind",
            profileId,
            scope
          });
          const bound = await bindOpenAiByo({
            runId,
            profileId,
            bindingScope: scope,
            apiKey: openAiKey,
            validateNow: true,
            proofReceipt: proof.receipt
          });
          const status = String(bound?.validation?.validation_status || "");
          if (status === "valid") {
            markCheckpoint(checkpointId, "completed", {
              binding_id: bound.binding?.id || null,
              binding_scope: scope,
              validation_status: status,
              browser_profile_id_hash: bound.binding?.browser_profile_id_hash || null,
              challenge_response_verified: true,
              exercised_modules: ["openai-byo-exact-validation", "browser-profile-isolation"]
            });
          } else {
            markCheckpoint(checkpointId, "failed", {
              reason: `openai_validation_not_valid:${status || "unknown"}`,
              validation_status: status,
              failure_reason: bound?.validation?.failure_reason || null
            });
          }
        } catch (error) {
          markCheckpoint(checkpointId, "failed", {
            reason: error instanceof Error ? error.message : String(error)
          });
        }
      }
    }

    // Checkpoint 3
    {
      const checkpointId = "checkpoint3_retrieval_decision";
      try {
        const query = String(
          plan.query || "Fix local verify script and deploy preview for the selected workspace"
        ).trim();
        const decision = classifyRetrievalDecision({
          query,
          task_type: "local_engineering",
          user_requested_web_search: false,
          freshness_required: false,
          url_provided: false,
          low_confidence_external_fact: false
        });
        emitEvent(runId, "retrieval.decision", {
          step_id: stepId,
          checkpoint_id: checkpointId,
          search_needed: decision.search_needed,
          reason_code: decision.reason_code,
          query_summary: summarizeText(query, 240)
        });
        recordRetrievalDecisionRow({
          runId,
          reasonCode: decision.reason_code,
          providerSelected: null,
          querySummary: query,
          status: decision.search_needed ? "search_required" : "no_search"
        });
        const acceptedReason =
          decision.reason_code === "local_repo_sufficient" || decision.reason_code === "deterministic_local_task";
        if (!decision.search_needed && acceptedReason) {
          markCheckpoint(checkpointId, "completed", {
            reason_code: decision.reason_code,
            search_triggered: false,
            exercised_modules: ["retrieval-broker-decision-gate"]
          });
        } else {
          markCheckpoint(checkpointId, "failed", {
            reason: "retrieval_decision_expected_no_search_for_local_story",
            reason_code: decision.reason_code,
            search_triggered: decision.search_needed
          });
        }
      } catch (error) {
        markCheckpoint(checkpointId, "failed", {
          reason: error instanceof Error ? error.message : String(error)
        });
      }
    }

    // Checkpoint 4
    {
      const checkpointId = "checkpoint4_local_code_eval_fix_verify";
      try {
        const rel = "src/check.js";
        const abs = workspaceAbsolutePath(workingRoot, rel);
        emitEvent(runId, "file.read.started", { step_id: stepId, checkpoint_id: checkpointId, path: rel });
        const before = readTextFileWithPolicy(abs);
        emitEvent(runId, "file.read.completed", {
          step_id: stepId,
          checkpoint_id: checkpointId,
          path: rel,
          bytes: Buffer.byteLength(before, "utf8")
        });
        emitEvent(runId, "file.write.started", { step_id: stepId, checkpoint_id: checkpointId, path: rel });
        const after = "module.exports = function deployCheck() {\n  return \"fixed\";\n};\n";
        writeTextFileWithPolicy(abs, after);
        recordFileChange({
          runId,
          filePath: rel,
          action: "update",
          beforeHash: textHash(before),
          afterHash: textHash(after),
          summary: "system_acceptance_local_fix"
        });
        emitEvent(runId, "file.write.completed", {
          step_id: stepId,
          checkpoint_id: checkpointId,
          path: rel,
          bytes: Buffer.byteLength(after, "utf8")
        });
        emitEvent(runId, "shell.command.started", {
          step_id: stepId,
          checkpoint_id: checkpointId,
          command: "node verify-local.mjs",
          cwd: workingRoot
        });
        const verify = runLocalCommand("node", ["verify-local.mjs"], 20000, { cwd: workingRoot });
        recordAdapterRun({
          runId,
          adapterId: "shell.adapter.v1",
          commandOrAction: "node verify-local.mjs",
          cwd: workingRoot,
          status: verify.ok ? "completed" : "failed",
          startedAt: nowIso(),
          completedAt: nowIso(),
          exitCode: normalizeExitCode(verify.status),
          stdoutSummary: summarizeText(verify.stdout, 512),
          stderrSummary: summarizeText(verify.stderr || verify.error_message, 512)
        });
        emitEvent(runId, "shell.command.completed", {
          step_id: stepId,
          checkpoint_id: checkpointId,
          command: "node verify-local.mjs",
          cwd: workingRoot,
          exit_code: normalizeExitCode(verify.status),
          status: verify.ok ? "completed" : "failed",
          stdout_summary: summarizeText(verify.stdout, 512),
          stderr_summary: summarizeText(verify.stderr || verify.error_message, 512)
        });
        if (!verify.ok) {
          markCheckpoint(checkpointId, "failed", {
            reason: "local_verify_failed_after_fix"
          });
        } else {
          markCheckpoint(checkpointId, "completed", {
            verify_command: "node verify-local.mjs",
            exercised_modules: ["local-file-shell-verify-mainchain"]
          });
        }
      } catch (error) {
        markCheckpoint(checkpointId, "failed", {
          reason: error instanceof Error ? error.message : String(error)
        });
      }
    }

    // Checkpoint 5 (optional)
    markCheckpoint("checkpoint5_approval_pending_same_run_continue", "not_needed_for_this_story", {
      reason: "story_has_no_escalated_external_write_request"
    });

    // Checkpoint 6 (optional)
    {
      const checkpointId = "checkpoint6_browser_readonly_verification";
      try {
        const browser = discoverBrowserLaneTools(runId, stepId, checkpointId);
        if (!browser?.selectedBrowser?.resolved_path) {
          markCheckpoint(checkpointId, "not_needed_for_this_story", {
            reason: "local_browser_unavailable_in_current_runtime"
          });
        } else {
          const target = toFileUrl(path.join(workingRoot, "index.html"));
          const dom = runBrowserDomDump(browser.selectedBrowser.resolved_path, target, 30000);
          const domText = String(dom?.result?.stdout || "");
          const marker = parseDomTextById(domText, "deploy-marker");
          const screenshotAbs = artifactPath(runId, `system_acceptance_browser_${Date.now()}.png`);
          const shot = runBrowserScreenshot(browser.selectedBrowser.resolved_path, target, screenshotAbs, 30000);
          if (dom.ok && shot.ok && marker.includes("preview-closeout-marker")) {
            markCheckpoint(checkpointId, "completed", {
              target,
              selector: "#deploy-marker",
              expected_text: "preview-closeout-marker",
              screenshot_path: toRepoRelative(screenshotAbs),
              exercised_modules: ["browser-lane-readonly-verification"]
            });
          } else {
            markCheckpoint(checkpointId, "failed_optional", {
              reason: "browser_readonly_verification_failed_or_marker_missing",
              screenshot_path: fs.existsSync(screenshotAbs) ? toRepoRelative(screenshotAbs) : null
            });
          }
        }
      } catch (error) {
        markCheckpoint(checkpointId, "failed_optional", {
          reason: error instanceof Error ? error.message : String(error)
        });
      }
    }

    // Checkpoint 7 (optional)
    markCheckpoint("checkpoint7_e2b_second_lane_writeback", "not_needed_for_this_story", {
      reason: "story_scoped_to_local_root_to_preview_release_without_isolated_writeback"
    });

    // Checkpoint 8
    {
      const checkpointId = "checkpoint8_real_deploy_closeout";
      try {
        const preflight = runDeployPreflightForCloseout({
          runId,
          stepId,
          caseId: checkpointId,
          workingRoot,
          provider: "vercel"
        });
        if (!preflight.ok) {
          markCheckpoint(checkpointId, "failed", {
            reason: preflight.reason || "deploy_preflight_failed"
          });
        } else {
          deployAttempt = runVercelDeployAttempt({
            runId,
            stepId,
            caseId: checkpointId,
            workingRoot,
            provider: "vercel",
            deployMode: String(deployCloseoutContract?.deploy_mode || "preview_non_destructive"),
            executable: preflight.executable,
            args: ["deploy", "--yes", "--debug"],
            retryNumber: 0
          });
          if (deployAttempt.ok) {
            markCheckpoint(checkpointId, "completed", {
              deploy_run_id: deployAttempt.row?.id || null,
              provider: "vercel",
              release_url_redacted: deployAttempt.releaseUrlRedacted || null,
              exercised_modules: ["real-deploy-closeout"]
            });
          } else {
            markCheckpoint(checkpointId, "failed", {
              reason: `deploy_failed:${deployAttempt.failureClass || "unknown_failure"}`,
              deploy_run_id: deployAttempt.row?.id || null
            });
          }
        }
      } catch (error) {
        markCheckpoint(checkpointId, "failed", {
          reason: error instanceof Error ? error.message : String(error)
        });
      }
    }

    // Checkpoint 9
    {
      const checkpointId = "checkpoint9_online_verification";
      try {
        if (!deployAttempt?.ok || !deployAttempt?.row) {
          markCheckpoint(checkpointId, "failed", {
            reason: "deploy_not_completed_for_online_verification"
          });
        } else {
          onlineVerification = runOnlineVerificationForRelease({
            runId,
            stepId,
            caseId: checkpointId,
            deployRunRow: deployAttempt.row,
            releaseUrl: deployAttempt.releaseUrl,
            workingRoot
          });
          if (onlineVerification.ok) {
            markCheckpoint(checkpointId, "completed", {
              verification_run_id: onlineVerification.row?.id || null,
              final_status: onlineVerification.payload?.final_status || null,
              node_status: onlineVerification.payload?.node_status || null,
              powershell_status: onlineVerification.payload?.powershell_status || null,
              browser_status: onlineVerification.payload?.browser_status || null,
              exercised_modules: ["online-verification-closeout"]
            });
          } else {
            markCheckpoint(checkpointId, "failed", {
              reason: "online_verification_failed",
              final_status: onlineVerification.payload?.final_status || null
            });
          }
        }
      } catch (error) {
        markCheckpoint(checkpointId, "failed", {
          reason: error instanceof Error ? error.message : String(error)
        });
      }
    }

    // Checkpoint 10 + final readiness
    {
      const checkpointId = "checkpoint10_final_system_acceptance_readiness";
      const finalRequiredFailures = checkpoints.filter((x) => requiredSet.has(x.checkpoint_id) && x.status !== "completed");
      const liteReady = finalRequiredFailures.length === 0;
      if (!liteReady && !uniqueBlocker) {
        uniqueBlocker = finalRequiredFailures[0]?.details?.reason || `${finalRequiredFailures[0]?.checkpoint_id || "unknown"}_failed`;
      }
      const chainStatus = liteReady
        ? deferredItems.length > 0
          ? "completed_with_deferred_optional"
          : "completed"
        : "failed_blocked";
      const completedModules = Array.isArray(systemAcceptanceContract?.completed_modules)
        ? systemAcceptanceContract.completed_modules
        : [];
      if (liteReady) {
        markCheckpoint(checkpointId, "completed", {
          chain_status: chainStatus
        });
      } else {
        markCheckpoint(checkpointId, "failed", {
          reason: uniqueBlocker || "system_acceptance_not_ready",
          chain_status: chainStatus
        });
      }

      const payload = {
        acceptance_chain: chain,
        exercised_modules: [...exercisedModules],
        completed_modules: completedModules,
        non_blocking_issues: nonBlockingIssues,
        deferred_items: deferredItems,
        litecodex_system_acceptance_ready: liteReady,
        unique_blocker: liteReady ? null : uniqueBlocker || "system_acceptance_not_ready",
        evidence_root:
          typeof systemAcceptanceContract?.evidence_root === "string" && systemAcceptanceContract.evidence_root.trim()
            ? systemAcceptanceContract.evidence_root.trim()
            : "evidence/system-acceptance-closeout"
      };
      const disk = writeRunArtifact(
        runId,
        `system_acceptance_closeout_${Date.now()}.json`,
        `${JSON.stringify(payload, null, 2)}\n`
      );
      const row = recordSystemAcceptanceResult({
        runId,
        acceptanceChainStatus: chainStatus,
        exercisedModulesJson: JSON.stringify(payload.exercised_modules || []),
        completedModulesJson: JSON.stringify(payload.completed_modules || []),
        nonBlockingIssuesJson: JSON.stringify(payload.non_blocking_issues || []),
        deferredItemsJson: JSON.stringify(payload.deferred_items || []),
        litecodexSystemAcceptanceReady: liteReady,
        evidencePath: toRepoRelative(disk),
        createdAt: nowIso()
      });
      emitEvent(runId, "acceptance.readiness.checked", {
        step_id: stepId,
        story_id: storyId,
        system_acceptance_result_id: row.id,
        ...payload,
        evidence_path: row.evidence_path
      });
      emitEvent(runId, "acceptance.chain.completed", {
        step_id: stepId,
        story_id: storyId,
        acceptance_chain_status: chainStatus,
        litecodex_system_acceptance_ready: liteReady,
        unique_blocker: payload.unique_blocker,
        checkpoints
      });
      if (liteReady) {
        emitEvent(runId, "step.completed", {
          step_id: stepId,
          story_id: storyId,
          message: "system acceptance closeout completed",
          system_acceptance_result_id: row.id
        });
      } else {
        emitEvent(runId, "step.failed_controlled", {
          step_id: stepId,
          story_id: storyId,
          reason: payload.unique_blocker || "system_acceptance_not_ready",
          system_acceptance_result_id: row.id
        });
      }
    }
  } catch (error) {
    emitEvent(runId, "step.failed", {
      step_id: stepId,
      story_id: storyId,
      reason: error instanceof Error ? error.message : String(error)
    });
  }
}

function createSystemAcceptanceCloseoutRun(input) {
  const id = shortId("run");
  const ts = nowIso();
  dbRun(
    "INSERT INTO runs (id, title, status, created_at, updated_at, last_event_type) VALUES (?, ?, ?, ?, ?, ?)",
    id,
    input.title,
    "running",
    ts,
    ts,
    null
  );
  activeRunId = id;
  writeRunMeta(id);
  emitEvent(id, "run.created", {
    title: input.title,
    phase: "system-acceptance-closeout",
    runtime_profile: runtimeProfile.id,
    story_id: typeof input.storyId === "string" ? input.storyId : null,
    acceptance_chain: systemAcceptanceChain()
  });
  setTimeout(() => {
    void executeSystemAcceptanceCloseout(id, input);
  }, 10);
  return dbGet("SELECT id, title, status, created_at, updated_at, last_event_type FROM runs WHERE id = ?", id);
}

function ensureTextFile(absPath, content) {
  fs.mkdirSync(path.dirname(absPath), { recursive: true });
  fs.writeFileSync(absPath, String(content || ""), "utf8");
}

function parseModelJsonObject(rawText) {
  const text = String(rawText || "").trim();
  if (!text) return null;
  const direct = safeParseJson(text);
  if (direct && typeof direct === "object") return direct;
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced?.[1]) {
    const parsed = safeParseJson(fenced[1].trim());
    if (parsed && typeof parsed === "object") return parsed;
  }
  const firstBrace = text.indexOf("{");
  const lastBrace = text.lastIndexOf("}");
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    const parsed = safeParseJson(text.slice(firstBrace, lastBrace + 1));
    if (parsed && typeof parsed === "object") return parsed;
  }
  return null;
}

function estimateModelCostUsd(usage) {
  const total = Number(usage?.total_tokens || 0);
  if (!Number.isFinite(total) || total <= 0) return 0;
  return Number((total * 0.000002).toFixed(6));
}

function invokeOpenAiResponsesViaPowerShellRaw(apiKey, body, timeoutMs = 15000) {
  if (process.platform !== "win32") return null;
  const timeoutSec = Math.max(3, Math.ceil(timeoutMs / 1000));
  const script = [
    "$ErrorActionPreference='Stop'",
    "$headers = @{ Authorization = ('Bearer ' + $env:LITECODEX_OPENAI_KEY); 'Content-Type' = 'application/json' }",
    "$uri = $env:LITECODEX_OPENAI_URL",
    "$body = $env:LITECODEX_OPENAI_BODY",
    "$timeout = [int]$env:LITECODEX_OPENAI_TIMEOUT",
    "$result = $null",
    "try {",
    "  $resp = Invoke-WebRequest -Uri $uri -Headers $headers -Method Post -Body $body -TimeoutSec $timeout -ErrorAction Stop",
    "  $respBody = ''",
    "  try { $respBody = [string]$resp.Content } catch { $respBody = '' }",
    "  if ($respBody.Length -gt 32768) { $respBody = $respBody.Substring(0, 32768) }",
    "  $result = @{ ok = $true; status = [int]$resp.StatusCode; body = [string]$respBody }",
    "} catch {",
    "  $webResp = $null",
    "  try { $webResp = $_.Exception.Response } catch { $webResp = $null }",
    "  if ($null -ne $webResp) {",
    "    $status = 0",
    "    try { $status = [int]$webResp.StatusCode.value__ } catch {",
    "      try { $status = [int]$webResp.StatusCode } catch { $status = 0 }",
    "    }",
    "    $errBody = ''",
    "    try {",
    "      $stream = $webResp.GetResponseStream()",
    "      if ($null -ne $stream) {",
    "        $reader = New-Object System.IO.StreamReader($stream)",
    "        $errBody = $reader.ReadToEnd()",
    "        if ($errBody.Length -gt 32768) { $errBody = $errBody.Substring(0, 32768) }",
    "      }",
    "    } catch { $errBody = '' }",
    "    $result = @{ ok = $false; status = $status; body = [string]$errBody; error = [string]$_.Exception.Message }",
    "  } else {",
    "    $result = @{ ok = $false; status = 0; error = [string]$_.Exception.Message }",
    "  }",
    "}",
    "$result | ConvertTo-Json -Compress"
  ].join(";");

  const candidates = ["powershell", "pwsh"];
  for (const cmd of candidates) {
    const childEnv = {
      ...process.env,
      LITECODEX_OPENAI_KEY: apiKey,
      LITECODEX_OPENAI_URL: OPENAI_RESPONSES_URL,
      LITECODEX_OPENAI_BODY: JSON.stringify(body || {}),
      LITECODEX_OPENAI_TIMEOUT: String(timeoutSec)
    };
    const result = spawnSync(cmd, ["-NoProfile", "-NonInteractive", "-Command", script], {
      encoding: "utf8",
      windowsHide: true,
      timeout: timeoutMs,
      maxBuffer: 512 * 1024,
      env: childEnv
    });
    if (typeof result.stdout === "string" && result.stdout.trim()) {
      const parsed = safeParseJson(result.stdout.trim());
      if (parsed && (typeof parsed.status === "number" || typeof parsed.ok === "boolean")) {
        return {
          ok: Boolean(parsed.ok),
          status: Number(parsed.status || 0),
          body: String(parsed.body || ""),
          error: parsed.error ? String(parsed.error) : null,
          command: cmd
        };
      }
    }
    const stderr = String(result.stderr || "").trim();
    if (result.status === 0 && !stderr) {
      continue;
    }
    return {
      ok: false,
      status: 0,
      body: "",
      error: stderr || `powershell_exit_${result.status ?? "unknown"}`,
      command: cmd
    };
  }
  return null;
}

function resolveOpenAiProviderRoute() {
  return {
    provider_id: OPENAI_PROVIDER_ID,
    base_url: OPENAI_BASE_URL,
    endpoint: OPENAI_RESPONSES_ENDPOINT,
    url: OPENAI_RESPONSES_URL,
    env_key: OPENAI_ENV_KEY,
    model: OPENAI_CODEGEN_MODEL || OPENAI_DEFAULT_MODEL
  };
}

function resolveOpenAiApiKey() {
  if (typeof byoApiKeyMemory === "string" && byoApiKeyMemory.trim()) {
    return byoApiKeyMemory.trim();
  }
  const fromEnv = String(process.env[OPENAI_ENV_KEY] || "").trim();
  return fromEnv || "";
}

function normalizeOpenAiUsage(raw) {
  const usage = raw && typeof raw === "object" ? raw : {};
  const promptTokens = Number(usage.prompt_tokens ?? usage.input_tokens ?? 0);
  const completionTokens = Number(usage.completion_tokens ?? usage.output_tokens ?? 0);
  const totalTokens = Number(usage.total_tokens ?? (promptTokens + completionTokens) ?? 0);
  return {
    prompt_tokens: Number.isFinite(promptTokens) ? promptTokens : 0,
    completion_tokens: Number.isFinite(completionTokens) ? completionTokens : 0,
    total_tokens: Number.isFinite(totalTokens) ? totalTokens : 0
  };
}

function extractResponsesOutputText(payload) {
  if (!payload || typeof payload !== "object") return "";
  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
    return payload.output_text;
  }
  const chunks = [];
  const output = Array.isArray(payload.output) ? payload.output : [];
  for (const item of output) {
    const content = Array.isArray(item?.content) ? item.content : [];
    for (const part of content) {
      if (typeof part?.text === "string" && part.text.trim()) chunks.push(part.text);
    }
  }
  if (chunks.length > 0) {
    return chunks.join("\n");
  }
  const legacyRaw = payload?.choices?.[0]?.message?.content;
  if (typeof legacyRaw === "string") return legacyRaw;
  if (Array.isArray(legacyRaw)) {
    return legacyRaw.map((x) => (typeof x?.text === "string" ? x.text : "")).join("\n");
  }
  return "";
}

function classifyOpenAiCodegenError(responseStatus, bodyText) {
  const parsed = safeParseJson(bodyText);
  const errorObj = parsed?.error && typeof parsed.error === "object" ? parsed.error : null;
  const errorCode = String(errorObj?.code || "");
  const errorType = String(errorObj?.type || "");
  const errorMessage = String(errorObj?.message || "");
  const normalized = normalizeProbeClassification({
    status: Number(responseStatus || 0),
    errorCode,
    errorType,
    errorMessage: errorMessage || bodyText
  });
  let error = "openai_codegen_http_error";
  if (normalized.failure_layer === "wrong_model") error = "openai_codegen_wrong_model";
  else if (normalized.failure_layer === "wrong_endpoint") error = "openai_codegen_wrong_endpoint";
  else if (normalized.failure_layer === "header_auth_error") {
    error = normalized.validation_status === "invalid_key" ? "openai_codegen_invalid_key" : "openai_codegen_permission_denied";
  } else if (normalized.failure_layer === "rate_limited") error = "openai_codegen_rate_limited";
  else if (normalized.failure_layer === "gateway_ambiguous") error = "openai_codegen_gateway_ambiguous";
  return {
    error,
    failure_layer: normalized.failure_layer || "unknown_auth_error",
    failure_reason: normalized.failure_reason || "unknown"
  };
}

async function probeOpenAiNodeSdkRoute(apiKey, timeoutMs = 12000) {
  const route = resolveOpenAiProviderRoute();
  const started = Date.now();
  try {
    const imported = await import("openai");
    const OpenAI = imported?.default || imported?.OpenAI;
    if (typeof OpenAI !== "function") {
      return {
        status: "failed",
        failure_layer: "sdk_wiring_error",
        failure_reason: "openai_sdk_constructor_missing",
        latency_ms: Date.now() - started,
        provider_id: route.provider_id,
        base_url: route.base_url,
        endpoint: route.endpoint,
        model: OPENAI_VALIDATION_MODEL || OPENAI_DEFAULT_MODEL
      };
    }
    const client = new OpenAI({
      apiKey,
      baseURL: route.base_url,
      timeout: Math.max(1000, Number(timeoutMs || 12000)),
      maxRetries: 0
    });
    await client.responses.create(openAiValidationProbeBody());
    return {
      status: "success",
      failure_layer: null,
      failure_reason: null,
      latency_ms: Date.now() - started,
      provider_id: route.provider_id,
      base_url: route.base_url,
      endpoint: route.endpoint,
      model: OPENAI_VALIDATION_MODEL || OPENAI_DEFAULT_MODEL
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    const status = Number(error?.status || error?.statusCode || 0);
    const code = String(error?.code || error?.type || "");
    const classification = normalizeProbeClassification({
      status,
      errorCode: code,
      errorType: String(error?.name || ""),
      errorMessage: message
    });
    const failureLayer = /Cannot find package 'openai'|Cannot find module 'openai'/.test(message)
      ? "sdk_wiring_error"
      : classification.failure_layer || "sdk_wiring_error";
    return {
      status: "failed",
      failure_layer: failureLayer,
      failure_reason: classification.failure_reason || normalizeByoFailureReason(message),
      latency_ms: Date.now() - started,
      provider_id: route.provider_id,
      base_url: route.base_url,
      endpoint: route.endpoint,
      model: OPENAI_VALIDATION_MODEL || OPENAI_DEFAULT_MODEL
    };
  }
}

async function callOpenAiJsonObject({
  systemPrompt,
  userPrompt,
  maxTokens = 1600,
  temperature = 0.1,
  runId = null,
  promptPhase = "generic",
  promptContext = null
}) {
  const route = resolveOpenAiProviderRoute();
  const key = resolveOpenAiApiKey();
  const effectiveSystemPrompt = composeSystemPromptWithContract({
    systemPrompt,
    userPrompt,
    runId,
    promptPhase,
    promptContext,
    skillInput: promptContext && typeof promptContext === "object" ? promptContext : {}
  });
  if (!key) {
    return {
      ok: false,
      error: "openai_api_key_missing",
      status: 0,
      latency_ms: 0,
      usage: null,
      text: "",
      failure_layer: "header_auth_error",
      provider_id: route.provider_id,
      base_url: route.base_url,
      endpoint: route.endpoint,
      model: route.model
    };
  }
  const started = Date.now();
  const requestTimeoutMs = Math.max(5000, parsePositiveInt(transportDiagnosticsContract?.timeout_ms, 15000));
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), requestTimeoutMs);
  try {
    const response = await fetch(route.url, {
      method: "POST",
      signal: controller.signal,
      headers: {
        Authorization: `Bearer ${key}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        model: route.model,
        temperature,
        max_output_tokens: maxTokens,
        text: {
          format: {
            type: "json_object"
          }
        },
        input: [
          {
            role: "system",
            content: [{ type: "input_text", text: effectiveSystemPrompt }]
          },
          {
            role: "user",
            content: [{ type: "input_text", text: userPrompt }]
          }
        ]
      })
    });
    const rawText = await response.text();
    const json = safeParseJson(rawText) || {};
    const latency = Date.now() - started;
    const content = extractResponsesOutputText(json);
    const usage = normalizeOpenAiUsage(json?.usage || {});
    if (!response.ok) {
      const classified = classifyOpenAiCodegenError(response.status, rawText);
      return {
        ok: false,
        error: classified.error,
        status: response.status,
        latency_ms: latency,
        usage: usage,
        text: content,
        failure_layer: classified.failure_layer,
        failure_reason: classified.failure_reason,
        provider_id: route.provider_id,
        base_url: route.base_url,
        endpoint: route.endpoint,
        model: route.model
      };
    }
    const parsed = parseModelJsonObject(content);
    if (!parsed) {
      return {
        ok: false,
        error: "openai_output_not_json",
        status: response.status,
        latency_ms: latency,
        usage: usage,
        text: content,
        failure_layer: "sdk_wiring_error",
        provider_id: route.provider_id,
        base_url: route.base_url,
        endpoint: route.endpoint,
        model: route.model
      };
    }
    return {
      ok: true,
      status: response.status,
      latency_ms: latency,
      usage,
      text: content,
      json: parsed,
      failure_layer: null,
      provider_id: route.provider_id,
      base_url: route.base_url,
      endpoint: route.endpoint,
      model: route.model
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "network_error";
    const classified = normalizeProbeClassification({
      status: 0,
      errorCode: "",
      errorType: "",
      errorMessage: message
    });
    const networkFailure = String(classified.validation_status || "") === "network_unreachable";
    if (networkFailure) {
      const psRaw = invokeOpenAiResponsesViaPowerShellRaw(
        key,
        {
          model: route.model,
          temperature,
          max_output_tokens: maxTokens,
          text: {
            format: {
              type: "json_object"
            }
          },
          input: [
            {
              role: "system",
              content: [{ type: "input_text", text: effectiveSystemPrompt }]
            },
            {
              role: "user",
              content: [{ type: "input_text", text: userPrompt }]
            }
          ]
        },
        30000
      );
      if (psRaw) {
        const parsedResp = safeParseJson(String(psRaw.body || "")) || {};
        const usage = normalizeOpenAiUsage(parsedResp?.usage || {});
        const content = extractResponsesOutputText(parsedResp);
        const latency = Date.now() - started;
        if (psRaw.ok && Number(psRaw.status || 0) >= 200 && Number(psRaw.status || 0) < 300) {
          const parsedObject = parseModelJsonObject(content);
          if (parsedObject) {
            return {
              ok: true,
              status: Number(psRaw.status || 200),
              latency_ms: latency,
              usage,
              text: content,
              json: parsedObject,
              failure_layer: null,
              provider_id: route.provider_id,
              base_url: route.base_url,
              endpoint: route.endpoint,
              model: route.model,
              transport_stack: "powershell_http_fallback"
            };
          }
        }
        const classifiedPs = normalizeProbeClassification({
          status: Number(psRaw.status || 0),
          errorCode: "",
          errorType: "",
          errorMessage: String(psRaw.error || psRaw.body || "powershell_transport_failed")
        });
        return {
          ok: false,
          error: "openai_codegen_network_unreachable",
          status: Number(psRaw.status || 0),
          latency_ms: latency,
          usage,
          text: content,
          failure_layer: classifiedPs.failure_layer || "network_unreachable",
          failure_reason: classifiedPs.failure_reason || normalizeByoFailureReason(String(psRaw.error || "powershell_transport_failed")),
          provider_id: route.provider_id,
          base_url: route.base_url,
          endpoint: route.endpoint,
          model: route.model,
          transport_stack: "powershell_http_fallback"
        };
      }
    }
    return {
      ok: false,
      error: "openai_codegen_network_unreachable",
      status: 0,
      latency_ms: Date.now() - started,
      usage: null,
      text: "",
      failure_layer: classified.failure_layer || "network_unreachable",
      failure_reason: classified.failure_reason || normalizeByoFailureReason(message),
      provider_id: route.provider_id,
      base_url: route.base_url,
      endpoint: route.endpoint,
      model: route.model
    };
  } finally {
    clearTimeout(timer);
  }
}

function compileUsageAccumulator(totalUsage, usage, latencyMs) {
  const next = totalUsage || {
    prompt_tokens: 0,
    completion_tokens: 0,
    total_tokens: 0,
    calls: 0,
    latency_ms: 0
  };
  next.prompt_tokens += Number(usage?.prompt_tokens || 0);
  next.completion_tokens += Number(usage?.completion_tokens || 0);
  next.total_tokens += Number(usage?.total_tokens || 0);
  next.calls += 1;
  next.latency_ms += Number(latencyMs || 0);
  return next;
}

