function compilerListWorkspaceFiles(root, maxFiles = 40) {
  const out = [];
  const stack = [root];
  while (stack.length > 0 && out.length < maxFiles) {
    const cur = stack.pop();
    if (!cur || !fs.existsSync(cur)) continue;
    for (const entry of fs.readdirSync(cur, { withFileTypes: true })) {
      const abs = path.join(cur, entry.name);
      const rel = path.relative(root, abs).replace(/\\/g, "/");
      if (!rel) continue;
      if (entry.isDirectory()) {
        if (["node_modules", ".git", "dist", "build", ".next", ".venv", "__pycache__"].includes(entry.name)) continue;
        stack.push(abs);
      } else if (entry.isFile()) {
        out.push(rel);
      }
      if (out.length >= maxFiles) break;
    }
  }
  out.sort();
  return out;
}

function readFilesForContext(root, paths, maxBytesPerFile = 8000) {
  const out = [];
  for (const relRaw of paths || []) {
    const rel = normalizeRelativeFilePath(relRaw);
    if (!rel) continue;
    const abs = workspaceAbsolutePath(root, rel);
    if (!fs.existsSync(abs) || !fs.statSync(abs).isFile()) continue;
    let text = fs.readFileSync(abs, "utf8");
    if (Buffer.byteLength(text, "utf8") > maxBytesPerFile) {
      text = `${text.slice(0, maxBytesPerFile)}\n/* TRUNCATED */\n`;
    }
    out.push({ path: rel, content: text });
  }
  return out;
}

function defaultVerificationCommandsForTask(taskType) {
  if (taskType === "frontend_fix") {
    return [
      "node scripts/format-check.mjs",
      "node scripts/lint-check.mjs",
      "node --check src/counter.js",
      "node tests/counter.test.mjs",
      "node scripts/smoke.mjs"
    ];
  }
  if (taskType === "backend_fix") {
    return ["python -m py_compile app/main.py", "python tests/test_main.py", "python scripts/smoke.py"];
  }
  if (taskType === "fullstack_feature") {
    return ["node frontend/tests/client.test.mjs", "python backend/tests/test_service.py", "node tests/integration-smoke.mjs"];
  }
  if (taskType === "worker_patch") {
    return ["node --check src/worker.js", "node tests/worker.test.mjs"];
  }
  if (taskType === "frontend_nextjs_fix") {
    return ["node scripts/lint.mjs", "node tests/next.test.mjs", "node scripts/smoke.mjs"];
  }
  if (taskType === "frontend_vue_fix") {
    return ["node scripts/lint.mjs", "node tests/vue.test.mjs", "node scripts/smoke.mjs"];
  }
  if (taskType === "backend_node_fix") {
    return ["node scripts/lint-check.mjs", "node --check src/server.js", "node tests/server.test.mjs", "node scripts/smoke.mjs"];
  }
  if (taskType === "polyglot_go_patch") {
    return ["go test ./..."];
  }
  if (taskType === "polyglot_java_patch") {
    return [
      "mvn -q -DskipTests package",
      "javac src/main/java/com/litecodex/GreetingService.java src/test/java/com/litecodex/GreetingServiceTest.java",
      "java -cp src/main/java;src/test/java com.litecodex.GreetingServiceTest"
    ];
  }
  if (taskType === "crossend_react_native_patch") {
    return [
      "npx --no-install @react-native-community/cli --version",
      "node scripts/lint.mjs",
      "node tests/mobile.test.mjs",
      "node scripts/smoke.mjs"
    ];
  }
  if (taskType === "polyglot_rust_patch") {
    return ["cargo check", "python scripts/rust_semantic_verify.py"];
  }
  if (taskType === "infra_terraform_patch") {
    return ["terraform fmt -check -recursive", "terraform validate"];
  }
  if (taskType === "config_yaml_schema_patch") {
    return ["python scripts/validate_yaml.py"];
  }
  if (taskType === "data_sql_migration_patch") {
    return ["python scripts/verify_sql.py"];
  }
  if (taskType === "backend_kotlin_patch") {
    return [
      "kotlinc src/main/kotlin/Greeting.kt src/test/kotlin/GreetingTest.kt -include-runtime -d build/test.jar",
      "java -jar build/test.jar"
    ];
  }
  if (taskType === "backend_swift_windows_patch") {
    return ["python scripts/swift_semantic_verify.py"];
  }
  if (taskType === "crossend_flutter_web_patch") {
    return ["flutter --version", "dart --version", "python scripts/flutter_semantic_verify.py"];
  }
  if (taskType === "crossend_flutter_patch") {
    return ["flutter --version", "dart --version", "python scripts/flutter_semantic_verify.py"];
  }
  return ["node scripts/lint-check.mjs", "node --check src/server.js", "node tests/server.test.mjs", "node scripts/smoke.mjs"];
}

function normalizeVerificationCommandsForTask(taskType, proposedCommands) {
  const fallback = defaultVerificationCommandsForTask(taskType);
  const proposed = Array.isArray(proposedCommands)
    ? proposedCommands.map((x) => String(x || "").trim()).filter((x) => x.length > 0)
    : [];
  // Keep deterministic and executable verify matrix for polyglot representative tasks.
  if (
    taskType === "frontend_fix" ||
    taskType === "backend_fix" ||
    taskType === "fullstack_feature" ||
    taskType === "worker_patch" ||
    taskType === "review_auto_repair" ||
    taskType === "frontend_nextjs_fix" ||
    taskType === "frontend_vue_fix" ||
    taskType === "backend_node_fix" ||
    taskType === "polyglot_go_patch" ||
    taskType === "polyglot_java_patch" ||
    taskType === "crossend_react_native_patch" ||
    taskType === "polyglot_rust_patch" ||
    taskType === "infra_terraform_patch" ||
    taskType === "config_yaml_schema_patch" ||
    taskType === "data_sql_migration_patch" ||
    taskType === "backend_kotlin_patch" ||
    taskType === "backend_swift_windows_patch" ||
    taskType === "crossend_flutter_patch" ||
    taskType === "crossend_flutter_web_patch"
  ) {
    return fallback;
  }
  return proposed.length > 0 ? proposed : fallback;
}

