function bringupReactNativeCli(workspaceRoot) {
  const memoKey = `react-native-cli::${normalizeFsPath(workspaceRoot)}`;
  const cached = polyglotToolchainInstallMemo.get(memoKey);
  if (cached?.ok) return cached;
  const parsed = splitCommand("npm install --no-audit --no-fund @react-native-community/cli");
  const install = runLocalCommand(parsed.command, parsed.args, 420000, {
    cwd: workspaceRoot,
    env: buildToolchainEnv()
  });
  const probe = runLocalCommand("npx", ["--no-install", "@react-native-community/cli", "--version"], 45000, {
    cwd: workspaceRoot,
    env: buildToolchainEnv()
  });
  const result = {
    ok: Boolean(install.ok && probe.ok),
    install_mode: "project_local",
    method: "npm_project_local",
    command_summary: "npm install --no-audit --no-fund @react-native-community/cli",
    stdout: summarizeText(`${install.stdout || ""}\n${probe.stdout || ""}`, 600),
    stderr: summarizeText(`${install.stderr || install.error_message || ""}\n${probe.stderr || probe.error_message || ""}`, 600),
    version_summary: summarizeText(`${probe.stdout || ""}\n${probe.stderr || ""}`, 600)
  };
  polyglotToolchainInstallMemo.set(memoKey, result);
  return result;
}

function bringupRustToolchain() {
  const memoKey = "rust";
  const cached = polyglotToolchainInstallMemo.get(memoKey);
  if (cached?.ok && findBoundToolchainExecutable("rustc") && findBoundToolchainExecutable("cargo")) return cached;

  ensurePolyglotToolchainRoots();
  const cargoHome = path.join(polyglotToolchainRoot, "rust", "cargo-home");
  const rustupHome = path.join(polyglotToolchainRoot, "rust", "rustup-home");
  fs.mkdirSync(cargoHome, { recursive: true });
  fs.mkdirSync(rustupHome, { recursive: true });
  polyglotToolchainEnv.CARGO_HOME = cargoHome;
  polyglotToolchainEnv.RUSTUP_HOME = rustupHome;
  process.env.CARGO_HOME = cargoHome;
  process.env.RUSTUP_HOME = rustupHome;

  const rustupExeLocal = path.join(cargoHome, "bin", "rustup.exe");
  const rustupCmd = fs.existsSync(rustupExeLocal)
    ? rustupExeLocal
    : findExecutableRecursive(polyglotToolchainRoot, "rustup.exe");

  const existingRustc = findBoundToolchainExecutable("rustc") || findExecutableRecursive(polyglotToolchainRoot, "rustc.exe");
  const existingCargo = findBoundToolchainExecutable("cargo") || findExecutableRecursive(polyglotToolchainRoot, "cargo.exe");
  if (existingRustc && existingCargo && rustupCmd) {
    const stabilized = stabilizeRustToolchain({
      rustupExe: rustupCmd,
      cargoExe: existingCargo,
      rustcExe: existingRustc,
      cargoHome,
      rustupHome
    });
    bindToolchainExecutable("rustc", stabilized.resolved_rustc);
    bindToolchainExecutable("cargo", stabilized.resolved_cargo);
    const result = {
      ok: stabilized.ok,
      install_mode: "fixture_local_cached",
      method: "fixture_local_cached",
      command_summary: "cargo --version && rustc --version",
      stdout: summarizeText(
        `${stabilized.cargo_probe.stdout || ""}\n${stabilized.rustc_probe.stdout || ""}\n${stabilized.rustup_show.stdout || ""}`,
        1200
      ),
      stderr: summarizeText(
        `${stabilized.cargo_probe.stderr || stabilized.cargo_probe.error_message || ""}\n${stabilized.rustc_probe.stderr || stabilized.rustc_probe.error_message || ""}\n${stabilized.rustup_show.stderr || stabilized.rustup_show.error_message || ""}`,
        1200
      ),
      version_summary: summarizeText(
        `${stabilized.cargo_probe.stdout || ""}\n${stabilized.rustc_probe.stdout || ""}`,
        600
      ),
      default_toolchain: stabilized.default_toolchain,
      host_triple: stabilized.host_triple,
      rustc_path: stabilized.resolved_rustc,
      cargo_path: stabilized.resolved_cargo,
      remediation_action: stabilized.remediation_action
    };
    polyglotToolchainInstallMemo.set(memoKey, result);
    return result;
  }

  const rustupExe = path.join(polyglotToolchainCacheRoot, "rustup-init.exe");
  if (!fs.existsSync(rustupExe)) {
    const dl = runPowerShellInline(
      [
        "$ProgressPreference='SilentlyContinue'",
        "[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12",
        `Invoke-WebRequest -Uri ${quotePowerShellLiteral("https://static.rust-lang.org/rustup/dist/x86_64-pc-windows-msvc/rustup-init.exe")} -OutFile ${quotePowerShellLiteral(rustupExe)}`
      ].join("; "),
      900000
    );
    if (!dl.ok) {
      const failed = {
        ok: false,
        install_mode: "fixture_local_download",
        method: "fixture_local_download",
        command_summary: "download rustup-init.exe",
        stdout: dl.stdout,
        stderr: dl.stderr || dl.error_message || "rustup_download_failed",
        version_summary: null
      };
      polyglotToolchainInstallMemo.set(memoKey, failed);
      return failed;
    }
  }
  const install = runLocalCommand(
    rustupExe,
    ["-y", "--profile", "minimal", "--default-toolchain", "stable", "--no-modify-path"],
    1200000,
    {
      cwd: repoRoot,
      env: buildToolchainEnv({
        CARGO_HOME: cargoHome,
        RUSTUP_HOME: rustupHome
      })
    }
  );
  const cargoExe = path.join(cargoHome, "bin", "cargo.exe");
  const rustcExe = path.join(cargoHome, "bin", "rustc.exe");
  const rustupBin = path.join(cargoHome, "bin", "rustup.exe");
  if (!install.ok || !fs.existsSync(cargoExe) || !fs.existsSync(rustcExe) || !fs.existsSync(rustupBin)) {
    const failed = {
      ok: false,
      install_mode: "fixture_local_download",
      method: "rustup_local_install",
      command_summary: "rustup-init --profile minimal",
      stdout: install.stdout,
      stderr: install.stderr || install.error_message || "rustup_install_failed",
      version_summary: null
    };
    polyglotToolchainInstallMemo.set(memoKey, failed);
    return failed;
  }
  const stabilized = stabilizeRustToolchain({
    rustupExe: rustupBin,
    cargoExe,
    rustcExe,
    cargoHome,
    rustupHome
  });
  bindToolchainExecutable("cargo", stabilized.resolved_cargo);
  bindToolchainExecutable("rustc", stabilized.resolved_rustc);
  const result = {
    ok: stabilized.ok,
    install_mode: "fixture_local_download",
    method: "rustup_local_install",
    command_summary: "rustup-init --profile minimal",
    stdout: summarizeText(
      `${install.stdout || ""}\n${stabilized.cargo_probe.stdout || ""}\n${stabilized.rustc_probe.stdout || ""}\n${stabilized.rustup_show.stdout || ""}`,
      1200
    ),
    stderr: summarizeText(
      `${install.stderr || install.error_message || ""}\n${stabilized.cargo_probe.stderr || stabilized.cargo_probe.error_message || ""}\n${stabilized.rustc_probe.stderr || stabilized.rustc_probe.error_message || ""}\n${stabilized.rustup_show.stderr || stabilized.rustup_show.error_message || ""}`,
      1200
    ),
    version_summary: summarizeText(
      `${stabilized.cargo_probe.stdout || ""}\n${stabilized.rustc_probe.stdout || ""}`,
      600
    ),
    default_toolchain: stabilized.default_toolchain,
    host_triple: stabilized.host_triple,
    rustc_path: stabilized.resolved_rustc,
    cargo_path: stabilized.resolved_cargo,
    remediation_action: stabilized.remediation_action
  };
  polyglotToolchainInstallMemo.set(memoKey, result);
  return result;
}
