    const revokeGrantMatch = pathname.match(/^\/capability-grants\/([^/]+)\/(revoke|invalidate)$/);
    if (req.method === "POST" && revokeGrantMatch) {
      const grantId = decodeURIComponent(revokeGrantMatch[1]);
      const action = revokeGrantMatch[2];
      const grant = dbGet("SELECT * FROM capability_grants WHERE id = ?", grantId);
      if (!grant) {
        sendJson(res, 404, { error: "grant_not_found", grant_id: grantId });
        return;
      }
      const body = await readJsonBody(req);
      const revokeReasonRaw = typeof body.revoke_reason === "string" ? body.revoke_reason.trim() : "";
      const revokeReason = revokeReasonRaw || (action === "invalidate" ? "manual_invalidate" : "manual_revoke");
      const updated = revokeGrant(grant, revokeReason);
      if (updated?.run_id) {
        emitEvent(updated.run_id, "capability.lifecycle.updated", {
          grant_id: updated.id,
          capability_key: updated.capability_key,
          lifecycle_action: action,
          status: updated.status,
          revoke_reason: updated.revoke_reason
        });
      }
      sendJson(res, 200, { ok: true, action, capability_grant: updated });
      return;
    }

    if (req.method === "POST" && pathname === "/byo/openai/challenge") {
      const body = await readJsonBody(req);
      const actionRaw = typeof body.action === "string" ? body.action.trim() : "";
      const action = BYO_CHALLENGE_ACTIONS.has(actionRaw) ? actionRaw : null;
      if (!action) {
        sendJson(res, 400, { error: "invalid_action", allowed_actions: [...BYO_CHALLENGE_ACTIONS] });
        return;
      }
      const profileId = resolveByoProfileId(req, body);
      const profileHash = browserProfileHash(profileId);
      const scope = normalizeByoScope(body.binding_scope);
      const bindingId = typeof body.binding_id === "string" && body.binding_id.trim() ? body.binding_id.trim() : null;
      const challenge = createByoChallenge({
        action,
        profileHash,
        scope,
        bindingId
      });
      sendJson(res, 200, {
        provider: BYO_PROVIDER_OPENAI,
        action,
        challenge_id: challenge.challenge_id,
        nonce: challenge.nonce,
        expires_at: challenge.expires_at,
        browser_profile_id_hash: challenge.profile_hash,
        machine_scope_id_hash: MACHINE_SCOPE_ID_HASH,
        binding_scope: challenge.scope
      });
      return;
    }

